// Obtener todos los posts
app.get('/api/admin/posts', authenticateToken, isAdmin, async (req, res) => {
  try {
    const { page = 1, limit = 20 } = req.query;
    
    console.log('📝 [ADMIN] Obteniendo posts');

    const snapshot = await db.collection('posts')
      .orderBy('createdAt', 'desc')
      .get();
    
    const posts = snapshot.docs.map(doc => ({
      id: doc.id,
      ...doc.data(),
      createdAt: doc.data().createdAt?.toDate(),
      updatedAt: doc.data().updatedAt?.toDate()
    }));

    const startIndex = (page - 1) * limit;
    const endIndex = startIndex + parseInt(limit);
    const paginatedPosts = posts.slice(startIndex, endIndex);

    res.json({
      success: true,
      data: paginatedPosts,
      pagination: {
        page: parseInt(page),
        limit: parseInt(limit),
        total: posts.length,
        totalPages: Math.ceil(posts.length / limit)
      }
    });

  } catch (error) {
    console.error('❌ [ADMIN] Error obteniendo posts:', error);
    res.status(500).json({
      success: false,
      message: 'Error obteniendo posts',
      error: error.message
    });
  }
});

// Crear nuevo post
app.post('/api/admin/posts', authenticateToken, isAdmin, async (req, res) => {
  try {
    const { content, imageUrl, communityId, attachedLists = [] } = req.body;
    
    console.log('➕ [ADMIN] Creando nuevo post');

    if (!content) {
      return res.status(400).json({
        success: false,
        message: 'El contenido del post es requerido'
      });
    }

    if (!communityId) {
      return res.status(400).json({
        success: false,
        message: 'El ID de la comunidad es requerido'
      });
    }

    // Verificar que la comunidad existe
    const communityDoc = await db.collection('communities').doc(communityId).get();
    if (!communityDoc.exists) {
      return res.status(404).json({
        success: false,
        message: 'Comunidad no encontrada'
      });
    }

    // Validar y verificar que las listas existen
    const validatedLists = [];
    if (attachedLists && Array.isArray(attachedLists) && attachedLists.length > 0) {
      console.log(`📋 [ADMIN] Validando ${attachedLists.length} listas adjuntas`);
      
      for (const listId of attachedLists) {
        try {
          const listDoc = await db.collection('lists').doc(listId).get();
          
          if (!listDoc.exists) {
            console.warn(`⚠️ [ADMIN] Lista no encontrada: ${listId}`);
            continue;
          }

          const listData = listDoc.data();
          validatedLists.push({
            id: listId,
            title: listData.title,
            description: listData.description || '',
            imageUrl: listData.imageUrl || null,
            isPublic: listData.isPublic,
            totalItems: listData.totalItems || 0,
            completedItems: listData.completedItems || 0
          });
          console.log(`✅ [ADMIN] Lista validada: ${listData.title}`);
        } catch (error) {
          console.error(`❌ [ADMIN] Error validando lista ${listId}:`, error.message);
        }
      }
    }

    const postData = {
      content,
      authorId: req.user.uid,
      communityId,
      isPinned: false,
      createdAt: admin.firestore.FieldValue.serverTimestamp(),
      updatedAt: admin.firestore.FieldValue.serverTimestamp(),
      likes: [],
      commentCount: 0
    };

    // Solo agregar imageUrl si se proporciona
    if (imageUrl) {
      postData.imageUrl = imageUrl;
    }

    // Agregar listas adjuntas si hay
    if (validatedLists.length > 0) {
      postData.attachedLists = validatedLists;
      console.log(`📋 [ADMIN] ${validatedLists.length} listas adjuntadas al post`);
    }

    const postRef = await db.collection('posts').add(postData);

    // Incrementar el contador de posts en la comunidad
    await db.collection('communities').doc(communityId).update({
      postCount: admin.firestore.FieldValue.increment(1)
    });

    console.log('✅ [ADMIN] Post creado exitosamente:', postRef.id);

    // Enviar notificaciones push a todos los miembros de la comunidad
    try {
      const communityData = communityDoc.data();
      const authorDoc = await db.collection('users').doc(req.user.uid).get();
      const authorData = authorDoc.exists ? authorDoc.data() : {};
      const authorName = authorData.displayName || authorData.name || 'Administrador';
      const communityName = communityData.name || 'la comunidad';

      // Obtener tokens de todos los miembros (incluyendo al admin autor, si es miembro)
      const membersToNotify = communityData.members || [];
      
      if (membersToNotify.length > 0) {
        console.log(`📤 [ADMIN] Enviando notificación de nueva publicación a ${membersToNotify.length} miembros`);
        
        const tokensPromises = membersToNotify.map(async (memberId) => {
          try {
            const memberDoc = await db.collection('users').doc(memberId).get();
            if (memberDoc.exists) {
              const memberData = memberDoc.data();
              return { userId: memberId, tokens: memberData.fcmTokens || [] };
            }
          } catch (error) {
            console.warn(`⚠️ [ADMIN] Error obteniendo tokens del miembro ${memberId}:`, error.message);
          }
          return { userId: memberId, tokens: [] };
        });
        
        const usersWithTokens = await Promise.all(tokensPromises);
        const allTokens = usersWithTokens.flatMap(u => u.tokens);
        
        if (allTokens.length > 0) {
          const notification = {
            title: `📢 ${authorName} publicó en ${communityName}`,
            body: content.length > 100 ? content.substring(0, 100) + '...' : content
          };

          const notificationData = {
            type: 'community_post',
            postId: postRef.id,
            communityId: communityId,
            communityName: communityName,
            authorId: req.user.uid,
            authorName: authorName,
            screen: 'CommunityPostScreen'
          };

          const pushResult = await sendPushNotification(allTokens, notification, notificationData);
          console.log(`✅ [ADMIN] Notificaciones enviadas: ${pushResult.successCount} exitosas, ${pushResult.failureCount} fallidas`);

          // Guardar notificaciones en Firestore para cada usuario
          const batch = db.batch();
          usersWithTokens.forEach(userWithTokens => {
            if (userWithTokens.tokens.length > 0) {
              const notifRef = db.collection('notifications').doc();
              batch.set(notifRef, {
                userId: userWithTokens.userId,
                type: 'community_post',
                title: notification.title,
                body: notification.body,
                data: notificationData,
                read: false,
                createdAt: admin.firestore.Timestamp.fromDate(new Date())
              });
            }
          });
          await batch.commit();
          console.log(`✅ [ADMIN] ${membersToNotify.length} notificaciones guardadas en Firestore`);
        } else {
          console.log('⚠️ [ADMIN] Ningún miembro tiene tokens FCM registrados');
        }
      } else {
        console.log('⚠️ [ADMIN] La comunidad no tiene miembros para notificar');
      }
    } catch (notificationError) {
      console.error('❌ [ADMIN] Error enviando notificaciones de nueva publicación:', notificationError);
      // No fallar la creación del post si falla la notificación
    }

    res.json({
      success: true,
      message: 'Post creado exitosamente',
      data: {
        id: postRef.id,
        ...postData
      }
    });

  } catch (error) {
    console.error('❌ [ADMIN] Error creando post:', error);
    res.status(500).json({
      success: false,
      message: 'Error creando post',
      error: error.message
    });
  }
});

// Editar post
app.put('/api/admin/posts/:postId', authenticateToken, isAdmin, async (req, res) => {
  try {
    const { postId } = req.params;
    const { content, imageUrl, attachedLists } = req.body;
    
    console.log('✏️ [ADMIN] Editando post:', postId);

    const postRef = db.collection('posts').doc(postId);
    const postDoc = await postRef.get();

    if (!postDoc.exists) {
      return res.status(404).json({
        success: false,
        message: 'Post no encontrado'
      });
    }

    const updateData = {
      updatedAt: admin.firestore.FieldValue.serverTimestamp()
    };

    if (content !== undefined) updateData.content = content;
    if (imageUrl !== undefined) updateData.imageUrl = imageUrl;

    // Actualizar listas adjuntas si se envían
    if (attachedLists !== undefined) {
      console.log(`📋 [ADMIN] attachedLists recibido:`, attachedLists);
      
      if (attachedLists === null || (Array.isArray(attachedLists) && attachedLists.length === 0)) {
        // Remover listas si se envía null o array vacío
        updateData.attachedLists = admin.firestore.FieldValue.delete();
        console.log('🗑️ [ADMIN] Removiendo listas adjuntas del post');
      } else if (Array.isArray(attachedLists)) {
        // Validar y verificar que las listas existen
        const validatedLists = [];
        console.log(`📋 [ADMIN] Validando ${attachedLists.length} listas adjuntas`);
        
        for (const listId of attachedLists) {
          console.log(`🔍 [ADMIN] Buscando lista: ${listId}`);
          try {
            const listDoc = await db.collection('lists').doc(listId).get();
            
            if (!listDoc.exists) {
              console.warn(`⚠️ [ADMIN] Lista no encontrada: ${listId}`);
              continue;
            }

            const listData = listDoc.data();
            validatedLists.push({
              id: listId,
              title: listData.title,
              description: listData.description || '',
              imageUrl: listData.imageUrl || null,
              isPublic: listData.isPublic,
              totalItems: listData.totalItems || 0,
              completedItems: listData.completedItems || 0
            });
            console.log(`✅ [ADMIN] Lista validada: ${listData.title}`);
          } catch (error) {
            console.error(`❌ [ADMIN] Error validando lista ${listId}:`, error.message);
          }
        }
        
        if (validatedLists.length > 0) {
          updateData.attachedLists = validatedLists;
          console.log(`📋 [ADMIN] ${validatedLists.length} listas serán actualizadas en el post`);
        } else {
          console.warn(`⚠️ [ADMIN] Ninguna lista fue validada. No se actualizarán listas.`);
        }
      }
    }

    console.log(`💾 [ADMIN] Actualizando post con datos:`, JSON.stringify(updateData, null, 2));
    await postRef.update(updateData);

    // Obtener el documento actualizado
    const updatedPostDoc = await postRef.get();
    const updatedData = updatedPostDoc.data();

    console.log(`✅ [ADMIN] Post actualizado. attachedLists:`, updatedData.attachedLists);

    res.json({
      success: true,
      message: 'Post actualizado exitosamente',
      data: {
        id: postId,
        ...updatedData,
        createdAt: updatedData.createdAt?.toDate?.(),
        updatedAt: updatedData.updatedAt?.toDate?.()
      }
    });

  } catch (error) {
    console.error('❌ [ADMIN] Error editando post:', error);
    res.status(500).json({
      success: false,
      message: 'Error editando post',
      error: error.message
    });
  }
});

