// Ver post compartido (público - sin autenticación)
app.get('/post/:postId', async (req, res) => {
  try {
    const { postId } = req.params;

    if (!db) {
      return res.status(500).json({
        success: false,
        message: 'Base de datos no disponible'
      });
    }

    // Obtener el post
    const postDoc = await db.collection('posts').doc(postId).get();

    if (!postDoc.exists) {
      return res.status(404).json({
        success: false,
        message: 'Publicación no encontrada'
      });
    }

    const postData = postDoc.data();

    // Obtener info del autor
    let authorName = 'Usuario';
    try {
      const authorDoc = await db.collection('users').doc(postData.authorId).get();
      if (authorDoc.exists) {
        const authorData = authorDoc.data();
        authorName = authorData.displayName || authorData.name || 'Usuario';
      }
    } catch (error) {
      console.warn('⚠️ [SHARE] Error obteniendo autor:', error);
    }

    // Obtener info de la comunidad
    let communityName = 'Munpa';
    try {
      const communityDoc = await db.collection('communities').doc(postData.communityId).get();
      if (communityDoc.exists) {
        communityName = communityDoc.data().name || 'Munpa';
      }
    } catch (error) {
      console.warn('⚠️ [SHARE] Error obteniendo comunidad:', error);
    }

    // Generar HTML para mostrar
    const html = `
<!DOCTYPE html>
<html lang="es">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>${authorName} en ${communityName} - Munpa</title>
    <meta property="og:title" content="${authorName} en ${communityName}">
    <meta property="og:description" content="${postData.content.substring(0, 200)}">
    ${postData.imageUrl ? `<meta property="og:image" content="${postData.imageUrl}">` : ''}
    <meta property="og:type" content="article">
    <style>
        body {
            font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Helvetica, Arial, sans-serif;
            margin: 0;
            padding: 20px;
            background: #f5f5f5;
            display: flex;
            justify-content: center;
            align-items: center;
            min-height: 100vh;
        }
        .container {
            max-width: 600px;
            background: white;
            border-radius: 12px;
            padding: 24px;
            box-shadow: 0 2px 8px rgba(0,0,0,0.1);
        }
        .header {
            display: flex;
            align-items: center;
            margin-bottom: 16px;
        }
        .logo {
            font-size: 32px;
            margin-right: 12px;
        }
        .title {
            font-size: 24px;
            font-weight: bold;
            color: #333;
        }
        .community {
            color: #666;
            font-size: 14px;
            margin-bottom: 8px;
        }
        .author {
            font-weight: 600;
            color: #6366f1;
            margin-bottom: 16px;
        }
        .content {
            font-size: 16px;
            line-height: 1.6;
            color: #333;
            margin-bottom: 20px;
            white-space: pre-wrap;
        }
        .image {
            width: 100%;
            border-radius: 8px;
            margin-bottom: 20px;
        }
        .button {
            display: inline-block;
            background: #6366f1;
            color: white;
            padding: 12px 24px;
            border-radius: 8px;
            text-decoration: none;
            font-weight: 600;
            transition: background 0.2s;
        }
        .button:hover {
            background: #4f46e5;
        }
        .stats {
            color: #666;
            font-size: 14px;
            margin-top: 16px;
        }
    </style>
    <script>
        function openInApp() {
            const isAndroid = /Android/i.test(navigator.userAgent);
            const isIOS = /iPhone|iPad|iPod/i.test(navigator.userAgent);
            
            if (isAndroid) {
                // Intent scheme para Android
                window.location.href = 'intent://post/${postId}#Intent;scheme=munpa;package=com.munpa.app;end';
            } else if (isIOS) {
                // Deep link para iOS
                window.location.href = 'munpa://post/${postId}';
                // Fallback a App Store si no tiene la app
                setTimeout(() => {
                    // Si sigue aquí después de 2s, no tiene la app
                    // window.location.href = 'https://apps.apple.com/app/munpa/idXXXXXX';
                }, 2000);
            } else {
                // Desktop o desconocido
                window.location.href = 'munpa://post/${postId}';
            }
        }
        
        // Intentar abrir automáticamente al cargar
        window.onload = function() {
            // Mostrar el botón inmediatamente y hacer auto-redirect
            setTimeout(openInApp, 100);
        };
    </script>
</head>
<body>
    <div class="container">
        <div class="header">
            <div class="logo">👶</div>
            <div class="title">Munpa</div>
        </div>
        <div class="community">📢 ${communityName}</div>
        <div class="author">Por ${authorName}</div>
        ${postData.imageUrl ? `<img src="${postData.imageUrl}" alt="Imagen del post" class="image">` : ''}
        <div class="content">${postData.content}</div>
        <div class="stats">
            ❤️ ${postData.likeCount || 0} likes · 💬 ${postData.commentCount || 0} comentarios
        </div>
        <br>
        <button onclick="openInApp()" class="button" style="border: none; cursor: pointer;">Abrir en Munpa 📱</button>
    </div>
</body>
</html>
    `;

    res.send(html);

  } catch (error) {
    console.error('❌ [SHARE] Error mostrando post:', error);
    res.status(500).send(`
      <html>
        <body style="font-family: Arial; padding: 20px; text-align: center;">
          <h2>😕 Ups, algo salió mal</h2>
          <p>No pudimos cargar esta publicación.</p>
          <a href="https://munpa.online" style="color: #6366f1;">Ir a Munpa</a>
        </body>
      </html>
    `);
  }
});

