// Endpoint para agregar un hijo
app.post('/api/auth/children', authenticateToken, async (req, res) => {
  try {
    const { uid } = req.user;
    const { 
      name, 
      birthDate,        // Nuevo: fecha de nacimiento (para bebés nacidos)
      dueDate,          // Nuevo: fecha esperada de parto (para bebés no nacidos)
      isUnborn, 
      photoUrl,
      // Legacy (para compatibilidad con apps antiguas)
      ageInMonths, 
      gestationWeeks 
    } = req.body;

    if (!name) {
      return res.status(400).json({
        success: false,
        message: 'Nombre es requerido'
      });
    }

    // Validar que si es un bebé no nacido, tenga fecha de parto o semanas de gestación (legacy)
    if (isUnborn) {
      if (!dueDate && (!gestationWeeks || gestationWeeks < 1 || gestationWeeks > 42)) {
      return res.status(400).json({
        success: false,
          message: 'Para bebés no nacidos, la fecha esperada de parto es requerida (o semanas de gestación entre 1 y 42)'
        });
      }
      
      // Validar que la fecha de parto sea futura (con un margen de 2 semanas para casos de parto tardío)
      if (dueDate) {
        const due = new Date(dueDate);
        const now = new Date();
        const twoWeeksAgo = new Date(now.getTime() - (14 * 24 * 60 * 60 * 1000));
        
        if (due < twoWeeksAgo) {
      return res.status(400).json({
        success: false,
            message: 'La fecha esperada de parto debe ser futura o reciente (máximo 2 semanas en el pasado)'
          });
        }
      }
    }

    // Validar que si es un bebé nacido, tenga fecha de nacimiento o edad en meses (legacy)
    if (!isUnborn) {
      if (!birthDate && (ageInMonths === undefined || ageInMonths < 0)) {
        return res.status(400).json({
          success: false,
          message: 'Para bebés nacidos, la fecha de nacimiento es requerida (o edad en meses mayor o igual a 0)'
        });
      }
      
      // Validar que la fecha de nacimiento sea pasada y no muy lejana
      if (birthDate) {
        const birth = new Date(birthDate);
        const now = new Date();
        const maxYearsBack = 18; // Máximo 18 años
        const minDate = new Date(now.getFullYear() - maxYearsBack, now.getMonth(), now.getDate());
        
        if (birth > now) {
          return res.status(400).json({
            success: false,
            message: 'La fecha de nacimiento debe ser en el pasado'
          });
        }
        
        if (birth < minDate) {
          return res.status(400).json({
            success: false,
            message: `La fecha de nacimiento no puede ser mayor a ${maxYearsBack} años atrás`
          });
        }
      }
    }

    if (!db) {
      return res.status(500).json({
        success: false,
        message: 'Base de datos no disponible'
      });
    }

    const now = new Date();
    const childData = {
      parentId: uid,
      name: name.trim(),
      isUnborn: isUnborn || false,
      photoUrl: photoUrl || null,
      createdAt: now,
      updatedAt: now
    };

    // Usar el nuevo sistema basado en fechas
    if (isUnborn) {
      if (dueDate) {
        childData.dueDate = new Date(dueDate); // Nuevo sistema
        childData.gestationWeeks = null;
      } else {
        // Fallback a sistema legacy
        childData.gestationWeeks = parseInt(gestationWeeks);
        childData.dueDate = null;
        childData.registeredAt = now; // Solo para sistema legacy
      }
      childData.birthDate = null;
      childData.ageInMonths = null;
    } else {
      if (birthDate) {
        childData.birthDate = new Date(birthDate); // Nuevo sistema
        childData.ageInMonths = null;
      } else {
        // Fallback a sistema legacy
        childData.ageInMonths = parseInt(ageInMonths);
        childData.birthDate = null;
        childData.registeredAt = now; // Solo para sistema legacy
      }
      childData.dueDate = null;
      childData.gestationWeeks = null;
    }

    const childRef = await db.collection('children').add(childData);
    
    // Calcular información actual del hijo
    const childDoc = await childRef.get();
    const childWithInfo = getChildCurrentInfo({ id: childRef.id, ...childDoc.data() });
    
    // Calcular el número real de hijos después de agregar
    const childrenSnapshot = await db.collection('children')
      .where('parentId', '==', uid)
      .get();
    
    const actualChildrenCount = childrenSnapshot.size;
    console.log('📊 [CHILDREN] Número real de hijos después de agregar:', actualChildrenCount);
    
    // Actualizar contador de hijos en el perfil con el valor real
    const userRef = db.collection('users').doc(uid);
    await userRef.update({
      childrenCount: actualChildrenCount,
      updatedAt: new Date()
    });

    // 📧 Enviar email según el número de hijos
    try {
      const userDoc = await userRef.get();
      const userData = userDoc.data();
      
      if (userData && userData.email) {
        // Calcular edad del hijo para el email
        let childAge = '';
        if (!isUnborn && birthDate) {
          const birth = new Date(birthDate);
          const now = new Date();
          const months = Math.floor((now - birth) / (1000 * 60 * 60 * 24 * 30.44));
          const years = Math.floor(months / 12);
          const remainingMonths = months % 12;
          
          if (years > 0) {
            childAge = `${years} ${years === 1 ? 'año' : 'años'}`;
            if (remainingMonths > 0) {
              childAge += ` y ${remainingMonths} ${remainingMonths === 1 ? 'mes' : 'meses'}`;
            }
          } else {
            childAge = `${months} ${months === 1 ? 'mes' : 'meses'}`;
          }
        } else if (isUnborn) {
          childAge = 'por nacer';
        } else if (ageInMonths !== undefined) {
          childAge = `${ageInMonths} ${ageInMonths === 1 ? 'mes' : 'meses'}`;
        }
        
        if (actualChildrenCount === 1) {
          // 📧 Primer hijo
          console.log(`📧 [EMAIL] Enviando email de primer hijo a ${userData.email}`);
          const { sendFirstChildEmail } = require('./services/emailService');
          sendFirstChildEmail(
            userData.displayName || userData.name || 'Mamá',
            userData.email,
            name.trim(),
            childAge
          ).catch(err => console.error('❌ [EMAIL] Error enviando email de primer hijo:', err));
          
        } else if (actualChildrenCount > 1) {
          // 📧 Hijo adicional (2do, 3ro, etc)
          console.log(`📧 [EMAIL] Enviando email de hijo adicional a ${userData.email}`);
          const { sendAdditionalChildEmail } = require('./services/emailService');
          sendAdditionalChildEmail(
            userData.displayName || userData.name || 'Mamá',
            userData.email,
            name.trim(),
            childAge,
            actualChildrenCount
          ).catch(err => console.error('❌ [EMAIL] Error enviando email de hijo adicional:', err));
        }
        
        // 📧 Si es un bebé por nacer (embarazo), enviar email de felicitación
        if (isUnborn && dueDate) {
          console.log(`📧 [EMAIL] Enviando email de embarazo a ${userData.email}`);
          const { sendPregnancyEmail } = require('./services/emailService');
          sendPregnancyEmail(
            userData.displayName || userData.name || 'Mamá',
            userData.email,
            name.trim(),
            dueDate
          ).catch(err => console.error('❌ [EMAIL] Error enviando email de embarazo:', err));
        }
      }
    } catch (emailError) {
      console.error('❌ [EMAIL] Error al enviar emails:', emailError);
      // No fallar la request si el email falla
    }

    res.json({
      success: true,
      message: 'Hijo agregado exitosamente',
      data: childWithInfo
    });

  } catch (error) {
    console.error('Error al agregar hijo:', error);
    res.status(500).json({
      success: false,
      message: 'Error al agregar hijo',
      error: error.message
    });
  }
});

// Endpoint para actualizar un hijo
app.put('/api/auth/children/:childId', authenticateToken, async (req, res) => {
  try {
    const { uid } = req.user;
    const { childId } = req.params;
    const { 
      name, 
      birthDate,        // Nuevo: fecha de nacimiento
      dueDate,          // Nuevo: fecha esperada de parto
      isUnborn, 
      photoUrl,
      // Legacy
      ageInMonths, 
      gestationWeeks 
    } = req.body;

    if (!name && !birthDate && !dueDate && ageInMonths === undefined && 
        isUnborn === undefined && gestationWeeks === undefined && !photoUrl) {
      return res.status(400).json({
        success: false,
        message: 'Al menos un campo debe ser proporcionado'
      });
    }

    if (!db) {
      return res.status(500).json({
        success: false,
        message: 'Base de datos no disponible'
      });
    }

    // Verificar que el hijo pertenece al usuario
    const childDoc = await db.collection('children').doc(childId).get();
    if (!childDoc.exists) {
      return res.status(404).json({
        success: false,
        message: 'Hijo no encontrado'
      });
    }

    if (childDoc.data().parentId !== uid) {
      return res.status(403).json({
        success: false,
        message: 'No tienes permisos para modificar este hijo'
      });
    }

    const currentData = childDoc.data();
    const updateData = {
      updatedAt: new Date()
    };
    
    // Actualizar nombre si se proporciona
    if (name) updateData.name = name.trim();
    
    // Actualizar foto si se proporciona
    if (photoUrl !== undefined) {
    if (photoUrl && !isValidUrl(photoUrl)) {
      return res.status(400).json({
        success: false,
        message: 'URL de foto inválida'
      });
      }
      updateData.photoUrl = photoUrl;
    }
    
    // Actualizar estado de embarazo si se proporciona
    if (isUnborn !== undefined) {
      updateData.isUnborn = isUnborn;
    }

    // Determinar el estado final de isUnborn
    const finalIsUnborn = isUnborn !== undefined ? isUnborn : currentData.isUnborn;

    // Manejar actualización de fechas/edades según el estado
    if (finalIsUnborn) {
      // Es un bebé no nacido
      if (dueDate) {
        // Validar fecha de parto
        const due = new Date(dueDate);
        if (isNaN(due.getTime())) {
          return res.status(400).json({
            success: false,
            message: 'La fecha esperada de parto es inválida'
          });
        }
        const now = new Date();
        const twoWeeksAgo = new Date(now.getTime() - (14 * 24 * 60 * 60 * 1000));
        
        if (due < twoWeeksAgo) {
          return res.status(400).json({
            success: false,
            message: 'La fecha esperada de parto debe ser futura o reciente (máximo 2 semanas en el pasado)'
          });
        }
        
        updateData.dueDate = due;
        updateData.gestationWeeks = null;
        updateData.birthDate = null;
      updateData.ageInMonths = null;
      } else if (gestationWeeks !== undefined) {
        // Legacy: usar semanas de gestación
        const parsedGestationWeeks = parseInt(gestationWeeks);
        if (Number.isNaN(parsedGestationWeeks) || parsedGestationWeeks < 1 || parsedGestationWeeks > 42) {
          return res.status(400).json({
            success: false,
            message: 'Las semanas de gestación deben estar entre 1 y 42'
          });
        }
        updateData.gestationWeeks = parsedGestationWeeks;
        updateData.dueDate = null;
        updateData.birthDate = null;
        updateData.ageInMonths = null;
        updateData.registeredAt = new Date();
      }
    } else {
      // Es un bebé nacido
      if (birthDate) {
        // Validar fecha de nacimiento
        const birth = new Date(birthDate);
        if (isNaN(birth.getTime())) {
          return res.status(400).json({
            success: false,
            message: 'La fecha de nacimiento es inválida'
          });
        }
        const now = new Date();
        const maxYearsBack = 18;
        const minDate = new Date(now.getFullYear() - maxYearsBack, now.getMonth(), now.getDate());
        
        if (birth > now) {
          return res.status(400).json({
            success: false,
            message: 'La fecha de nacimiento debe ser en el pasado'
          });
        }
        
        if (birth < minDate) {
          return res.status(400).json({
            success: false,
            message: `La fecha de nacimiento no puede ser mayor a ${maxYearsBack} años atrás`
          });
        }
        
        updateData.birthDate = birth;
        updateData.ageInMonths = null;
        updateData.dueDate = null;
      updateData.gestationWeeks = null;
      } else if (ageInMonths !== undefined) {
        // Legacy: usar edad en meses
        const parsedAgeInMonths = parseInt(ageInMonths);
        if (Number.isNaN(parsedAgeInMonths) || parsedAgeInMonths < 0) {
          return res.status(400).json({
            success: false,
            message: 'La edad en meses debe ser mayor o igual a 0'
          });
        }
        updateData.ageInMonths = parsedAgeInMonths;
        updateData.birthDate = null;
        updateData.dueDate = null;
        updateData.gestationWeeks = null;
        updateData.registeredAt = new Date();
      }
    }

    await db.collection('children').doc(childId).update(updateData);

    // Obtener el hijo actualizado con información calculada
    const updatedChildDoc = await db.collection('children').doc(childId).get();
    const updatedChild = getChildCurrentInfo({ id: childId, ...updatedChildDoc.data() });

    res.json({
      success: true,
      message: 'Hijo actualizado exitosamente',
      data: updatedChild
    });

  } catch (error) {
    console.error('Error al actualizar hijo:', error);
    res.status(500).json({
      success: false,
      message: 'Error al actualizar hijo',
      error: error.message
    });
  }
});

// Endpoint para subir foto de hijo usando Firebase Storage
app.post('/api/auth/children/upload-photo', authenticateToken, upload.single('photo'), async (req, res) => {
  try {
    const { uid } = req.user;
    const { childId } = req.body;

    if (!childId) {
      return res.status(400).json({
        success: false,
        message: 'ID del hijo es requerido'
      });
    }

    if (!req.file) {
      return res.status(400).json({
        success: false,
        message: 'No se proporcionó ningún archivo'
      });
    }

    // Verificar que Firebase Admin esté inicializado
    if (!admin) {
      console.error('❌ [STORAGE] Firebase Admin no está inicializado');
      return res.status(500).json({
        success: false,
        message: 'Error interno del servidor: Firebase no configurado'
      });
    }

    // Verificar que Firebase Storage esté disponible
    try {
      const bucket = admin.storage().bucket();
      console.log('✅ [STORAGE] Firebase Storage disponible');
      console.log('📦 [STORAGE] Bucket:', bucket.name);
    } catch (storageError) {
      console.error('❌ [STORAGE] Error accediendo a Firebase Storage:', storageError);
      return res.status(500).json({
        success: false,
        message: 'Error interno del servidor: Storage no disponible',
        error: storageError.message
      });
    }

    // Verificar que el hijo pertenece al usuario
    const childDoc = await db.collection('children').doc(childId).get();
    if (!childDoc.exists) {
      return res.status(404).json({
        success: false,
        message: 'Hijo no encontrado'
      });
    }

    const childData = childDoc.data();
    if (childData.parentId !== uid) {
      return res.status(403).json({
        success: false,
        message: 'No tienes permisos para modificar este hijo'
      });
    }

    // Subir archivo a Firebase Storage usando buffer de memoria
    console.log('🔍 [STORAGE] Verificando admin:', admin ? '✅ Inicializado' : '❌ Null');
    console.log('🔍 [STORAGE] Verificando admin.storage:', admin.storage ? '✅ Disponible' : '❌ No disponible');
    console.log('🔍 [STORAGE] Project ID:', process.env.FIREBASE_PROJECT_ID);
    
    const bucket = admin.storage().bucket();
    console.log('📦 [STORAGE] Bucket obtenido:', bucket.name);
    
    const fileName = `children/${childId}/photo-${Date.now()}-${Math.round(Math.random() * 1E9)}${path.extname(req.file.originalname)}`;
    
    console.log('📤 [STORAGE] Subiendo archivo a Firebase Storage:', fileName);

    // Usar el buffer de memoria directamente
    const file = bucket.file(fileName);
    await file.save(req.file.buffer, {
      metadata: {
        contentType: req.file.mimetype,
        metadata: {
          uploadedBy: uid,
          childId: childId,
          originalName: req.file.originalname
        }
      }
    });

    // Hacer el archivo público
    await file.makePublic();

    // Obtener URL pública
    const photoUrl = `https://storage.googleapis.com/${bucket.name}/${fileName}`;
    
    console.log('✅ [STORAGE] Archivo subido exitosamente:', photoUrl);

    // Actualizar el hijo con la nueva foto
    await db.collection('children').doc(childId).update({
      photoUrl: photoUrl,
      updatedAt: new Date()
    });

    res.json({
      success: true,
      message: 'Foto subida exitosamente',
      data: {
        photoUrl: photoUrl,
        fileName: fileName
      }
    });

  } catch (error) {
    console.error('Error subiendo foto a Firebase Storage:', error);
    
    res.status(500).json({
      success: false,
      message: 'Error subiendo foto',
      error: error.message
    });
  }
});



