// Endpoint para tests automáticos de calidad
app.post('/api/doula/quality-test', authenticateToken, async (req, res) => {
  try {
    const testQuestions = [
      {
        question: "¿Qué ejercicios puedo hacer durante el embarazo?",
        expectedCategory: "embarazo",
        expectedKeywords: ["caminar", "yoga", "natación", "seguro"]
      },
      {
        question: "¿Cómo puedo prepararme para la lactancia?",
        expectedCategory: "lactancia",
        expectedKeywords: ["contacto", "agarre", "demanda", "beneficios"]
      },
      {
        question: "¿Cuáles son los síntomas del primer trimestre?",
        expectedCategory: "embarazo",
        expectedKeywords: ["náuseas", "fatiga", "senos", "hormonas"]
      },
      {
        question: "¿Puedes ayudarme con programación en JavaScript?",
        expectedCategory: "off_topic",
        expectedResponse: "especializada en acompañamiento durante el embarazo"
      }
    ];

    const results = [];
    let totalScore = 0;

    for (const test of testQuestions) {
      try {
        // Simular llamada al chat
        const response = await generateDoulaResponse(test.question, '', '', 'TestUser');
        
        let score = 0;
        let feedback = '';

        if (test.expectedCategory === 'off_topic') {
          // Verificar que redirija correctamente
          if (response.includes(test.expectedResponse)) {
            score = 1;
            feedback = '✅ Redirección correcta para tema fuera del ámbito';
          } else {
            feedback = '❌ No redirigió correctamente tema fuera del ámbito';
          }
        } else {
          // Verificar palabras clave esperadas
          const keywordMatches = test.expectedKeywords.filter(keyword => 
            response.toLowerCase().includes(keyword.toLowerCase())
          );
          
          score = keywordMatches.length / test.expectedKeywords.length;
          feedback = `✅ Encontró ${keywordMatches.length}/${test.expectedKeywords.length} palabras clave`;
        }

        results.push({
          question: test.question,
          expectedCategory: test.expectedCategory,
          score: score,
          feedback: feedback,
          response: response.substring(0, 200) + '...'
        });

        totalScore += score;

      } catch (error) {
        results.push({
          question: test.question,
          expectedCategory: test.expectedCategory,
          score: 0,
          feedback: '❌ Error en test',
          error: error.message
        });
      }
    }

    const averageScore = totalScore / testQuestions.length;
    const qualityStatus = averageScore >= 0.8 ? 'EXCELENTE' : averageScore >= 0.6 ? 'BUENO' : 'NEEDS_IMPROVEMENT';

    res.json({
      success: true,
      data: {
        testDate: new Date(),
        totalTests: testQuestions.length,
        averageScore: averageScore,
        qualityStatus: qualityStatus,
        results: results
      }
    });

  } catch (error) {
    console.error('❌ Error en test de calidad:', error);
    res.status(500).json({
      success: false,
      message: 'Error en test de calidad',
      error: error.message
    });
  }
});

// Endpoint para obtener información de desarrollo infantil por edad
app.post('/api/children/development-info', authenticateToken, async (req, res) => {
  try {
    const { childId, name } = req.body;
    const userId = req.user.uid;

    let child = null;
    let currentAgeInMonths = null;
    let currentGestationWeeks = null;
    let isUnborn = false;

    // Si se proporciona childId, buscar el hijo en la base de datos
    if (childId) {
      const childDoc = await db.collection('children').doc(childId).get();
      if (!childDoc.exists) {
        return res.status(404).json({
          success: false,
          message: 'Hijo no encontrado'
        });
      }
      
      child = childDoc.data();
      
      // Verificar que el hijo pertenece al usuario
      if (child.parentId !== userId) {
        return res.status(403).json({
          success: false,
          message: 'No tienes permisos para acceder a este hijo'
        });
      }

      // Calcular edad actual basada en fecha de registro
      const childInfo = getChildCurrentInfo(child);
      currentAgeInMonths = childInfo.currentAgeInMonths;
      currentGestationWeeks = childInfo.currentGestationWeeks;
      isUnborn = child.isUnborn;
      
      console.log(`📊 [DEVELOPMENT] ${child.name}: ${isUnborn ? currentGestationWeeks + ' semanas' : currentAgeInMonths + ' meses'} (calculado desde ${childInfo.registeredAgeInMonths || childInfo.registeredGestationWeeks})`);
    } else if (name) {
      // Modo de compatibilidad: usar nombre y parámetros manuales
      const { ageInMonths, isUnborn: manualIsUnborn, gestationWeeks } = req.body;
      
      if (!name.trim()) {
        return res.status(400).json({
          success: false,
          message: 'El nombre del niño es requerido'
        });
      }

      if (manualIsUnborn && !gestationWeeks) {
        return res.status(400).json({
          success: false,
          message: 'Para niños por nacer, las semanas de gestación son requeridas'
        });
      }

      if (!manualIsUnborn && !ageInMonths && ageInMonths !== 0) {
        return res.status(400).json({
          success: false,
          message: 'Para niños nacidos, la edad en meses es requerida'
        });
      }

      currentAgeInMonths = manualIsUnborn ? null : ageInMonths;
      currentGestationWeeks = manualIsUnborn ? gestationWeeks : null;
      isUnborn = manualIsUnborn;
      
      console.log(`📊 [DEVELOPMENT] ${name}: ${isUnborn ? currentGestationWeeks + ' semanas' : currentAgeInMonths + ' meses'} (manual)`);
    } else {
      return res.status(400).json({
        success: false,
        message: 'Se requiere childId o nombre del niño'
      });
    }

    // Crear clave única para el historial
    const childKey = child ? `${child.id}_${isUnborn ? 'unborn' : 'born'}` : `${name.trim()}_${isUnborn ? 'unborn' : 'born'}`;
    const previousResponses = await getPreviousDevelopmentResponses(userId, childKey);

    // Obtener información variada desde OpenAI
    let developmentInfo = [];
    if (isUnborn) {
      developmentInfo = await getUnbornDevelopmentInfoFromAI(currentGestationWeeks, previousResponses, child ? child.name : name.trim());
    } else {
      developmentInfo = await getChildDevelopmentInfoFromAI(currentAgeInMonths, previousResponses, child ? child.name : name.trim());
    }

    // Guardar esta respuesta para futuras consultas
    await saveDevelopmentResponse(userId, childKey, {
      childName: child ? child.name : name.trim(),
      childId: child ? child.id : null,
      ageInMonths: currentAgeInMonths,
      gestationWeeks: currentGestationWeeks,
      isUnborn: isUnborn,
      developmentInfo: developmentInfo,
      timestamp: new Date()
    });

    res.json({
      success: true,
      data: {
        childName: child ? child.name : name.trim(),
        childId: child ? child.id : null,
        ageInMonths: currentAgeInMonths,
        gestationWeeks: currentGestationWeeks,
        isUnborn: isUnborn,
        developmentInfo: developmentInfo,
        timestamp: new Date(),
        responseCount: previousResponses.length + 1,
        isNewInfo: previousResponses.length === 0,
        calculatedAge: true,
        // Información detallada de edades
        registeredAge: child ? (child.isUnborn ? childInfo.registeredGestationWeeks : childInfo.registeredAgeInMonths) : null,
        currentAge: child ? (child.isUnborn ? childInfo.currentGestationWeeks : childInfo.currentAgeInMonths) : null,
        daysSinceCreation: child ? childInfo.daysSinceCreation : null,
        // Información adicional para bebés por nacer
        isOverdue: child ? childInfo.isOverdue : false,
        // Información de cálculo
        calculationInfo: child ? {
          registeredWeeks: child.isUnborn ? childInfo.registeredGestationWeeks : null,
          registeredMonths: child.isUnborn ? null : childInfo.registeredAgeInMonths,
          currentWeeks: child.isUnborn ? childInfo.currentGestationWeeks : null,
          currentMonths: child.isUnborn ? null : childInfo.currentAgeInMonths,
          daysSinceCreation: childInfo.daysSinceCreation
        } : null
      }
    });

  } catch (error) {
    console.error('❌ Error obteniendo información de desarrollo:', error);
    res.status(500).json({
      success: false,
      message: 'Error obteniendo información de desarrollo',
      error: error.message
    });
  }
});

// Guía diaria para bebé o embarazo (con OpenAI)
app.post('/api/guide/today', authenticateToken, async (req, res) => {
  try {
    const { birthDate, gestationWeeks, ageWeeks, name, isPregnant = false, childId } = req.body;

    let weeks = null;
    let months = null;
    let ageBreakdown = null;
    let pregnant = Boolean(isPregnant);
    let resolvedChildId = childId || null;

    if (!resolvedChildId && name && db) {
      const trimmedName = String(name).trim();
      const ownSnapshot = await db.collection('children')
        .where('parentId', '==', req.user.uid)
        .where('name', '==', trimmedName)
        .limit(1)
        .get();
      if (!ownSnapshot.empty) {
        resolvedChildId = ownSnapshot.docs[0].id;
      } else {
        const sharedSnapshot = await db.collection('children')
          .where('sharedWith', 'array-contains', req.user.uid)
          .where('name', '==', trimmedName)
          .limit(1)
          .get();
        if (!sharedSnapshot.empty) {
          resolvedChildId = sharedSnapshot.docs[0].id;
        }
      }
    }

    if (resolvedChildId) {
      const childDoc = await db.collection('children').doc(resolvedChildId).get();
      if (!childDoc.exists) {
        return res.status(404).json({
          success: false,
          message: 'Hijo no encontrado'
        });
      }
      const childData = childDoc.data();
      const isOwner = childData.parentId === req.user.uid;
      const isShared = Array.isArray(childData.sharedWith) && childData.sharedWith.includes(req.user.uid);
      if (!isOwner && !isShared) {
        return res.status(403).json({
          success: false,
          message: 'No tienes permisos para acceder a este hijo'
        });
      }
      pregnant = Boolean(childData.isUnborn);
      weeks = getWeeksFromChildData(childData);
      months = getMonthsFromChildData(childData);
      if (!pregnant && childData.birthDate) {
        ageBreakdown = calculateAgeBreakdownFromBirthDate(childData.birthDate);
      }
    } else if (gestationWeeks || isPregnant) {
      weeks = parseInt(gestationWeeks, 10);
      pregnant = true;
    } else if (ageWeeks || ageWeeks === 0) {
      weeks = parseInt(ageWeeks, 10);
    } else if (birthDate) {
      weeks = calculateWeeksFromBirthDate(birthDate);
      months = calculateMonthsFromBirthDate(birthDate);
      ageBreakdown = calculateAgeBreakdownFromBirthDate(birthDate);
    }

    if (pregnant) {
      if (!weeks || weeks < 1 || weeks > 45) {
        return res.status(400).json({
          success: false,
          message: 'Para embarazo debes enviar gestationWeeks (1-45) o childId'
        });
      }
    } else {
      if ((!weeks || weeks < 1 || weeks > 60) && (months === null || months < 0)) {
        return res.status(400).json({
          success: false,
          message: 'Debes enviar birthDate o ageWeeks (1-60) o childId'
        });
      }
    }

    let unit = 'week';
    let value = weeks;
    if (!pregnant) {
      const isUnderOneMonth = weeks !== null && weeks < 4;
      if (!isUnderOneMonth) {
        unit = 'month';
        if (months !== null) {
          value = Math.max(1, months);
        } else if (weeks !== null) {
          value = Math.max(1, Math.floor(weeks / 4.3));
        }
      }
    }

    const cacheKey = `/api/guide/today?childId=${resolvedChildId || 'none'}&unit=${unit}&value=${value}&pregnant=${Boolean(pregnant)}`;
    const cached = getCachedResponse(cacheKey);
    if (cached) {
      return res.json(cached);
    }

    const guide = await getDailyGuideFromAI({
      unit,
      value,
      name: name && String(name).trim() ? String(name).trim() : null,
      isPregnant: pregnant
    });

    let title = guide.title;
    let ageLabel = null;
    if (!pregnant && ageBreakdown && ageBreakdown.totalMonths >= 12) {
      const parts = [];
      if (ageBreakdown.years > 0) {
        parts.push(`${ageBreakdown.years} año${ageBreakdown.years === 1 ? '' : 's'}`);
      }
      if (ageBreakdown.months > 0) {
        parts.push(`${ageBreakdown.months} mes${ageBreakdown.months === 1 ? '' : 'es'}`);
      }
      ageLabel = parts.length > 0 ? parts.join(' ') : `${ageBreakdown.totalMonths} meses`;
      const titleSuffix = title && String(title).includes(':')
        ? String(title).split(':').slice(1).join(':').trim()
        : String(title || '');
      title = `${ageLabel}: ${titleSuffix || 'El descubrimiento'}`;
    }

    const responsePayload = {
      success: true,
      data: {
        title,
        subtitle: guide.subtitle,
        description: guide.description,
        tip: guide.tip,
        unit,
        value,
        ageLabel,
        ageYears: ageBreakdown ? ageBreakdown.years : null,
        ageMonths: ageBreakdown ? ageBreakdown.months : null,
        ageTotalMonths: ageBreakdown ? ageBreakdown.totalMonths : null,
        isPregnant: pregnant,
        source: guide.source
      }
    };

    setCachedResponse(cacheKey, responsePayload, 2 * 60 * 60 * 1000);
    res.json(responsePayload);
  } catch (error) {
    console.error('❌ Error obteniendo guía diaria:', error);
    res.status(500).json({
      success: false,
      message: 'Error obteniendo guía diaria',
      error: error.message
    });
  }
});

/**
 * Generar receta según ingredientes en la nevera y edad del hijo
 * POST /api/recipes/from-ingredients
 * Body: { ingredients: "leche, huevos, pan, queso...", childId: "xxx" }
 */
app.post('/api/recipes/from-ingredients', authenticateToken, async (req, res) => {
  try {
    const { ingredients, childId } = req.body || {};
    const userId = req.user.uid;

    const ingredientsText = typeof ingredients === 'string' ? ingredients.trim() : '';
    if (!ingredientsText || ingredientsText.length < 3) {
      return res.status(400).json({
        success: false,
        message: 'Envía "ingredients" con los alimentos que tienes en la nevera (texto libre)'
      });
    }

    let ageMonths = null;
    let childName = null;

    if (childId) {
      if (!db) {
        return res.status(503).json({ success: false, message: 'Base de datos no disponible' });
      }
      const childDoc = await db.collection('children').doc(childId).get();
      if (!childDoc.exists) {
        return res.status(404).json({ success: false, message: 'Hijo no encontrado' });
      }
      const childData = childDoc.data();
      const isParent = childData.parentId === userId;
      const isShared = Array.isArray(childData.sharedWith) && childData.sharedWith.includes(userId);
      if (!isParent && !isShared) {
        return res.status(403).json({ success: false, message: 'Sin permiso para este hijo' });
      }
      childName = childData.name || null;
      const birthDate = childData.birthDate?.toDate?.() || childData.birthDate;
      if (birthDate) {
        ageMonths = calculateMonthsFromBirthDate(birthDate);
      }
    }

    const ageContext = ageMonths !== null
      ? `El niño tiene ${ageMonths} meses (${Math.floor(ageMonths / 12)} años y ${ageMonths % 12} meses). La receta debe ser apropiada para su edad: evita alimentos de riesgo (miel antes del año, frutos secos enteros en menores de 5 años, etc.) y adapta texturas según la edad.`
      : 'No se especificó edad del niño. Sugiere recetas seguras para distintas edades e indica para qué rango de edad es adecuada cada una.';

    if (!openai) {
      return res.status(503).json({
        success: false,
        message: 'El servicio de recetas no está disponible (OPENAI_API_KEY no configurada)'
      });
    }

    const systemPrompt = `Eres un asistente de recetas para familias con niños pequeños. Tu tarea es sugerir recetas saludables, fáciles de preparar y apropiadas para la edad del niño.

${ageContext}

Responde en JSON con esta estructura EXACTA (igual que las recetas de nutrición):
{
  "recipe": {
    "mealType": "breakfast" | "lunch" | "dinner",
    "name": "Nombre atractivo de la receta",
    "description": "Breve descripción (1-2 líneas)",
    "ageAppropriate": true,
    "prepTime": número en minutos,
    "cookTime": número en minutos,
    "servings": número de porciones,
    "difficulty": "fácil" | "media" | "avanzada",
    "ingredients": [
      { "item": "ingrediente", "quantity": "cantidad con unidad" }
    ],
    "instructions": ["Paso 1 detallado", "Paso 2 detallado", "etc..."],
    "nutritionalInfo": {
      "calories": "aproximado por porción",
      "protein": "gramos aproximados",
      "carbs": "gramos aproximados",
      "fat": "gramos aproximados"
    },
    "tips": ["Consejo útil 1", "Consejo útil 2"],
    "allergens": ["posibles alérgenos presentes"]
  }
}

Usa principalmente los ingredientes que el usuario indicó. Puedes sugerir 1-2 ingredientes adicionales comunes si mejoran la receta.`;

    const userPrompt = `Ingredientes que tengo en la nevera:\n${ingredientsText}\n\nGenera una receta apropiada.`;

    let content = '';
    try {
      const completion = await openai.chat.completions.create({
        model: process.env.OPENAI_MODEL || 'gpt-3.5-turbo',
        messages: [
          { role: 'system', content: systemPrompt },
          { role: 'user', content: userPrompt }
        ],
        max_tokens: 1200,
        temperature: 0.7
      });
      content = completion.choices[0]?.message?.content || '';
    } catch (openaiErr) {
      console.error('❌ [RECIPES] OpenAI error:', openaiErr.message);
      return res.status(502).json({
        success: false,
        message: openaiErr.message?.includes('quota') || openaiErr.message?.includes('429')
          ? 'Límite de uso alcanzado. Intenta más tarde.'
          : 'Error al generar la receta. Intenta de nuevo.'
      });
    }

    let recipe = null;
    try {
      const jsonMatch = content.match(/\{[\s\S]*\}/);
      if (jsonMatch) {
        recipe = JSON.parse(jsonMatch[0]);
      }
    } catch (e) {
      console.warn('⚠️ [RECIPES] No se pudo parsear JSON:', e.message);
    }

    if (!recipe || !recipe.recipe) {
      recipe = {
        recipe: {
          mealType: 'lunch',
          name: 'Receta sugerida',
          description: 'No se pudo generar la receta. Intenta con otros ingredientes.',
          ageAppropriate: true,
          prepTime: 0,
          cookTime: 0,
          servings: 2,
          difficulty: 'fácil',
          ingredients: [],
          instructions: [content || 'Intenta con otros ingredientes.'],
          nutritionalInfo: { calories: '-', protein: '-', carbs: '-', fat: '-' },
          tips: [],
          allergens: []
        }
      };
    }

    const r = recipe?.recipe || {};
    const recipeIngredients = Array.isArray(r.ingredients)
      ? r.ingredients.map(ing => typeof ing === 'string' ? { item: ing, quantity: '' } : { item: String(ing?.item || ing?.name || ''), quantity: String(ing?.quantity || '') })
      : [];
    const tips = Array.isArray(r.tips) ? r.tips : (typeof r.tips === 'string' && r.tips ? [r.tips] : []);
    const allergens = Array.isArray(r.allergens) ? r.allergens : [];
    const instructions = Array.isArray(r.instructions) ? r.instructions : (typeof r.instructions === 'string' ? [r.instructions] : []);

    const enrichedRecipe = {
      id: `recipe_${Date.now()}_0`,
      mealType: r.mealType || 'lunch',
      name: r.name || r.title || 'Receta',
      description: r.description || '',
      ageAppropriate: r.ageAppropriate !== false,
      prepTime: parseInt(r.prepTime, 10) || 0,
      cookTime: parseInt(r.cookTime, 10) || 0,
      servings: parseInt(r.servings, 10) || 2,
      difficulty: r.difficulty || 'fácil',
      ingredients: recipeIngredients,
      instructions,
      nutritionalInfo: (r.nutritionalInfo && typeof r.nutritionalInfo === 'object') ? {
        calories: String(r.nutritionalInfo.calories || '-'),
        protein: String(r.nutritionalInfo.protein || '-'),
        carbs: String(r.nutritionalInfo.carbs || '-'),
        fat: String(r.nutritionalInfo.fat || '-')
      } : { calories: '-', protein: '-', carbs: '-', fat: '-' },
      tips,
      allergens,
      childId: childId || null,
      ageMonths,
      generatedAt: new Date().toISOString()
    };

    res.json({
      success: true,
      data: [enrichedRecipe],
      metadata: {
        childName: childName || null,
        ageMonths
      }
    });
  } catch (err) {
    console.error('❌ [RECIPES] Error:', err);
    res.status(500).json({
      success: false,
      message: err.message || 'Error generando receta',
      error: process.env.NODE_ENV === 'development' ? err.stack : undefined
    });
  }
});

