// Obtener lista de productos con filtros
app.get('/api/marketplace/products', authenticateToken, async (req, res) => {
  try {
    const { 
      type,           // venta, donacion, trueque
      category,       // transporte, ropa, etc.
      status,         // disponible, vendido, etc.
      minPrice,
      maxPrice,
      search,         // búsqueda en título/descripción
      orderBy,        // reciente, precio_asc, precio_desc
      page = 1,
      limit = 20,
      userId,         // Filtrar por usuario específico
      latitude,
      longitude
    } = req.query;

    if (!db) {
      return res.status(500).json({
        success: false,
        message: 'Base de datos no disponible'
      });
    }

    const userLocation = await getUserCountryForMarketplace(req.user.uid);

    let query = db.collection('marketplace_products');
    if (userLocation.countryId) {
      query = query.where('countryId', '==', userLocation.countryId);
    }

    // Aplicar filtros
    if (type && TRANSACTION_TYPES.includes(type)) {
      query = query.where('type', '==', type);
    }

    // Filtrar por categoría (ahora dinámica desde Firestore)
    // Soporta tanto slug como ID de categoría
    let categoryIdToFilter = null;
    if (category) {
      categoryIdToFilter = category;
      
      // Si no parece ser un ID de Firestore (muy corto o tiene guiones), buscar por slug
      if (category.length < 15 || category.includes('-')) {
        try {
          const categoryQuery = await db.collection('marketplace_categories')
            .where('slug', '==', category.toLowerCase())
            .limit(1)
            .get();
          
          if (!categoryQuery.empty) {
            categoryIdToFilter = categoryQuery.docs[0].id;
          }
        } catch (error) {
          console.warn('⚠️ Error buscando categoría por slug:', error);
        }
      }
      
      // Solo aplicar filtro si encontramos una categoría válida
      if (categoryIdToFilter) {
        query = query.where('category', '==', categoryIdToFilter);
      }
    }

    console.log('🔍 [MARKETPLACE] Filtros recibidos:', { status, userId, category, type, minPrice, maxPrice, search, orderBy });
    
    if (status && PRODUCT_STATUS.includes(status)) {
      query = query.where('status', '==', status);
      console.log('✅ [MARKETPLACE] Filtrando por status:', status);
    } else {
      // Por defecto, solo mostrar productos disponibles
      query = query.where('status', '==', 'disponible');
      console.log('✅ [MARKETPLACE] Filtrando por status por defecto: disponible');
    }

    if (userId) {
      query = query.where('userId', '==', userId);
      console.log('✅ [MARKETPLACE] Filtrando por userId:', userId);
    }

    // Filtro de aprobación (deshabilitado temporalmente para compatibilidad)
    // Los productos antiguos sin isApproved se mostrarán
    // TODO: En producción, habilitar: query = query.where('isApproved', '==', true);

    // Ordenamiento
    switch (orderBy) {
      case 'precio_asc':
        query = query.orderBy('price', 'asc');
        break;
      case 'precio_desc':
        query = query.orderBy('price', 'desc');
        break;
      case 'reciente':
      default:
        query = query.orderBy('createdAt', 'desc');
        break;
    }

    // Ejecutar query
    const snapshot = await query.get();
    const userLat = latitude ? parseFloat(latitude) : null;
    const userLng = longitude ? parseFloat(longitude) : null;
    const hasUserLocation = !isNaN(userLat) && !isNaN(userLng);

    let products = snapshot.docs.map(doc => {
      const data = doc.data();
      const location = normalizeMarketplaceLocation(data);
      return {
        id: doc.id,
        ...data,
        location
      };
    });

    products = products.filter(p => p.countryId && p.countryId === userLocation.countryId);

    // Filtro de precio (Firestore no permite where con != null)
    if (minPrice !== undefined) {
      const min = parseFloat(minPrice);
      products = products.filter(p => p.price >= min);
    }

    if (maxPrice !== undefined) {
      const max = parseFloat(maxPrice);
      products = products.filter(p => p.price <= max);
    }

    // Búsqueda en texto
    if (search) {
      const searchLower = search.toLowerCase();
      products = products.filter(p => 
        p.title.toLowerCase().includes(searchLower) ||
        p.description.toLowerCase().includes(searchLower)
      );
    }

    // Ordenar por distancia si hay ubicación del usuario
    if (hasUserLocation && (!orderBy || orderBy === 'distancia')) {
      products = products
        .filter(p => p.location && p.location.latitude && p.location.longitude)
        .map(p => ({
          ...p,
          distance: calculateDistance(
            userLat,
            userLng,
            p.location.latitude,
            p.location.longitude
          )
        }))
        .sort((a, b) => a.distance - b.distance);
    }

    // Logging de productos encontrados
    console.log(`📊 [MARKETPLACE] Productos encontrados: ${products.length}`);
    if (products.length > 0) {
      const statusCounts = products.reduce((acc, p) => {
        acc[p.status] = (acc[p.status] || 0) + 1;
        return acc;
      }, {});
      console.log('📊 [MARKETPLACE] Distribución por status:', statusCounts);
    }
    
    // Paginación
    const total = products.length;
    const startIndex = (page - 1) * limit;
    const endIndex = startIndex + parseInt(limit);
    const paginatedProducts = products.slice(startIndex, endIndex);

    console.log(`📄 [MARKETPLACE] Devolviendo página ${page}: ${paginatedProducts.length} productos (de ${total} totales)`);

    res.json({
      success: true,
      data: paginatedProducts,
      pagination: {
        total,
        page: parseInt(page),
        limit: parseInt(limit),
        totalPages: Math.ceil(total / limit)
      }
    });

  } catch (error) {
    console.error('❌ [MARKETPLACE] Error obteniendo productos:', error);
    res.status(500).json({
      success: false,
      message: 'Error obteniendo productos',
      error: error.message
    });
  }
});
// Buscar productos cercanos (por proximidad geográfica)
app.get('/api/marketplace/products/nearby', authenticateToken, async (req, res) => {
  try {
    const cacheKey = `${buildCacheKey(req)}&uid=${req.user.uid}`;
    const cached = getCachedResponse(cacheKey);
    if (cached) {
      return res.json(cached);
    }

    const {
      latitude,
      longitude,
      radius = 50,    // Radio en kilómetros (por defecto 50 km)
      type,
      category,
      status,
      minPrice,
      maxPrice,
      search,
      orderBy,
      page = 1,
      limit = 20
    } = req.query;

    if (!db) {
      return res.status(500).json({
        success: false,
        message: 'Base de datos no disponible'
      });
    }

    const userLocation = await getUserCountryForMarketplace(req.user.uid);
    const userLat = latitude ? parseFloat(latitude) : null;
    const userLng = longitude ? parseFloat(longitude) : null;
    const searchRadius = parseFloat(radius);
    const hasUserLocation = !isNaN(userLat) && !isNaN(userLng);

    if ((latitude || longitude) && !hasUserLocation) {
      return res.status(400).json({
        success: false,
        message: 'Latitude y longitude deben ser números válidos'
      });
    }
    // Función para calcular distancia entre dos puntos (fórmula de Haversine)
    const calculateDistance = (lat1, lon1, lat2, lon2) => {
      const R = 6371; // Radio de la Tierra en km
      const dLat = (lat2 - lat1) * Math.PI / 180;
      const dLon = (lon2 - lon1) * Math.PI / 180;
      const a = 
        Math.sin(dLat/2) * Math.sin(dLat/2) +
        Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
        Math.sin(dLon/2) * Math.sin(dLon/2);
      const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
      return R * c; // Distancia en km
    };

    let query = db.collection('marketplace_products');

    // Aplicar filtros básicos
    if (type && TRANSACTION_TYPES.includes(type)) {
      query = query.where('type', '==', type);
    }

    // Filtrar por categoría (ahora dinámica desde Firestore)
    // Soporta tanto slug como ID de categoría
    let categoryIdToFilter = null;
    if (category) {
      categoryIdToFilter = category;
      
      // Si no parece ser un ID de Firestore (muy corto o tiene guiones), buscar por slug
      if (category.length < 15 || category.includes('-')) {
        try {
          const categoryQuery = await db.collection('marketplace_categories')
            .where('slug', '==', category.toLowerCase())
            .limit(1)
            .get();
          
          if (!categoryQuery.empty) {
            categoryIdToFilter = categoryQuery.docs[0].id;
          }
        } catch (error) {
          console.warn('⚠️ Error buscando categoría por slug:', error);
        }
      }
      
      // Solo aplicar filtro si encontramos una categoría válida
      if (categoryIdToFilter) {
        query = query.where('category', '==', categoryIdToFilter);
      }
    }

    if (status && PRODUCT_STATUS.includes(status)) {
      query = query.where('status', '==', status);
    } else {
      query = query.where('status', '==', 'disponible');
    }

    // Filtro de aprobación (deshabilitado temporalmente para compatibilidad)
    // Los productos antiguos sin isApproved se mostrarán
    // TODO: En producción, habilitar: query = query.where('isApproved', '==', true);

    // Obtener todos los productos
    const snapshot = await query.get();
    let products = snapshot.docs.map(doc => {
      const data = doc.data();
      const location = normalizeMarketplaceLocation(data);
      return {
        id: doc.id,
        ...data,
        location
      };
    });

    products = products.filter(p => p.countryId && p.countryId === userLocation.countryId);

    if (hasUserLocation && (!orderBy || orderBy === 'distancia')) {
      products = products
        .filter(p => p.location && p.location.latitude && p.location.longitude)
        .map(p => ({
          ...p,
          distance: calculateDistance(
            userLat,
            userLng,
            p.location.latitude,
            p.location.longitude
          )
        }))
        .filter(p => p.distance <= parseFloat(radius));
    }

    // Filtrar por distancia y calcular distancia para cada producto
    products = products
      .filter(p => p.location && p.location.latitude && p.location.longitude)
      .map(p => {
        const distance = calculateDistance(
          userLat, 
          userLng, 
          p.location.latitude, 
          p.location.longitude
        );
        return { ...p, distance };
      })
      .filter(p => p.distance <= searchRadius);

    // Filtro de precio
    if (minPrice !== undefined) {
      const min = parseFloat(minPrice);
      products = products.filter(p => p.price >= min);
    }

    if (maxPrice !== undefined) {
      const max = parseFloat(maxPrice);
      products = products.filter(p => p.price <= max);
    }

    // Búsqueda en texto
    if (search) {
      const searchLower = search.toLowerCase();
      products = products.filter(p => 
        p.title.toLowerCase().includes(searchLower) ||
        p.description.toLowerCase().includes(searchLower)
      );
    }

    // Ordenamiento
    const orderByNormalized = orderBy || 'distancia';
    switch (orderByNormalized) {
      case 'distancia':
        products.sort((a, b) => a.distance - b.distance);
        break;
      case 'precio_asc':
        products.sort((a, b) => (a.price || 0) - (b.price || 0));
        break;
      case 'precio_desc':
        products.sort((a, b) => (b.price || 0) - (a.price || 0));
        break;
      case 'reciente':
      default:
        products.sort((a, b) => b.createdAt.seconds - a.createdAt.seconds);
        break;
    }

    // Paginación
    const total = products.length;
    const startIndex = (page - 1) * limit;
    const endIndex = startIndex + parseInt(limit);
    const paginatedProducts = products.slice(startIndex, endIndex);

    const responsePayload = {
      success: true,
      data: paginatedProducts,
      searchParams: {
        latitude: userLat,
        longitude: userLng,
        radius: searchRadius
      },
      pagination: {
        total,
        page: parseInt(page),
        limit: parseInt(limit),
        totalPages: Math.ceil(total / limit)
      }
    };

    setCachedResponse(cacheKey, responsePayload);
    res.json(responsePayload);

  } catch (error) {
    console.error('❌ [MARKETPLACE] Error buscando productos cercanos:', error);
    res.status(500).json({
      success: false,
      message: 'Error buscando productos cercanos',
      error: error.message
    });
  }
});

// Top productos cercanos por vistas (APP)
app.get('/api/marketplace/products/nearby/top', authenticateToken, async (req, res) => {
  try {
    const cacheKey = `${buildCacheKey(req)}&uid=${req.user.uid}`;
    const cached = getCachedResponse(cacheKey);
    if (cached) {
      return res.json(cached);
    }

    const {
      latitude,
      longitude,
      radius = 50,
      type,
      category,
      status,
      limit = 3
    } = req.query;

    const userLat = latitude ? parseFloat(latitude) : null;
    const userLng = longitude ? parseFloat(longitude) : null;
    const searchRadius = parseFloat(radius);
    const limitNumber = Math.min(parseInt(limit), 10);

    if ((latitude || longitude) && (isNaN(userLat) || userLat < -90 || userLat > 90)) {
      return res.status(400).json({
        success: false,
        message: 'Latitud inválida'
      });
    }

    if ((latitude || longitude) && (isNaN(userLng) || userLng < -180 || userLng > 180)) {
      return res.status(400).json({
        success: false,
        message: 'Longitud inválida'
      });
    }

    if (!db) {
      return res.status(500).json({
        success: false,
        message: 'Base de datos no disponible'
      });
    }

    const calculateDistance = (lat1, lon1, lat2, lon2) => {
      const R = 6371;
      const dLat = (lat2 - lat1) * Math.PI / 180;
      const dLon = (lon2 - lon1) * Math.PI / 180;
      const a = 
        Math.sin(dLat/2) * Math.sin(dLat/2) +
        Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
        Math.sin(dLon/2) * Math.sin(dLon/2);
      const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
      return R * c;
    };

    let query = db.collection('marketplace_products');

    if (type && TRANSACTION_TYPES.includes(type)) {
      query = query.where('type', '==', type);
    }

    let categoryIdToFilter = null;
    if (category) {
      categoryIdToFilter = category;
      if (typeof category === 'string' && category.includes('-')) {
        try {
          const categoryQuery = await db.collection('marketplace_categories')
            .where('slug', '==', category)
            .limit(1)
            .get();
          if (!categoryQuery.empty) {
            categoryIdToFilter = categoryQuery.docs[0].id;
          }
        } catch (error) {
          console.warn('⚠️ Error buscando categoría por slug:', error);
        }
      }
      if (categoryIdToFilter) {
        query = query.where('category', '==', categoryIdToFilter);
      }
    }

    if (status && PRODUCT_STATUS.includes(status)) {
      query = query.where('status', '==', status);
    } else {
      query = query.where('status', '==', 'disponible');
    }

    const userLocation = await getUserCountryForMarketplace(req.user.uid);
    const snapshot = await query.get();
    let products = snapshot.docs.map(doc => {
      const data = doc.data();
      const location = normalizeMarketplaceLocation(data);
      return {
        id: doc.id,
        ...data,
        location
      };
    });

    products = products.filter(p => p.countryId && p.countryId === userLocation.countryId);

    if (!isNaN(userLat) && !isNaN(userLng)) {
      products = products
        .filter(p => p.location && p.location.latitude && p.location.longitude)
        .map(p => {
          const distance = calculateDistance(
            userLat,
            userLng,
            p.location.latitude,
            p.location.longitude
          );
          return { ...p, distance };
        })
        .filter(p => p.distance <= searchRadius);
    }

    products.sort((a, b) => {
      const aViews = a.views || 0;
      const bViews = b.views || 0;
      if (bViews !== aViews) return bViews - aViews;
      if (a.distance !== b.distance) return a.distance - b.distance;
      return (b.createdAt?.seconds || 0) - (a.createdAt?.seconds || 0);
    });

    const topProducts = products.slice(0, limitNumber);

    const responsePayload = {
      success: true,
      data: topProducts,
      meta: {
        latitude: !isNaN(userLat) ? userLat : null,
        longitude: !isNaN(userLng) ? userLng : null,
        radius: searchRadius,
        limit: limitNumber
      }
    };

    setCachedResponse(cacheKey, responsePayload);
    res.json(responsePayload);
  } catch (error) {
    console.error('❌ [MARKETPLACE] Error obteniendo top productos cercanos:', error);
    res.status(500).json({
      success: false,
      message: 'Error obteniendo top productos cercanos',
      error: error.message
    });
  }
});

// Obtener detalle de un producto específico
app.get('/api/marketplace/products/:id', async (req, res) => {
  try {
    const { id } = req.params;

    if (!db) {
      return res.status(500).json({
        success: false,
        message: 'Base de datos no disponible'
      });
    }

    const productDoc = await db.collection('marketplace_products').doc(id).get();

    if (!productDoc.exists) {
      return res.status(404).json({
        success: false,
        message: 'Producto no encontrado'
      });
    }

    const productData = productDoc.data();
    
    // Precio efectivo (promo si aplica)
    let effectivePrice = productData.price;
    let hasPromo = false;
    if (productData.type === 'venta' && productData.price) {
      const promoValid = productData.promoValidUntil && new Date(productData.promoValidUntil) >= new Date();
      if (promoValid && (productData.promoPrice != null || productData.discountPercentage != null)) {
        hasPromo = true;
        if (productData.promoPrice != null) {
          effectivePrice = productData.promoPrice;
        } else {
          effectivePrice = Math.max(0, productData.price * (1 - (productData.discountPercentage || 0) / 100));
        }
      }
    }
    
    // Enriquecer con información actualizada del vendedor
    const sellerDoc = await db.collection('users').doc(productData.userId).get();
    let enrichedProduct = {
      id: productDoc.id,
      ...productData,
      location: normalizeMarketplaceLocation(productData),
      effectivePrice: productData.type === 'venta' ? effectivePrice : null,
      hasPromo
    };
    
    if (sellerDoc.exists) {
      const sellerData = sellerDoc.data();
      enrichedProduct.userName = sellerData.displayName || sellerData.name || productData.userName || 'Usuario';
      enrichedProduct.userPhoto = sellerData.photoUrl || productData.userPhoto || null;
      console.log(`✅ [MARKETPLACE] Producto ${id} enriquecido con info del vendedor: ${enrichedProduct.userName}`);
    } else {
      console.log(`⚠️ [MARKETPLACE] Vendedor ${productData.userId} no encontrado para producto ${id}`);
    }

    // Incrementar contador de vistas
    await db.collection('marketplace_products').doc(id).update({
      views: admin.firestore.FieldValue.increment(1)
    });

    res.json({
      success: true,
      data: enrichedProduct
    });

  } catch (error) {
    console.error('❌ [MARKETPLACE] Error obteniendo producto:', error);
    res.status(500).json({
      success: false,
      message: 'Error obteniendo producto',
      error: error.message
    });
  }
});

// Crear nuevo producto
app.post('/api/marketplace/products', authenticateToken, async (req, res) => {
  try {
    const { uid } = req.user;
    const {
      title,
      description,
      category,
      condition,
      photos,
      type,
      price,
      tradeFor,
      location,
      cityId,
      countryId
    } = req.body;

    // Validaciones
    if (!title || title.trim().length < 10 || title.trim().length > 100) {
      return res.status(400).json({
        success: false,
        message: 'El título debe tener entre 10 y 100 caracteres'
      });
    }

    if (!description || description.trim().length < 20 || description.trim().length > 1000) {
      return res.status(400).json({
        success: false,
        message: 'La descripción debe tener entre 20 y 1000 caracteres'
      });
    }

    // Validar categoría dinámica desde Firestore
    if (!category) {
      return res.status(400).json({
        success: false,
        message: 'La categoría es requerida'
      });
    }

    if (!db) {
      return res.status(500).json({
        success: false,
        message: 'Base de datos no disponible'
      });
    }

    // Verificar que la categoría existe y está activa (buscar por slug o por ID)
    let categoryDoc;
    let categoryId;
    
    // Primero intentar buscar por ID
    categoryDoc = await db.collection('marketplace_categories').doc(category).get();
    
    if (categoryDoc.exists) {
      categoryId = categoryDoc.id;
    } else {
      // Si no existe por ID, buscar por slug
      const categoryQuery = await db.collection('marketplace_categories')
        .where('slug', '==', category.toLowerCase())
        .limit(1)
        .get();
      
      if (categoryQuery.empty) {
        return res.status(400).json({
          success: false,
          message: 'Categoría inválida o no existe'
        });
      }
      
      categoryDoc = categoryQuery.docs[0];
      categoryId = categoryDoc.id;
    }

    const categoryData = categoryDoc.data();
    if (!categoryData.isActive) {
      return res.status(400).json({
        success: false,
        message: 'La categoría no está disponible'
      });
    }

    if (!condition || !PRODUCT_CONDITIONS.includes(condition)) {
      return res.status(400).json({
        success: false,
        message: 'Condición del producto inválida'
      });
    }

    if (!photos || !Array.isArray(photos) || photos.length === 0 || photos.length > 5) {
      return res.status(400).json({
        success: false,
        message: 'Debes subir entre 1 y 5 fotos'
      });
    }

    if (!type || !TRANSACTION_TYPES.includes(type)) {
      return res.status(400).json({
        success: false,
        message: 'Tipo de transacción inválido'
      });
    }

    if (type === 'venta') {
      if (!price || price <= 0) {
        return res.status(400).json({
          success: false,
          message: 'El precio es requerido para ventas y debe ser mayor a 0'
        });
      }
    }

    if (type === 'trueque') {
      if (!tradeFor || tradeFor.trim().length < 5) {
        return res.status(400).json({
          success: false,
          message: 'Debes especificar qué buscas a cambio'
        });
      }
    }

    let locationData = { countryId: null, countryName: null, cityId: null, cityName: null };
    if (!cityId && !countryId) {
      locationData = await getDefaultUserLocation();
    } else {
      try {
        locationData = await resolveCountryCity(countryId, cityId);
      } catch (err) {
        return res.status(400).json({
          success: false,
          message: err.message
        });
      }
    }

    let normalizedLocation = {
      city: locationData.cityName || '',
      state: '',
      country: locationData.countryName || null
    };
    if (location && typeof location === 'object') {
      const hasLat = location.latitude !== undefined && location.latitude !== null;
      const hasLng = location.longitude !== undefined && location.longitude !== null;
      normalizedLocation.city = location.city || locationData.cityName || '';
      normalizedLocation.state = location.state || '';
      normalizedLocation.country = location.country || locationData.countryName || null;
      if (hasLat || hasLng) {
        const lat = parseFloat(location.latitude);
        const lng = parseFloat(location.longitude);
        if (!isNaN(lat) && !isNaN(lng)) {
          normalizedLocation.latitude = lat;
          normalizedLocation.longitude = lng;
        }
      }
    }

    if (!db) {
      return res.status(500).json({
        success: false,
        message: 'Base de datos no disponible'
      });
    }

    // Obtener información del usuario
    const userDoc = await db.collection('users').doc(uid).get();
    const userData = userDoc.data();

    // Crear producto
    const now = new Date();
    const productData = {
      userId: uid,
      userName: userData?.displayName || userData?.name || 'Usuario',
      userPhoto: userData?.photoUrl || null,
      
      title: title.trim(),
      description: description.trim(),
      category: categoryId,  // Guardar el ID real de la categoría
      categoryName: categoryData.name,  // Guardar el nombre para facilitar consultas
      categorySlug: categoryData.slug,  // Guardar el slug para referencia
      condition,
      photos,
      
      type,
      price: type === 'venta' ? parseFloat(price) : null,
      tradeFor: type === 'trueque' ? tradeFor.trim() : null,
      
      location: normalizedLocation,
      countryId: locationData.countryId,
      countryName: locationData.countryName,
      cityId: locationData.cityId,
      cityName: locationData.cityName,
      
      status: 'disponible',
      
      views: 0,
      favorites: 0,
      messages: 0,
      
      createdAt: now,
      updatedAt: now,
      publishedAt: now,
      soldAt: null,
      
      isApproved: true,  // Auto-aprobar por ahora
      isReported: false,
      reportCount: 0
    };

    const productRef = await db.collection('marketplace_products').add(productData);

    console.log('✅ [MARKETPLACE] Producto creado:', productRef.id);

    res.json({
      success: true,
      message: 'Producto publicado exitosamente',
      data: {
        id: productRef.id,
        ...productData
      }
    });

  } catch (error) {
    console.error('❌ [MARKETPLACE] Error creando producto:', error);
    res.status(500).json({
      success: false,
      message: 'Error creando producto',
      error: error.message
    });
  }
});

// Actualizar producto propio
app.put('/api/marketplace/products/:id', authenticateToken, async (req, res) => {
  try {
    const { uid } = req.user;
    const { id } = req.params;
    const {
      title,
      description,
      category,
      condition,
      photos,
      price,
      tradeFor,
      location,
      cityId,
      countryId,
      promoPrice,
      discountPercentage,
      promoValidUntil,
      promoLabel,
      promoClear
    } = req.body;

    if (!db) {
      return res.status(500).json({
        success: false,
        message: 'Base de datos no disponible'
      });
    }

    // Verificar que el producto existe y pertenece al usuario
    const productDoc = await db.collection('marketplace_products').doc(id).get();

    if (!productDoc.exists) {
      return res.status(404).json({
        success: false,
        message: 'Producto no encontrado'
      });
    }

    if (productDoc.data().userId !== uid) {
      return res.status(403).json({
        success: false,
        message: 'No tienes permisos para editar este producto'
      });
    }

    // Preparar datos de actualización
    const updateData = {
      updatedAt: new Date()
    };

    if (title) {
      if (title.trim().length < 10 || title.trim().length > 100) {
        return res.status(400).json({
          success: false,
          message: 'El título debe tener entre 10 y 100 caracteres'
        });
      }
      updateData.title = title.trim();
    }

    if (description) {
      if (description.trim().length < 20 || description.trim().length > 1000) {
        return res.status(400).json({
          success: false,
          message: 'La descripción debe tener entre 20 y 1000 caracteres'
        });
      }
      updateData.description = description.trim();
    }

    if (category) {
      // Verificar que la categoría existe y está activa (buscar por slug o por ID)
      let categoryDoc;
      let categoryId;
      
      // Primero intentar buscar por ID
      categoryDoc = await db.collection('marketplace_categories').doc(category).get();
      
      if (categoryDoc.exists) {
        categoryId = categoryDoc.id;
      } else {
        // Si no existe por ID, buscar por slug
        const categoryQuery = await db.collection('marketplace_categories')
          .where('slug', '==', category.toLowerCase())
          .limit(1)
          .get();
        
        if (categoryQuery.empty) {
          return res.status(400).json({
            success: false,
            message: 'Categoría inválida o no existe'
          });
        }
        
        categoryDoc = categoryQuery.docs[0];
        categoryId = categoryDoc.id;
      }

      const categoryData = categoryDoc.data();
      if (!categoryData.isActive) {
        return res.status(400).json({
          success: false,
          message: 'La categoría no está disponible'
        });
      }

      updateData.category = categoryId;
      updateData.categoryName = categoryData.name;
      updateData.categorySlug = categoryData.slug;
    }

    if (condition) {
      if (!PRODUCT_CONDITIONS.includes(condition)) {
        return res.status(400).json({
          success: false,
          message: 'Condición del producto inválida'
        });
      }
      updateData.condition = condition;
    }

    if (photos) {
      if (!Array.isArray(photos) || photos.length === 0 || photos.length > 5) {
        return res.status(400).json({
          success: false,
          message: 'Debes tener entre 1 y 5 fotos'
        });
      }
      updateData.photos = photos;
    }

    if (price !== undefined) {
      if (productDoc.data().type === 'venta' && price <= 0) {
        return res.status(400).json({
          success: false,
          message: 'El precio debe ser mayor a 0'
        });
      }
      updateData.price = parseFloat(price);
    }

    if (tradeFor) {
      updateData.tradeFor = tradeFor.trim();
    }

    // Promociones (solo para productos de venta)
    if (productDoc.data().type === 'venta') {
      if (promoClear) {
        updateData.promoPrice = admin.firestore.FieldValue.delete();
        updateData.discountPercentage = admin.firestore.FieldValue.delete();
        updateData.promoValidUntil = admin.firestore.FieldValue.delete();
        updateData.promoLabel = admin.firestore.FieldValue.delete();
      } else if (promoPrice !== undefined || discountPercentage !== undefined || promoValidUntil !== undefined || promoLabel !== undefined) {
        const basePrice = productDoc.data().price || 0;
        if (promoPrice !== undefined && promoPrice !== null && promoPrice !== '') {
          const p = parseFloat(promoPrice);
          if (p >= 0 && p <= basePrice) updateData.promoPrice = p;
        }
        if (discountPercentage !== undefined && discountPercentage !== null && discountPercentage !== '') {
          const d = parseFloat(discountPercentage);
          if (d >= 0 && d <= 100) updateData.discountPercentage = d;
        }
        if (promoValidUntil !== undefined && promoValidUntil !== null && promoValidUntil !== '') {
          updateData.promoValidUntil = new Date(promoValidUntil);
        }
        if (promoLabel !== undefined && promoLabel !== null) {
          updateData.promoLabel = String(promoLabel).trim().slice(0, 50);
        }
      }
    }

    const hasLocationUpdate = Object.prototype.hasOwnProperty.call(req.body || {}, 'cityId')
      || Object.prototype.hasOwnProperty.call(req.body || {}, 'countryId');
    if (hasLocationUpdate) {
      try {
        const locationData = await resolveCountryCity(countryId, cityId);
        updateData.countryId = locationData.countryId;
        updateData.countryName = locationData.countryName;
        updateData.cityId = locationData.cityId;
        updateData.cityName = locationData.cityName;
      } catch (err) {
        return res.status(400).json({
          success: false,
          message: err.message
        });
      }
    }

    if (location) {
      // Validar coordenadas si se proporciona ubicación
      if (location.latitude && location.longitude) {
        const lat = parseFloat(location.latitude);
        const lng = parseFloat(location.longitude);
        
        if (isNaN(lat) || lat < -90 || lat > 90) {
          return res.status(400).json({
            success: false,
            message: 'Latitud inválida (debe estar entre -90 y 90)'
          });
        }

        if (isNaN(lng) || lng < -180 || lng > 180) {
          return res.status(400).json({
            success: false,
            message: 'Longitud inválida (debe estar entre -180 y 180)'
          });
        }

        updateData.location = {
          latitude: lat,
          longitude: lng,
          city: location.city || '',
          state: location.state || '',
          country: location.country || updateData.countryName || 'México'
        };
      } else {
        return res.status(400).json({
          success: false,
          message: 'Las coordenadas (latitude, longitude) son requeridas'
        });
      }
    }

    await db.collection('marketplace_products').doc(id).update(updateData);

    console.log('✅ [MARKETPLACE] Producto actualizado:', id);

    res.json({
      success: true,
      message: 'Producto actualizado exitosamente',
      data: updateData
    });

  } catch (error) {
    console.error('❌ [MARKETPLACE] Error actualizando producto:', error);
    res.status(500).json({
      success: false,
      message: 'Error actualizando producto',
      error: error.message
    });
  }
});

