// Cambiar estado del producto
app.patch('/api/marketplace/products/:id/status', authenticateToken, async (req, res) => {
  try {
    const { uid } = req.user;
    const { id } = req.params;
    const { status, buyerId, buyerName } = req.body;

    if (!status || !PRODUCT_STATUS.includes(status)) {
      return res.status(400).json({
        success: false,
        message: 'Estado inválido'
      });
    }

    if (!db) {
      return res.status(500).json({
        success: false,
        message: 'Base de datos no disponible'
      });
    }

    const productDoc = await db.collection('marketplace_products').doc(id).get();

    if (!productDoc.exists) {
      return res.status(404).json({
        success: false,
        message: 'Producto no encontrado'
      });
    }

    if (productDoc.data().userId !== uid) {
      return res.status(403).json({
        success: false,
        message: 'No tienes permisos para cambiar el estado de este producto'
      });
    }

    const now = new Date();
    const updateData = {
      status,
      updatedAt: now
    };

    // Si se marca como vendido/donado/intercambiado, guardar fecha y crear transacción
    if (['vendido', 'donado', 'intercambiado'].includes(status)) {
      updateData.soldAt = now;

      // Crear transacción
      const productData = productDoc.data();
      let saleAmount = productData.price || 0;
      if (productData.type === 'venta') {
        const promoValid = productData.promoValidUntil && new Date(productData.promoValidUntil) >= now;
        if (promoValid && (productData.promoPrice != null || productData.discountPercentage != null)) {
          if (productData.promoPrice != null) {
            saleAmount = productData.promoPrice;
          } else {
            saleAmount = Math.max(0, saleAmount * (1 - (productData.discountPercentage || 0) / 100));
          }
        }
      }
      const transactionData = {
        productId: id,
        productTitle: productData.title,
        sellerId: uid,
        sellerName: productData.userName,
        buyerId: buyerId || null,
        buyerName: buyerName || 'No especificado',
        type: productData.type,
        amount: saleAmount,
        originalPrice: productData.type === 'venta' ? (productData.price || 0) : null,
        tradeDetails: productData.tradeFor || null,
        status: 'completada',
        createdAt: now,
        completedAt: now
      };

      await db.collection('marketplace_transactions').add(transactionData);
      console.log('✅ [MARKETPLACE] Transacción creada para producto:', id);

      // Notificar a todos los usuarios que chatearon sobre este producto
      try {
        const productData = productDoc.data();
        console.log('📢 [MARKETPLACE] Buscando usuarios que chatearon sobre el producto:', id);
        
        // Obtener todos los mensajes relacionados con este producto
        const messagesSnapshot = await db.collection('marketplace_messages')
          .where('productId', '==', id)
          .get();

        // Recopilar IDs únicos de usuarios (excluyendo al vendedor)
        const interestedUserIds = new Set();
        messagesSnapshot.docs.forEach(doc => {
          const msgData = doc.data();
          if (msgData.senderId !== uid) {
            interestedUserIds.add(msgData.senderId);
          }
          if (msgData.receiverId !== uid) {
            interestedUserIds.add(msgData.receiverId);
          }
        });

        console.log(`📢 [MARKETPLACE] ${interestedUserIds.size} usuarios interesados encontrados`);

        // Enviar notificación a cada usuario interesado
        for (const userId of interestedUserIds) {
          try {
            // Obtener tokens FCM del usuario
            const userDoc = await db.collection('users').doc(userId).get();
            if (!userDoc.exists || !userDoc.data().fcmTokens || userDoc.data().fcmTokens.length === 0) {
              console.log(`⚠️ [MARKETPLACE] Usuario ${userId} sin tokens FCM`);
              continue;
            }

            const tokens = userDoc.data().fcmTokens;
            const statusText = status === 'vendido' ? 'vendió' : status === 'donado' ? 'donó' : 'intercambió';

            // Enviar push notification
            await sendPushNotification(
              tokens,
              {
                title: '🛍️ Artículo vendido',
                body: `${productData.title} ya se ${statusText}. ¡Gracias por tu interés!`
              },
              {
                type: 'compra',
                productId: id,
                productTitle: productData.title,
                status: status,
                sellerId: uid
              }
            );

            // Guardar notificación en Firestore para historial
            await db.collection('notifications').add({
              userId: userId,
              type: 'compra',
              title: '🛍️ Artículo vendido',
              message: `${productData.title} ya se ${statusText}. ¡Gracias por tu interés!`,
              data: {
                productId: id,
                productTitle: productData.title,
                status: status,
                sellerId: uid
              },
              read: false,
              createdAt: now
            });

            console.log(`✅ [MARKETPLACE] Notificación enviada a usuario ${userId}`);

          } catch (userError) {
            console.error(`❌ [MARKETPLACE] Error notificando a usuario ${userId}:`, userError.message);
          }
        }

      } catch (notifyError) {
        console.error('❌ [MARKETPLACE] Error enviando notificaciones:', notifyError.message);
        // No fallar el endpoint si las notificaciones fallan
      }
    }

    await db.collection('marketplace_products').doc(id).update(updateData);

    console.log('✅ [MARKETPLACE] Estado actualizado:', id, '->', status);
    console.log('📝 [MARKETPLACE] Datos actualizados:', JSON.stringify(updateData, null, 2));
    
    // Verificar que se guardó correctamente
    const updatedDoc = await db.collection('marketplace_products').doc(id).get();
    const updatedData = updatedDoc.data();
    console.log('🔍 [MARKETPLACE] Verificación - Status en BD:', updatedData.status);

    res.json({
      success: true,
      message: 'Estado actualizado exitosamente',
      data: {
        ...updateData,
        currentStatus: updatedData.status // Incluir el status actual de la BD
      }
    });

  } catch (error) {
    console.error('❌ [MARKETPLACE] Error actualizando estado:', error);
    res.status(500).json({
      success: false,
      message: 'Error actualizando estado',
      error: error.message
    });
  }
});

