// Obtener conversaciones del usuario
app.get('/api/marketplace/messages', authenticateToken, async (req, res) => {
  try {
    const { uid } = req.user;

    if (!db) {
      return res.status(500).json({
        success: false,
        message: 'Base de datos no disponible'
      });
    }

    // Obtener mensajes donde el usuario es sender o receiver
    const sentMessages = await db.collection('marketplace_messages')
      .where('senderId', '==', uid)
      .orderBy('createdAt', 'desc')
      .limit(100)
      .get();

    const receivedMessages = await db.collection('marketplace_messages')
      .where('receiverId', '==', uid)
      .orderBy('createdAt', 'desc')
      .limit(100)
      .get();

    const allMessages = [
      ...sentMessages.docs.map(doc => ({ id: doc.id, ...doc.data() })),
      ...receivedMessages.docs.map(doc => ({ id: doc.id, ...doc.data() }))
    ];

    // Agrupar por producto
    const conversationsByProduct = {};
    allMessages.forEach(msg => {
      if (!conversationsByProduct[msg.productId]) {
        conversationsByProduct[msg.productId] = [];
      }
      conversationsByProduct[msg.productId].push(msg);
    });

    res.json({
      success: true,
      data: conversationsByProduct
    });

  } catch (error) {
    console.error('❌ [MARKETPLACE] Error obteniendo mensajes:', error);
    res.status(500).json({
      success: false,
      message: 'Error obteniendo mensajes',
      error: error.message
    });
  }
});

// Obtener mensajes de un producto específico
app.get('/api/marketplace/messages/:productId', authenticateToken, async (req, res) => {
  try {
    const { uid } = req.user;
    const { productId } = req.params;

    if (!db) {
      return res.status(500).json({
        success: false,
        message: 'Base de datos no disponible'
      });
    }

    const messagesSnapshot = await db.collection('marketplace_messages')
      .where('productId', '==', productId)
      .orderBy('createdAt', 'asc')
      .get();

    let messages = messagesSnapshot.docs
      .map(doc => ({ id: doc.id, ...doc.data() }))
      .filter(msg => msg.senderId === uid || msg.receiverId === uid);

    // Enriquecer mensajes con información actual de usuarios
    const usersCache = {};
    const userIds = new Set();
    
    // Recolectar todos los IDs de usuarios únicos
    messages.forEach(msg => {
      if (msg.senderId) userIds.add(msg.senderId);
      if (msg.receiverId) userIds.add(msg.receiverId);
    });

    console.log(`🔍 [MARKETPLACE] Enriqueciendo ${messages.length} mensajes con info de ${userIds.size} usuarios`);

    // Obtener información de todos los usuarios de una vez
    for (const userId of userIds) {
      try {
        const userDoc = await db.collection('users').doc(userId).get();
        if (userDoc.exists) {
          usersCache[userId] = userDoc.data();
          const userName = usersCache[userId].displayName || usersCache[userId].name || 'Usuario';
          console.log(`✅ [MARKETPLACE] Usuario ${userId}: ${userName}, foto: ${usersCache[userId].photoUrl ? 'Sí' : 'No'}`);
        } else {
          console.log(`⚠️ [MARKETPLACE] Usuario ${userId} no encontrado en Firestore`);
        }
      } catch (error) {
        console.error(`❌ [MARKETPLACE] Error obteniendo usuario ${userId}:`, error);
      }
    }

    // Enriquecer cada mensaje con la información actualizada
    messages = messages.map(msg => {
      const enrichedMsg = { ...msg };

      // Enriquecer información del sender - usar displayName o name (consistente con el resto del código)
      if (msg.senderId && usersCache[msg.senderId]) {
        enrichedMsg.senderName = usersCache[msg.senderId].displayName || usersCache[msg.senderId].name || 'Usuario';
        enrichedMsg.senderPhoto = usersCache[msg.senderId].photoUrl || null;
      } else if (msg.senderId) {
        console.log(`⚠️ [MARKETPLACE] No se encontró info para sender: ${msg.senderId}`);
        enrichedMsg.senderName = enrichedMsg.senderName || 'Usuario';
        enrichedMsg.senderPhoto = null;
      }

      // Enriquecer información del receiver - usar displayName o name (consistente con el resto del código)
      if (msg.receiverId && usersCache[msg.receiverId]) {
        enrichedMsg.receiverName = usersCache[msg.receiverId].displayName || usersCache[msg.receiverId].name || 'Usuario';
        enrichedMsg.receiverPhoto = usersCache[msg.receiverId].photoUrl || null;
      } else if (msg.receiverId) {
        console.log(`⚠️ [MARKETPLACE] No se encontró info para receiver: ${msg.receiverId}`);
        enrichedMsg.receiverName = enrichedMsg.receiverName || 'Usuario';
        enrichedMsg.receiverPhoto = null;
      }

      return enrichedMsg;
    });

    console.log(`✅ [MARKETPLACE] ${messages.length} mensajes enriquecidos para producto ${productId}`);

    res.json({
      success: true,
      data: messages
    });

  } catch (error) {
    console.error('❌ [MARKETPLACE] Error obteniendo mensajes del producto:', error);
    res.status(500).json({
      success: false,
      message: 'Error obteniendo mensajes',
      error: error.message
    });
  }
});

// Enviar mensaje
app.post('/api/marketplace/messages', authenticateToken, async (req, res) => {
  try {
    const { uid } = req.user;
    const { productId, message } = req.body;

    if (!productId || !message || message.trim().length === 0) {
      return res.status(400).json({
        success: false,
        message: 'Producto y mensaje son requeridos'
      });
    }

    if (message.trim().length > 500) {
      return res.status(400).json({
        success: false,
        message: 'El mensaje no puede exceder 500 caracteres'
      });
    }

    if (!db) {
      return res.status(500).json({
        success: false,
        message: 'Base de datos no disponible'
      });
    }

    // Obtener info del producto y del sender
    const productDoc = await db.collection('marketplace_products').doc(productId).get();
    if (!productDoc.exists) {
      return res.status(404).json({
        success: false,
        message: 'Producto no encontrado'
      });
    }

    const productData = productDoc.data();
    const userDoc = await db.collection('users').doc(uid).get();
    
    if (!userDoc.exists) {
      console.log(`⚠️ [MARKETPLACE] Usuario ${uid} no encontrado en Firestore`);
    }
    
    const userData = userDoc.exists ? userDoc.data() : {};
    
    console.log(`🔍 [MARKETPLACE] Datos del sender (${uid}):`);
    console.log(`   - Existe en Firestore: ${userDoc.exists}`);
    console.log(`   - displayName: ${userData.displayName || 'NO TIENE'}`);
    console.log(`   - name: ${userData.name || 'NO TIENE'}`);
    console.log(`   - Foto: ${userData.photoUrl || 'NO TIENE'}`);
    console.log(`   - Es dueño del producto: ${uid === productData.userId}`);

    // Determinar quién es el receptor del mensaje
    let receiverId;
    
    // Si el que envía es el dueño del producto, buscar al otro usuario en los mensajes previos
    if (uid === productData.userId) {
      console.log(`📨 [MARKETPLACE] El sender es el dueño del producto, buscando al otro usuario...`);
      
      // Buscar mensajes previos de este producto donde el sender NO sea el dueño
      const previousMessagesSnapshot = await db.collection('marketplace_messages')
        .where('productId', '==', productId)
        .where('senderId', '!=', uid)
        .orderBy('senderId')
        .orderBy('createdAt', 'desc')
        .limit(1)
        .get();
      
      if (!previousMessagesSnapshot.empty) {
        receiverId = previousMessagesSnapshot.docs[0].data().senderId;
        console.log(`✅ [MARKETPLACE] Receiver encontrado: ${receiverId}`);
      } else {
        // Si no hay mensajes previos, puede ser que el dueño esté iniciando la conversación
        // (caso raro, pero posible). En este caso, no hay a quién enviar notificación.
        console.log(`⚠️ [MARKETPLACE] El dueño está enviando el primer mensaje, no hay receptor conocido`);
        return res.status(400).json({
          success: false,
          message: 'No se puede iniciar una conversación como dueño del producto'
        });
      }
    } else {
      // Si el que envía NO es el dueño, el receptor es el dueño del producto
      receiverId = productData.userId;
      console.log(`✅ [MARKETPLACE] El receiver es el dueño del producto: ${receiverId}`);
    }

    // Obtener información del receiver
    const receiverDoc = await db.collection('users').doc(receiverId).get();
    const receiverData = receiverDoc.exists ? receiverDoc.data() : {};
    
    console.log(`🔍 [MARKETPLACE] Datos del receiver (${receiverId}):`);
    console.log(`   - Existe en Firestore: ${receiverDoc.exists}`);
    console.log(`   - displayName: ${receiverData.displayName || 'NO TIENE'}`);
    console.log(`   - name: ${receiverData.name || 'NO TIENE'}`);
    console.log(`   - Foto: ${receiverData.photoUrl || 'NO TIENE'}`);

    // Crear mensaje - usar displayName o name (consistente con el resto del código)
    const messageData = {
      productId,
      senderId: uid,
      senderName: userData?.displayName || userData?.name || 'Usuario',
      senderPhoto: userData?.photoUrl || null,
      receiverId: receiverId,
      receiverName: receiverData?.displayName || receiverData?.name || productData.userName || 'Usuario',
      receiverPhoto: receiverData?.photoUrl || null,
      message: message.trim(),
      isRead: false,
      createdAt: new Date()
    };
    
    console.log(`📝 [MARKETPLACE] Mensaje a guardar:`, {
      senderName: messageData.senderName,
      senderPhoto: messageData.senderPhoto ? 'Sí' : 'No',
      receiverName: messageData.receiverName,
      receiverPhoto: messageData.receiverPhoto ? 'Sí' : 'No'
    });

    const messageRef = await db.collection('marketplace_messages').add(messageData);

    // Incrementar contador de mensajes en el producto
    await db.collection('marketplace_products').doc(productId).update({
      messages: admin.firestore.FieldValue.increment(1)
    });

    console.log('✅ [MARKETPLACE] Mensaje enviado:', messageRef.id);

    // Enviar notificación push al destinatario
    try {
      // Verificar que el receiver no sea el mismo que el sender
      if (uid === receiverId) {
        console.log(`⚠️ [MARKETPLACE] No se envía notificación: sender y receiver son el mismo usuario (${uid})`);
      } else {
        const receiverTokens = receiverData?.fcmTokens || [];
        
        if (receiverTokens.length > 0) {
          console.log(`📤 [MARKETPLACE] Enviando notificación push a ${receiverId}`);
        
        const senderFullName = userData?.displayName || userData?.name || 'Usuario';
        
        const notification = {
          title: `💬 Nuevo mensaje de ${senderFullName}`,
          body: message.trim().length > 100 ? message.trim().substring(0, 100) + '...' : message.trim()
        };

        const notificationData = {
          type: 'new_message',
          senderId: uid,
          senderName: senderFullName,
          senderPhoto: userData?.photoUrl || null,
          productId: productId,
          productTitle: productData.title || 'Producto',
          screen: 'ChatScreen',
          chatId: `${productId}_${uid}_${receiverId}`
        };

        const pushResult = await sendPushNotification(receiverTokens, notification, notificationData);
        
        if (pushResult.success) {
          console.log(`✅ [MARKETPLACE] Notificación enviada: ${pushResult.successCount} exitosas, ${pushResult.failureCount} fallidas`);
        } else {
          console.log(`⚠️ [MARKETPLACE] No se pudo enviar notificación: ${pushResult.error || pushResult.message}`);
        }

        // Guardar notificación en Firestore
        await db.collection('notifications').add({
          userId: receiverId,
          type: 'new_message',
          title: notification.title,
          body: notification.body,
          data: notificationData,
          read: false,
          createdAt: admin.firestore.Timestamp.fromDate(new Date())
        });
        
        console.log('✅ [MARKETPLACE] Notificación guardada en Firestore');
        } else {
          console.log('⚠️ [MARKETPLACE] El destinatario no tiene tokens FCM registrados');
        }
      }
    } catch (notificationError) {
      console.error('❌ [MARKETPLACE] Error enviando notificación push:', notificationError);
      // No fallar el envío del mensaje si falla la notificación
    }

    res.json({
      success: true,
      message: 'Mensaje enviado exitosamente',
      data: {
        id: messageRef.id,
        ...messageData
      }
    });

  } catch (error) {
    console.error('❌ [MARKETPLACE] Error enviando mensaje:', error);
    res.status(500).json({
      success: false,
      message: 'Error enviando mensaje',
      error: error.message
    });
  }
});

// Marcar mensaje como leído
app.patch('/api/marketplace/messages/:id/read', authenticateToken, async (req, res) => {
  try {
    const { uid } = req.user;
    const { id } = req.params;

    if (!db) {
      return res.status(500).json({
        success: false,
        message: 'Base de datos no disponible'
      });
    }

    const messageDoc = await db.collection('marketplace_messages').doc(id).get();

    if (!messageDoc.exists) {
      return res.status(404).json({
        success: false,
        message: 'Mensaje no encontrado'
      });
    }

    // Solo el receptor puede marcar como leído
    if (messageDoc.data().receiverId !== uid) {
      return res.status(403).json({
        success: false,
        message: 'No tienes permisos para marcar este mensaje'
      });
    }

    await db.collection('marketplace_messages').doc(id).update({
      isRead: true
    });

    res.json({
      success: true,
      message: 'Mensaje marcado como leído'
    });

  } catch (error) {
    console.error('❌ [MARKETPLACE] Error marcando mensaje:', error);
    res.status(500).json({
      success: false,
      message: 'Error marcando mensaje',
      error: error.message
    });
  }
});

