// Obtener banners activos (público)
app.get('/api/banners', async (req, res) => {
  try {
    const { section } = req.query; // Filtrar por sección: home, marketplace, products, etc.

    if (!db) {
      return res.status(500).json({
        success: false,
        message: 'Base de datos no disponible'
      });
    }

    const now = new Date();

    // Obtener banners activos
    let query = db.collection('banners')
      .where('isActive', '==', true);

    // Filtrar por sección si se proporciona
    if (section) {
      query = query.where('section', '==', section);
    }

    query = query.orderBy('order', 'asc');

    const snapshot = await query.get();

    let banners = snapshot.docs.map(doc => ({
      id: doc.id,
      ...doc.data()
    }));

    // Filtrar por fechas de visibilidad
    banners = banners.filter(banner => {
      const startDate = banner.startDate?.toDate?.() || new Date(0);
      const endDate = banner.endDate?.toDate?.() || new Date('2099-12-31');
      return now >= startDate && now <= endDate;
    });

    console.log(`📰 [BANNERS] Banners activos${section ? ` para sección "${section}"` : ''}: ${banners.length}`);

    res.json({
      success: true,
      data: banners
    });

  } catch (error) {
    console.error('❌ [BANNERS] Error obteniendo banners:', error);
    res.status(500).json({
      success: false,
      message: 'Error obteniendo banners',
      error: error.message
    });
  }
});

