// Enviar notificaciones a través de Expo Push Notification Service
async function sendExpoNotifications(tokens, notification, data) {
  try {
    const messages = tokens.map(token => ({
      to: token,
      sound: 'default',
      title: notification.title || 'Munpa',
      body: notification.body || '',
      data: {
        ...data,
        timestamp: new Date().toISOString()
      },
      badge: 1,
      priority: 'high',
    }));

    console.log('📤 [EXPO] Enviando notificación a Expo Push Service:');
    console.log('   Título:', notification.title);
    console.log('   Cuerpo:', notification.body);
    console.log('   Total tokens:', tokens.length);
    console.log('   Primer mensaje:', JSON.stringify(messages[0], null, 2));

    const chunks = [];
    for (let i = 0; i < messages.length; i += 100) {
      chunks.push(messages.slice(i, i + 100));
    }

    let successCount = 0;
    let failureCount = 0;
    const failedTokens = [];

    for (const chunk of chunks) {
      const response = await fetch('https://exp.host/--/api/v2/push/send', {
        method: 'POST',
        headers: {
          'Accept': 'application/json',
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(chunk),
      });

      const result = await response.json();
      
      console.log('🔍 [EXPO] Respuesta completa de Expo:', JSON.stringify(result, null, 2));
      
      if (result.data) {
        result.data.forEach((item, index) => {
          if (item.status === 'ok') {
            successCount++;
            console.log(`✅ [EXPO] Notificación enviada exitosamente a: ${chunk[index].to.substring(0, 30)}...`);
          } else {
            failureCount++;
            failedTokens.push(chunk[index].to);
            console.log(`❌ [EXPO] Error enviando notificación:`);
            console.log(`   Token: ${chunk[index].to.substring(0, 30)}...`);
            console.log(`   Status: ${item.status}`);
            console.log(`   Message: ${item.message}`);
            console.log(`   Details: ${JSON.stringify(item.details || {})}`);
          }
        });
      } else {
        console.log('❌ [EXPO] Respuesta sin data:', JSON.stringify(result));
      }
    }

    console.log(`✅ [EXPO] Notificaciones Expo enviadas: ${successCount}/${tokens.length}`);

    return { successCount, failureCount, failedTokens };

  } catch (error) {
    console.error('❌ [EXPO] Error enviando notificaciones Expo:', error);
    return { successCount: 0, failureCount: tokens.length, failedTokens: tokens };
  }
}

// Enviar notificaciones a través de Firebase Cloud Messaging
async function sendFCMNotifications(tokens, notification, data) {
  try {
    const message = {
      notification: {
        title: notification.title || 'Munpa',
        body: notification.body || '',
        ...(notification.imageUrl && isValidUrl(notification.imageUrl) ? { imageUrl: notification.imageUrl } : {})
      },
      data: {
        ...data,
        click_action: data.click_action || 'FLUTTER_NOTIFICATION_CLICK',
        timestamp: new Date().toISOString()
      },
      tokens: tokens,
      android: {
        priority: 'high',
        notification: {
          sound: 'default',
          channelId: 'munpa_notifications'
        }
      },
      apns: {
        payload: {
          aps: {
            sound: 'default',
            badge: 1
          }
        }
      }
    };

    const response = await admin.messaging().sendEachForMulticast(message);
    
    console.log(`✅ [FCM] Notificaciones FCM enviadas: ${response.successCount}/${tokens.length}`);
    
    const failedTokens = [];
    const invalidTokenCodes = new Set([
      'messaging/registration-token-not-registered',
      'messaging/invalid-registration-token'
    ]);
    if (response.failureCount > 0) {
      response.responses.forEach((resp, idx) => {
        if (!resp.success) {
          const errorCode = resp.error?.code;
          if (invalidTokenCodes.has(errorCode)) {
            failedTokens.push(tokens[idx]);
            console.log(`❌ [FCM] Token inválido: ${errorCode}`);
          } else {
            console.log(`⚠️ [FCM] Error enviando token (${errorCode || 'unknown'})`);
          }
        }
      });
    }

    return {
      successCount: response.successCount,
      failureCount: response.failureCount,
      failedTokens
    };

  } catch (error) {
    console.error('❌ [FCM] Error enviando notificaciones FCM:', error);
    return { successCount: 0, failureCount: tokens.length, failedTokens: [] };
  }
}

// Limpiar tokens inválidos
async function cleanInvalidTokens(invalidTokens) {
  try {
    const usersRef = db.collection('users');
    const snapshot = await usersRef.where('fcmTokens', 'array-contains-any', invalidTokens.slice(0, 10)).get();
    
    const batch = db.batch();
    snapshot.docs.forEach(doc => {
      const userData = doc.data();
      const validTokens = userData.fcmTokens?.filter(token => !invalidTokens.includes(token)) || [];
      batch.update(doc.ref, { fcmTokens: validTokens });
    });
    
    await batch.commit();
    console.log(`🧹 [PUSH] Tokens inválidos limpiados: ${invalidTokens.length}`);
  } catch (error) {
    console.error('❌ [PUSH] Error limpiando tokens:', error);
  }
}

// Registrar/actualizar token FCM del dispositivo
app.post('/api/notifications/register-token', authenticateToken, async (req, res) => {
  try {
    const { token, platform } = req.body;
    const userId = req.user.uid;

    if (!token) {
      return res.status(400).json({
        success: false,
        message: 'Token FCM requerido'
      });
    }

    // Evitar guardar tokens APNS (64 hex) en lugar de FCM
    const looksLikeApnsToken = /^[a-f0-9]{64}$/i.test(token);
    if (looksLikeApnsToken) {
      return res.status(400).json({
        success: false,
        message: 'Token inválido. Se requiere token FCM, no APNS.'
      });
    }

    if (!db) {
      return res.status(500).json({
        success: false,
        message: 'Base de datos no disponible'
      });
    }

    const userRef = db.collection('users').doc(userId);
    const userDoc = await userRef.get();

    if (!userDoc.exists) {
      return res.status(404).json({
        success: false,
        message: 'Usuario no encontrado'
      });
    }

    const userData = userDoc.data();
    const currentTokens = userData.fcmTokens || [];

    // Agregar token si no existe
    if (!currentTokens.includes(token)) {
      await userRef.update({
        fcmTokens: admin.firestore.FieldValue.arrayUnion(token),
        lastTokenUpdate: admin.firestore.Timestamp.fromDate(new Date()),
        platform: platform || 'unknown'
      });
      console.log('✅ [PUSH] Token registrado para:', userId);
    } else {
      console.log('ℹ️ [PUSH] Token ya existe para:', userId);
    }

    res.json({
      success: true,
      message: 'Token registrado exitosamente'
    });

  } catch (error) {
    console.error('❌ [PUSH] Error registrando token:', error);
    res.status(500).json({
      success: false,
      message: 'Error registrando token',
      error: error.message
    });
  }
});

