// Obtener notificaciones del usuario
app.get('/api/notifications', authenticateToken, async (req, res) => {
  try {
    const userId = req.user.uid;
    const { page = 1, limit = 50, unreadOnly = false } = req.query;
    const cacheKey = `${req.path}?uid=${userId}&page=${page}&limit=${limit}&unreadOnly=${unreadOnly}`;
    const cached = getCachedResponse(cacheKey);
    if (cached) {
      res.set('Cache-Control', 'private, max-age=10');
      return res.json(cached);
    }

    if (!db) {
      return res.status(500).json({
        success: false,
        message: 'Base de datos no disponible'
      });
    }

    // Obtener todas las notificaciones del usuario
    const snapshot = await db.collection('notifications')
      .where('userId', '==', userId)
      .get();

    // Si está vacío, devolver array vacío
    if (snapshot.empty) {
      return res.json({
        success: true,
        data: [],
        pagination: {
          total: 0,
          page: parseInt(page),
          limit: parseInt(limit),
          totalPages: 0,
          unreadCount: 0
        }
      });
    }

    let notifications = snapshot.docs.map(doc => ({
      id: doc.id,
      ...doc.data(),
      createdAt: doc.data().createdAt?.toDate?.() || doc.data().createdAt
    }));

    // Filtrar solo no leídas si se especifica
    if (unreadOnly === 'true') {
      notifications = notifications.filter(n => !n.read);
    }

    // Ordenar por fecha de creación (más reciente primero)
    notifications.sort((a, b) => {
      const dateA = a.createdAt instanceof Date ? a.createdAt : new Date(a.createdAt || 0);
      const dateB = b.createdAt instanceof Date ? b.createdAt : new Date(b.createdAt || 0);
      return dateB - dateA;
    });

    // Calcular contador de no leídas antes de paginar
    const unreadCount = snapshot.docs.filter(doc => !doc.data().read).length;

    // Paginación
    const total = notifications.length;
    const startIndex = (page - 1) * limit;
    const endIndex = startIndex + parseInt(limit);
    const paginatedNotifications = notifications.slice(startIndex, endIndex);

    console.log(`✅ [NOTIFICATIONS] Notificaciones obtenidas para ${userId}: ${paginatedNotifications.length}`);

    const responsePayload = {
      success: true,
      data: paginatedNotifications,
      pagination: {
        total,
        page: parseInt(page),
        limit: parseInt(limit),
        totalPages: Math.ceil(total / limit),
        unreadCount
      }
    };

    setCachedResponse(cacheKey, responsePayload, 10 * 1000);
    res.set('Cache-Control', 'private, max-age=10');
    res.json(responsePayload);

  } catch (error) {
    console.error('❌ [NOTIFICATIONS] Error obteniendo notificaciones:', error);
    res.status(500).json({
      success: false,
      message: 'Error obteniendo notificaciones',
      error: error.message
    });
  }
});

