// Función para obtener recordatorio según edad
function getDailyReminder(ageInMonths, ageInDays) {
  const reminders = [];
  
  // Verificar vacunas próximas
  DAILY_REMINDERS.vaccines.forEach(vaccine => {
    const targetDays = vaccine.ageMonths * 30;
    const daysUntilVaccine = targetDays - ageInDays;
    
    if (daysUntilVaccine === vaccine.daysBefore) {
      reminders.push({
        type: 'vaccine',
        priority: 1,
        title: vaccine.title,
        message: vaccine.message
      });
    }
  });
  
  // Verificar hitos
  DAILY_REMINDERS.milestones.forEach(milestone => {
    if (milestone.ageMonths === ageInMonths && ageInDays % 30 === 0) {
      reminders.push({
        type: 'milestone',
        priority: 2,
        title: milestone.title,
        message: milestone.message
      });
    }
  });
  
  // Consejos según edad (rotar diariamente)
  const ageTips = DAILY_REMINDERS.tips[ageInMonths];
  if (ageTips) {
    const dayOfWeek = new Date().getDay(); // 0-6
    const tipIndex = dayOfWeek % ageTips.length;
    reminders.push({
      type: 'tip',
      priority: 3,
      title: ageTips[tipIndex].title,
      message: ageTips[tipIndex].message
    });
  }
  
  // Si no hay consejos específicos, usar del mes más cercano (extendido hasta 144 meses = 12 años)
  if (reminders.filter(r => r.type === 'tip').length === 0) {
    const availableAges = [0, 1, 2, 3, 4, 5, 6, 9, 12, 18, 24, 30, 36, 42, 48, 54, 60, 72, 84, 96, 108, 120, 132, 144];
    const nearestAge = availableAges.reduce((prev, curr) => {
      return Math.abs(curr - ageInMonths) < Math.abs(prev - ageInMonths) ? curr : prev;
    });
    const fallbackTips = DAILY_REMINDERS.tips[nearestAge] || DAILY_REMINDERS.tips[24];
    if (fallbackTips) {
      const dayOfWeek = new Date().getDay();
      const tipIndex = dayOfWeek % fallbackTips.length;
      reminders.push({
        type: 'tip',
        priority: 3,
        title: fallbackTips[tipIndex].title,
        message: fallbackTips[tipIndex].message
      });
    }
  }
  
  // GARANTIZAR que siempre haya un recordatorio para TODOS los hijos
  if (reminders.length === 0) {
    // Consejos genéricos por rango de edad
    const genericTips = [
      { title: '💝 Momento especial', message: 'Dedica unos minutos hoy para jugar y conectar con tu bebé. Los momentos de calidad fortalecen el vínculo.' },
      { title: '🌟 Tip del día', message: 'Habla con tu bebé durante las actividades diarias. Esto estimula su desarrollo del lenguaje.' },
      { title: '🎈 Diversión en familia', message: 'Los juegos simples como esconderse y aparecer son excelentes para el desarrollo cognitivo.' },
      { title: '📚 Lectura diaria', message: 'Leer cuentos juntos, aunque sea por pocos minutos, beneficia enormemente su desarrollo.' },
      { title: '🤗 Conexión emocional', message: 'Los abrazos y el contacto físico son fundamentales para el bienestar emocional de tu pequeño.' },
      { title: '🎵 Música y movimiento', message: 'Cantar y bailar juntos estimula múltiples áreas del desarrollo de tu hijo.' },
      { title: '🌈 Exploración', message: 'Permite que tu hijo explore de forma segura. La curiosidad es el motor del aprendizaje.' }
    ];
    
    const dayOfWeek = new Date().getDay();
    const tipIndex = dayOfWeek % genericTips.length;
    
    reminders.push({
      type: 'tip',
      priority: 3,
      title: genericTips[tipIndex].title,
      message: genericTips[tipIndex].message
    });
  }
  
  // Ordenar por prioridad (vacunas primero)
  return reminders.sort((a, b) => a.priority - b.priority)[0];
}

const getUpcomingScheduledVaccineReminder = async (childId, childName) => {
  if (!db) return null;
  const now = new Date();
  const targetDate = new Date(now);
  targetDate.setDate(targetDate.getDate() + 7);
  const startOfDay = new Date(targetDate);
  startOfDay.setHours(0, 0, 0, 0);
  const endOfDay = new Date(targetDate);
  endOfDay.setHours(23, 59, 59, 999);

  const snapshot = await db.collection('children').doc(childId)
    .collection('vaccines')
    .where('scheduledDate', '>=', startOfDay)
    .where('scheduledDate', '<=', endOfDay)
    .orderBy('scheduledDate', 'asc')
    .limit(1)
    .get();

  if (snapshot.empty) return null;
  const vaccineDoc = snapshot.docs[0].data();
  if (vaccineDoc.status === 'applied') return null;
  const name = vaccineDoc.name || 'vacuna';
  const childLabel = childName || 'tu bebé';
  return {
    type: 'vaccine',
    priority: 1,
    title: '💉 Vacuna próxima',
    message: `En una semana ${childLabel} tiene la vacuna ${name}.`
  };
};

// Middleware especial para cron jobs: acepta JWT admin o CRON_SECRET
const authenticateCron = (req, res, next) => {
  console.log('🔍 [CRON] Headers recibidos:', Object.keys(req.headers));
  
  // Opción 1: x-cron-secret header (para servicios externos como cron-job.org)
  const cronSecretHeader = req.headers['x-cron-secret'];
  if (cronSecretHeader && cronSecretHeader === process.env.CRON_SECRET) {
    console.log('✅ [CRON] Autenticado con x-cron-secret');
    req.user = { uid: 'cron-job', isAdmin: true };
    return next();
  }

  // Opción 2: Authorization Bearer (para Vercel Cron Jobs)
  const authHeader = req.headers.authorization;
  if (authHeader) {
    const parts = authHeader.split(' ');
    if (parts.length === 2 && parts[0] === 'Bearer') {
      const token = parts[1];
      
      // Verificar si es el CRON_SECRET
      if (token === process.env.CRON_SECRET) {
        console.log('✅ [CRON] Autenticado con Authorization Bearer (CRON_SECRET)');
        req.user = { uid: 'cron-job', isAdmin: true };
        return next();
      }
      
      // Si no es CRON_SECRET, intentar como JWT de admin
      try {
        const decoded = jwt.verify(token, JWT_SECRET);
        req.user = decoded;
        
        // Verificar que es admin
        if (!req.user.isAdmin) {
          return res.status(403).json({
            success: false,
            message: 'Acceso denegado. Se requieren permisos de administrador'
          });
        }
        
        console.log('✅ [CRON] Autenticado con JWT admin');
        return next();
      } catch (error) {
        // No es un JWT válido, continuar con error
      }
    }
  }

  // Si llegamos aquí, no hay autenticación válida
  return res.status(401).json({
    success: false,
    message: 'No autorizado. Requiere CRON_SECRET header o token de admin'
  });
};

// Endpoint para enviar notificaciones diarias (llamado por cron job)
// Vercel Cron Jobs usan GET por defecto
app.get('/api/notifications/daily-reminders', authenticateCron, async (req, res) => {
  try {
    if (!db) {
      return res.status(500).json({
        success: false,
        message: 'Base de datos no disponible'
      });
    }

    console.log('📅 [DAILY] Iniciando envío de recordatorios diarios...');
    
    let notificationsSent = 0;
    let errors = 0;
    const results = [];
    let usersWithoutTokens = 0;
    let usersWithoutChildren = 0;
    let childrenTooOld = 0;
    let noReminderForAge = 0;

    // Obtener todos los usuarios
    const usersSnapshot = await db.collection('users').get();
    console.log(`👥 [DAILY] Total usuarios en BD: ${usersSnapshot.docs.length}`);

    for (const userDoc of usersSnapshot.docs) {
      try {
        const userData = userDoc.data();
        const userId = userDoc.id;

        // Saltar si no tiene tokens FCM
        if (!userData.fcmTokens || userData.fcmTokens.length === 0) {
          usersWithoutTokens++;
          continue;
        }

        // Obtener hijos del usuario (como padre principal)
        const childrenSnapshot = await db.collection('children')
          .where('parentId', '==', userId)
          .get();

        // También obtener hijos compartidos con el usuario
        const sharedChildrenSnapshot = await db.collection('children')
          .where('sharedWith', 'array-contains', userId)
          .get();

        const allChildren = [...childrenSnapshot.docs, ...sharedChildrenSnapshot.docs];

        if (allChildren.length === 0) {
          usersWithoutChildren++;
          continue; // Usuario sin hijos asignados
        }

        console.log(`👶 [DAILY] Usuario ${userId} tiene ${allChildren.length} hijo(s) total(es)`);

        // Recopilar TODOS los hijos elegibles (< 24 meses) con sus recordatorios
        const eligibleChildren = [];

        for (const childDoc of allChildren) {
          const childData = childDoc.data();
          
          // Calcular edad actual
          if (childData.birthDate) {
            const birthDate = childData.birthDate.toDate?.() || new Date(childData.birthDate);
            const now = new Date();
            const ageInDays = Math.floor((now - birthDate) / (1000 * 60 * 60 * 24));
            const ageInMonths = Math.floor(ageInDays / 30);

            console.log(`   👶 Hijo: ${childData.name}, ${ageInMonths} meses, ${ageInDays} días`);

            // Priorizar vacuna programada 1 semana antes
            let fallbackReminder = null;
            try {
              fallbackReminder = await getUpcomingScheduledVaccineReminder(childDoc.id, childData.name);
            } catch (error) {
              console.warn('⚠️ [DAILY] Error buscando vacuna programada:', error.message);
            }
            if (!fallbackReminder) {
              // Obtener recordatorio sin límite de edad
              fallbackReminder = getDailyReminder(ageInMonths, ageInDays);
            }
            
            if (fallbackReminder) {
              console.log(`   ✅ Tiene recordatorio: ${fallbackReminder.title}`);
              eligibleChildren.push({
                ...childData,
                id: childDoc.id,
                ageInMonths,
                ageInDays,
                fallbackReminder
              });
            } else {
              console.log(`   ⏭️ No hay recordatorio para ${childData.name} (${ageInMonths} meses, ${ageInDays} días)`);
              noReminderForAge++;
            }
          } else {
            console.log(`   ⚠️ ${childData.name} no tiene birthDate`);
          }
        }

        console.log(`   📊 Hijos elegibles para ${userId}: ${eligibleChildren.length}/${allChildren.length}`);

        if (eligibleChildren.length === 0) {
          if (allChildren.length > 0) {
            childrenTooOld++;
          }
          continue; // No hay hijos elegibles
        }

        // Generar mensajes para cada hijo
        const childReminders = [];
        for (const child of eligibleChildren) {
          const gptReminder = await generatePersonalizedReminder(
            child,
            child.fallbackReminder.type,
            child.ageInMonths,
            child.ageInDays
          );

          const reminder = gptReminder || child.fallbackReminder;
          let message = reminder.message || child.fallbackReminder.message;
          const childName = child.name || 'tu bebé';
          message = message.replace(/tu bebé|el bebé/gi, childName);

          childReminders.push({
            child,
            reminder,
            message,
            childName
          });
        }

        // Crear título y mensaje combinado
        let title, message;
        if (eligibleChildren.length === 1) {
          // Un solo hijo: mensaje personalizado
          const { child, reminder, message: childMessage, childName } = childReminders[0];
          
          if (childName !== 'tu bebé') {
            if (child.fallbackReminder.type === 'tip') {
              title = `👶 Consejo para ${childName}`;
            } else if (child.fallbackReminder.type === 'milestone') {
              // Formatear edad en título de milestone
              let ageText;
              if (child.ageInMonths < 24) {
                ageText = `${child.ageInMonths} meses`;
              } else {
                const years = Math.floor(child.ageInMonths / 12);
                const remainingMonths = child.ageInMonths % 12;
                if (remainingMonths === 0) {
                  ageText = `${years} ${years === 1 ? 'año' : 'años'}`;
                } else {
                  ageText = `${years} ${years === 1 ? 'año' : 'años'} y ${remainingMonths} meses`;
                }
              }
              title = `🎉 ¡${childName} cumple ${ageText}!`;
            } else {
              title = reminder.title || child.fallbackReminder.title;
            }
          } else {
            title = reminder.title || child.fallbackReminder.title;
          }
          
          message = childMessage;
        } else {
          // Múltiples hijos: combinar en un mensaje
          const childNames = childReminders.map(r => r.childName).join(' y ');
          title = `👶 Consejos para ${childNames}`;
          
          // Combinar mensajes
          const messages = childReminders.map((r, idx) => {
            // Formatear edad: < 24 meses en meses, >= 24 meses en años
            let ageDisplay;
            if (r.child.ageInMonths < 24) {
              ageDisplay = `${r.child.ageInMonths}m`;
            } else {
              const years = Math.floor(r.child.ageInMonths / 12);
              const remainingMonths = r.child.ageInMonths % 12;
              if (remainingMonths === 0) {
                ageDisplay = `${years}a`;
              } else if (remainingMonths === 6) {
                ageDisplay = `${years}.5a`;
              } else {
                ageDisplay = `${years}a ${remainingMonths}m`;
              }
            }
            return `${r.childName} (${ageDisplay}): ${r.message}`;
          });
          message = messages.join('\n\n');
        }

        // Enviar push notification
        await sendPushNotification(
          userData.fcmTokens,
          {
            title: title,
            body: message
          },
          {
            type: 'daily_reminder',
            childrenIds: eligibleChildren.map(c => c.id),
            childrenNames: eligibleChildren.map(c => c.name).join(', ')
          }
        );

        // Guardar notificación en Firestore
        await db.collection('notifications').add({
          userId: userId,
          type: 'daily_reminder',
          title: title,
          body: message, // Campo body para consistencia con otras notificaciones
          message: message, // Mantener message para compatibilidad
          data: {
            childrenIds: eligibleChildren.map(c => c.id),
            childrenNames: eligibleChildren.map(c => c.name).join(', '),
            childrenCount: eligibleChildren.length
          },
          read: false,
          createdAt: new Date()
        });

        // Guardar log detallado para cada hijo en el dashboard
        for (const childReminderData of childReminders) {
          await db.collection('reminders_history').add({
            userId: userId,
            userName: userData.displayName || userData.name || 'Usuario',
            childId: childReminderData.child.id,
            childName: childReminderData.childName,
            childAge: childReminderData.child.ageInMonths,
            childAgeDays: childReminderData.child.ageInDays,
            reminderType: childReminderData.child.fallbackReminder.type,
            title: eligibleChildren.length === 1 ? title : `👶 Consejo para ${childReminderData.childName}`,
            message: childReminderData.message,
            generatedBy: childReminderData.reminder.generatedBy || 'fallback',
            model: childReminderData.reminder.model || null,
            prompt: childReminderData.reminder.prompt || null,
            sent: true,
            sentAt: new Date(),
            createdAt: new Date()
          });
        }

        notificationsSent++;
        
        const childrenNames = eligibleChildren.map(c => c.name).join(', ');
        results.push({
          userId,
          childrenNames: childrenNames,
          childrenCount: eligibleChildren.length,
          title: title,
          generatedBy: childReminders[0]?.reminder?.generatedBy || 'fallback'
        });

        console.log(`✅ [DAILY] Notificación enviada a ${userId} para ${eligibleChildren.length} hijo(s): ${childrenNames}`);

      } catch (userError) {
        errors++;
        console.error(`❌ [DAILY] Error procesando usuario ${userDoc.id}:`, userError.message);
      }
    }

    console.log(`📊 [DAILY] Completado: ${notificationsSent} enviadas, ${errors} errores`);
    console.log(`📊 [DAILY] Estadísticas:`);
    console.log(`   👥 Total usuarios en BD: ${usersSnapshot.docs.length}`);
    console.log(`   ❌ Sin tokens FCM: ${usersWithoutTokens}`);
    console.log(`   ❌ Sin hijos: ${usersWithoutChildren}`);
    console.log(`   ❌ Hijos > 24 meses: ${childrenTooOld}`);
    console.log(`   ❌ Sin recordatorio para edad: ${noReminderForAge}`);
    console.log(`   ✅ Notificaciones enviadas: ${notificationsSent}`);

    res.json({
      success: true,
      message: 'Recordatorios diarios enviados',
      data: {
        notificationsSent,
        errors,
        results: results.slice(0, 10), // Primeros 10 para muestra
        stats: {
          totalUsers: usersSnapshot.docs.length,
          usersWithoutTokens,
          usersWithoutChildren,
          childrenTooOld,
          noReminderForAge
        }
      }
    });

  } catch (error) {
    console.error('❌ [DAILY] Error en recordatorios diarios:', error);
    res.status(500).json({
      success: false,
      message: 'Error enviando recordatorios diarios',
      error: error.message
    });
  }
});

// ============================================================================
// 📅 RECORDATORIOS SEMANALES ALEATORIOS
// ============================================================================

// Endpoint para enviar notificaciones semanales en horarios aleatorios
// Se ejecuta cada hora entre 9am-7pm, pero solo envía 1 vez por semana
app.get('/api/notifications/weekly-reminders', authenticateCron, async (req, res) => {
  try {
    if (!db) {
      return res.status(500).json({
        success: false,
        message: 'Base de datos no disponible'
      });
    }

    console.log('📅 [WEEKLY] Verificando si enviar recordatorios semanales...');

    // Obtener configuración de envío semanal
    const configRef = db.collection('config').doc('weekly_reminders');
    const configDoc = await configRef.get();
    const configData = configDoc.exists ? configDoc.data() : {};

    // Verificar si ya se envió esta semana
    const now = new Date();
    const startOfWeek = new Date(now);
    startOfWeek.setDate(now.getDate() - now.getDay()); // Domingo de esta semana
    startOfWeek.setHours(0, 0, 0, 0);

    if (configData.lastSentAt) {
      const lastSent = configData.lastSentAt.toDate();
      if (lastSent >= startOfWeek) {
        console.log(`⏭️ [WEEKLY] Ya se enviaron notificaciones esta semana (${lastSent.toLocaleString()})`);
        return res.json({
          success: true,
          message: 'Ya se enviaron notificaciones esta semana',
          data: {
            lastSentAt: lastSent,
            nextAvailableAt: new Date(startOfWeek.getTime() + 7 * 24 * 60 * 60 * 1000)
          }
        });
      }
    }

    // Probabilidad aleatoria de envío (15% cada hora = ~100% de probabilidad en el día)
    const randomChance = Math.random();
    const sendProbability = 0.15; // 15%

    if (randomChance > sendProbability) {
      console.log(`🎲 [WEEKLY] Probabilidad no cumplida (${(randomChance * 100).toFixed(1)}% > ${(sendProbability * 100)}%). Esperando próxima ejecución...`);
      return res.json({
        success: true,
        message: 'Esperando momento aleatorio para enviar',
        data: {
          randomValue: randomChance,
          threshold: sendProbability,
          willSend: false
        }
      });
    }

    console.log(`🎲 [WEEKLY] ¡Momento de enviar! (${(randomChance * 100).toFixed(1)}% <= ${(sendProbability * 100)}%)`);

    // ===== LÓGICA DE ENVÍO (misma que daily-reminders) =====
    
    let notificationsSent = 0;
    let errors = 0;
    const results = [];
    let usersWithoutTokens = 0;
    let usersWithoutChildren = 0;
    let childrenTooOld = 0;
    let noReminderForAge = 0;

    // Obtener todos los usuarios
    const usersSnapshot = await db.collection('users').get();
    console.log(`👥 [WEEKLY] Total usuarios en BD: ${usersSnapshot.docs.length}`);

    for (const userDoc of usersSnapshot.docs) {
      try {
        const userData = userDoc.data();
        const userId = userDoc.id;

        // Saltar si no tiene tokens FCM
        if (!userData.fcmTokens || userData.fcmTokens.length === 0) {
          usersWithoutTokens++;
          continue;
        }

        // Obtener hijos del usuario (como padre principal)
        const childrenSnapshot = await db.collection('children')
          .where('parentId', '==', userId)
          .get();

        // También obtener hijos compartidos con el usuario
        const sharedChildrenSnapshot = await db.collection('children')
          .where('sharedWith', 'array-contains', userId)
          .get();

        const allChildren = [...childrenSnapshot.docs, ...sharedChildrenSnapshot.docs];

        if (allChildren.length === 0) {
          usersWithoutChildren++;
          continue;
        }

        console.log(`👶 [WEEKLY] Usuario ${userId} tiene ${allChildren.length} hijo(s) total(es)`);

        // Recopilar TODOS los hijos elegibles con sus recordatorios
        const eligibleChildren = [];

        for (const childDoc of allChildren) {
          const childData = childDoc.data();
          
          // Calcular edad actual
          if (childData.birthDate) {
            const birthDate = childData.birthDate.toDate?.() || new Date(childData.birthDate);
            const now = new Date();
            const ageInDays = Math.floor((now - birthDate) / (1000 * 60 * 60 * 24));
            const ageInMonths = Math.floor(ageInDays / 30);

            console.log(`   👶 Hijo: ${childData.name}, ${ageInMonths} meses, ${ageInDays} días`);

            // Priorizar vacuna programada 1 semana antes
            let fallbackReminder = null;
            try {
              fallbackReminder = await getUpcomingScheduledVaccineReminder(childDoc.id, childData.name);
            } catch (error) {
              console.warn('⚠️ [WEEKLY] Error buscando vacuna programada:', error.message);
            }
            if (!fallbackReminder) {
              // Obtener recordatorio
              fallbackReminder = getDailyReminder(ageInMonths, ageInDays);
            }
            
            if (fallbackReminder) {
              console.log(`   ✅ Tiene recordatorio: ${fallbackReminder.title}`);
              eligibleChildren.push({
                ...childData,
                id: childDoc.id,
                ageInMonths,
                ageInDays,
                fallbackReminder
              });
            } else {
              console.log(`   ⏭️ No hay recordatorio para ${childData.name} (${ageInMonths} meses, ${ageInDays} días)`);
              noReminderForAge++;
            }
          } else {
            console.log(`   ⚠️ ${childData.name} no tiene birthDate`);
          }
        }

        console.log(`   📊 Hijos elegibles para ${userId}: ${eligibleChildren.length}/${allChildren.length}`);

        if (eligibleChildren.length === 0) {
          if (allChildren.length > 0) {
            childrenTooOld++;
          }
          continue;
        }

        // Generar mensajes para cada hijo
        const childReminders = [];
        for (const child of eligibleChildren) {
          const gptReminder = await generatePersonalizedReminder(
            child,
            child.fallbackReminder.type,
            child.ageInMonths,
            child.ageInDays
          );

          const reminder = gptReminder || child.fallbackReminder;
          let message = reminder.message || child.fallbackReminder.message;
          const childName = child.name || 'tu bebé';
          message = message.replace(/tu bebé|el bebé/gi, childName);

          childReminders.push({
            child,
            reminder,
            message,
            childName
          });
        }

        // Crear título y mensaje combinado
        let title, message;
        if (eligibleChildren.length === 1) {
          const { child, reminder, message: childMessage, childName } = childReminders[0];
          
          if (childName !== 'tu bebé') {
            if (child.fallbackReminder.type === 'tip') {
              title = `👶 Consejo para ${childName}`;
            } else if (child.fallbackReminder.type === 'milestone') {
              let ageText;
              if (child.ageInMonths < 24) {
                ageText = `${child.ageInMonths} meses`;
              } else {
                const years = Math.floor(child.ageInMonths / 12);
                const remainingMonths = child.ageInMonths % 12;
                if (remainingMonths === 0) {
                  ageText = `${years} ${years === 1 ? 'año' : 'años'}`;
                } else {
                  ageText = `${years} ${years === 1 ? 'año' : 'años'} y ${remainingMonths} meses`;
                }
              }
              title = `🎉 ¡${childName} cumple ${ageText}!`;
            } else {
              title = reminder.title || child.fallbackReminder.title;
            }
          } else {
            title = reminder.title || child.fallbackReminder.title;
          }
          
          message = childMessage;
        } else {
          const childNames = childReminders.map(r => r.childName).join(' y ');
          title = `👶 Consejos para ${childNames}`;
          
          const messages = childReminders.map((r, idx) => {
            let ageDisplay;
            if (r.child.ageInMonths < 24) {
              ageDisplay = `${r.child.ageInMonths}m`;
            } else {
              const years = Math.floor(r.child.ageInMonths / 12);
              const remainingMonths = r.child.ageInMonths % 12;
              if (remainingMonths === 0) {
                ageDisplay = `${years}a`;
              } else if (remainingMonths === 6) {
                ageDisplay = `${years}.5a`;
              } else {
                ageDisplay = `${years}a ${remainingMonths}m`;
              }
            }
            return `${r.childName} (${ageDisplay}): ${r.message}`;
          });
          message = messages.join('\n\n');
        }

        // Enviar push notification
        await sendPushNotification(
          userData.fcmTokens,
          {
            title: title,
            body: message
          },
          {
            type: 'weekly_reminder',
            childrenIds: eligibleChildren.map(c => c.id),
            childrenNames: eligibleChildren.map(c => c.name).join(', ')
          }
        );

        // Guardar notificación en Firestore
        await db.collection('notifications').add({
          userId: userId,
          type: 'weekly_reminder',
          title: title,
          body: message,
          message: message,
          data: {
            childrenIds: eligibleChildren.map(c => c.id),
            childrenNames: eligibleChildren.map(c => c.name).join(', '),
            childrenCount: eligibleChildren.length
          },
          read: false,
          createdAt: new Date()
        });

        // Guardar log detallado para cada hijo en el dashboard
        for (const childReminderData of childReminders) {
          await db.collection('reminders_history').add({
            userId: userId,
            userName: userData.displayName || userData.name || 'Usuario',
            childId: childReminderData.child.id,
            childName: childReminderData.childName,
            childAge: childReminderData.child.ageInMonths,
            childAgeDays: childReminderData.child.ageInDays,
            reminderType: childReminderData.child.fallbackReminder.type,
            title: eligibleChildren.length === 1 ? title : `👶 Consejo para ${childReminderData.childName}`,
            message: childReminderData.message,
            generatedBy: childReminderData.reminder.generatedBy || 'fallback',
            model: childReminderData.reminder.model || null,
            prompt: childReminderData.reminder.prompt || null,
            sent: true,
            sentAt: new Date(),
            sentType: 'weekly_random',
            createdAt: new Date()
          });
        }

        notificationsSent++;
        
        const childrenNames = eligibleChildren.map(c => c.name).join(', ');
        results.push({
          userId,
          childrenNames: childrenNames,
          childrenCount: eligibleChildren.length,
          title: title,
          generatedBy: childReminders[0]?.reminder?.generatedBy || 'fallback'
        });

        console.log(`✅ [WEEKLY] Notificación enviada a ${userId} para ${eligibleChildren.length} hijo(s): ${childrenNames}`);

      } catch (userError) {
        errors++;
        console.error(`❌ [WEEKLY] Error procesando usuario ${userDoc.id}:`, userError.message);
      }
    }

    // Registrar que ya se envió esta semana
    await configRef.set({
      lastSentAt: now,
      lastSentHour: now.getHours(),
      notificationsSent,
      errors
    }, { merge: true });

    console.log(`📊 [WEEKLY] Completado: ${notificationsSent} enviadas, ${errors} errores`);
    console.log(`📊 [WEEKLY] Horario: ${now.toLocaleString()}`);
    console.log(`📊 [WEEKLY] Estadísticas:`);
    console.log(`   👥 Total usuarios en BD: ${usersSnapshot.docs.length}`);
    console.log(`   ❌ Sin tokens FCM: ${usersWithoutTokens}`);
    console.log(`   ❌ Sin hijos: ${usersWithoutChildren}`);
    console.log(`   ❌ Hijos > 24 meses: ${childrenTooOld}`);
    console.log(`   ❌ Sin recordatorio para edad: ${noReminderForAge}`);
    console.log(`   ✅ Notificaciones enviadas: ${notificationsSent}`);

    res.json({
      success: true,
      message: 'Recordatorios semanales enviados',
      data: {
        sentAt: now,
        sentHour: now.getHours(),
        notificationsSent,
        errors,
        results: results.slice(0, 10),
        stats: {
          totalUsers: usersSnapshot.docs.length,
          usersWithoutTokens,
          usersWithoutChildren,
          childrenTooOld,
          noReminderForAge
        }
      }
    });

  } catch (error) {
    console.error('❌ [WEEKLY] Error en recordatorios semanales:', error);
    res.status(500).json({
      success: false,
      message: 'Error enviando recordatorios semanales',
      error: error.message
    });
  }
});

// Endpoint para probar recordatorio de un usuario específico
app.post('/api/notifications/test-daily-reminder', authenticateToken, async (req, res) => {
  try {
    const { uid } = req.user;

    if (!db) {
      return res.status(500).json({
        success: false,
        message: 'Base de datos no disponible'
      });
    }

    const userDoc = await db.collection('users').doc(uid).get();
    if (!userDoc.exists) {
      return res.status(404).json({
        success: false,
        message: 'Usuario no encontrado'
      });
    }

    const userData = userDoc.data();

    // Obtener hijos
    const childrenSnapshot = await db.collection('children')
      .where('parentId', '==', uid)
      .get();

    const sharedChildrenSnapshot = await db.collection('children')
      .where('sharedWith', 'array-contains', uid)
      .get();

    const allChildren = [...childrenSnapshot.docs, ...sharedChildrenSnapshot.docs];

    if (allChildren.length === 0) {
      return res.status(404).json({
        success: false,
        message: 'No tienes hijos registrados'
      });
    }

    // Buscar hijo más pequeño
    let youngestChild = null;
    let youngestAge = 999;

    for (const childDoc of allChildren) {
      const childData = childDoc.data();
      
      if (childData.birthDate) {
        const birthDate = childData.birthDate.toDate?.() || new Date(childData.birthDate);
        const now = new Date();
        const ageInDays = Math.floor((now - birthDate) / (1000 * 60 * 60 * 24));
        const ageInMonths = Math.floor(ageInDays / 30);

        if (ageInMonths < youngestAge && ageInMonths <= 24) {
          youngestAge = ageInMonths;
          youngestChild = {
            ...childData,
            id: childDoc.id,
            ageInMonths,
            ageInDays
          };
        }
      }
    }

    if (!youngestChild) {
      return res.status(404).json({
        success: false,
        message: 'No se pudo calcular la edad de los hijos'
      });
    }

    // Priorizar vacuna programada 1 semana antes
    let reminder = null;
    try {
      reminder = await getUpcomingScheduledVaccineReminder(youngestChild.id, youngestChild.name);
    } catch (error) {
      console.warn('⚠️ [TEST] Error buscando vacuna programada:', error.message);
    }
    if (!reminder) {
      // Obtener recordatorio
      reminder = getDailyReminder(youngestChild.ageInMonths, youngestChild.ageInDays);
    }

    if (!reminder) {
      return res.json({
        success: true,
        message: 'No hay recordatorio disponible para hoy',
        data: {
          childName: youngestChild.name,
          ageMonths: youngestChild.ageInMonths,
          ageDays: youngestChild.ageInDays
        }
      });
    }

    const personalizedMessage = reminder.message.replace('tu bebé', youngestChild.name || 'tu bebé');

    // Enviar push si tiene tokens
    if (userData.fcmTokens && userData.fcmTokens.length > 0) {
      await sendPushNotification(
        userData.fcmTokens,
        {
          title: `🧪 Test: ${reminder.title}`,
          body: personalizedMessage
        },
        {
          type: 'daily_reminder',
          reminderType: reminder.type,
          childId: youngestChild.id,
          test: true
        }
      );
    }

    res.json({
      success: true,
      message: 'Recordatorio de prueba enviado',
      data: {
        childName: youngestChild.name,
        ageMonths: youngestChild.ageInMonths,
        ageDays: youngestChild.ageInDays,
        reminder: {
          type: reminder.type,
          title: reminder.title,
          message: personalizedMessage
        }
      }
    });

  } catch (error) {
    console.error('❌ [DAILY] Error en test:', error);
    res.status(500).json({
      success: false,
      message: 'Error en recordatorio de prueba',
      error: error.message
    });
  }
});

// Endpoint para probar push de receta (envía ahora, sin validar hora)
app.post('/api/notifications/test-recipe-reminder', authenticateToken, async (req, res) => {
  try {
    const { uid } = req.user;
    const { childId, regenerate = false } = req.body;

    if (!db || !openai) {
      return res.status(503).json({
        success: false,
        message: 'Servicio no disponible'
      });
    }

    const userDoc = await db.collection('users').doc(uid).get();
    if (!userDoc.exists) {
      return res.status(404).json({ success: false, message: 'Usuario no encontrado' });
    }
    const userData = userDoc.data();
    if (!userData.fcmTokens || userData.fcmTokens.length === 0) {
      return res.status(400).json({
        success: false,
        message: 'No tienes tokens FCM. Abre la app en tu dispositivo para registrar notificaciones.'
      });
    }

    const childrenSnapshot = await db.collection('children').where('parentId', '==', uid).get();
    const sharedSnapshot = await db.collection('children').where('sharedWith', 'array-contains', uid).get();
    const allChildren = [...childrenSnapshot.docs, ...sharedSnapshot.docs];

    let child = null;
    if (childId) {
      const childDoc = allChildren.find(d => d.id === childId);
      if (childDoc) {
        const d = childDoc.data();
        const birthDate = d.birthDate?.toDate?.() || new Date(d.birthDate);
        const ageMonths = Math.floor((new Date() - birthDate) / (1000 * 60 * 60 * 24 * 30.44));
        if (ageMonths >= 6) child = { id: childDoc.id, ...d, ageMonths };
      }
    }
    if (!child) {
      for (const childDoc of allChildren) {
        const d = childDoc.data();
        const birthDate = d.birthDate?.toDate?.() || new Date(d.birthDate);
        const ageMonths = Math.floor((new Date() - birthDate) / (1000 * 60 * 60 * 24 * 30.44));
        if (ageMonths >= 6) {
          child = { id: childDoc.id, ...d, ageMonths };
          break;
        }
      }
    }

    if (!child) {
      return res.status(400).json({
        success: false,
        message: 'No tienes hijos de 6+ meses para enviar receta de prueba'
      });
    }

    const mealType = 'lunch';
    const childName = child.name || 'tu bebé';
    let recipe = null;

    if (!regenerate) {
    try {
      const now = new Date();
      const cacheCutoff = new Date(now.getTime() - 12 * 60 * 60 * 1000);
      const cachedSnapshot = await db.collection('homeRecipeCache')
        .where('childId', '==', child.id)
        .where('mealType', '==', mealType)
        .orderBy('createdAt', 'desc')
        .limit(1)
        .get();
      if (!cachedSnapshot.empty) {
        const cached = cachedSnapshot.docs[0].data();
        const cachedAt = cached.createdAt?.toDate?.() || new Date(cached.createdAt);
        if (cachedAt >= cacheCutoff) recipe = cached.recipe;
      }
    } catch (cacheErr) {
      // Índice puede no existir; continuar sin caché
    }
    }

    if (!recipe) {
      const ageYears = Math.floor(child.ageMonths / 12);
      const remainingMonths = child.ageMonths % 12;
      let ageContext = child.ageMonths < 12
        ? `Bebé de ${child.ageMonths} meses en alimentación complementaria.`
        : child.ageMonths < 24
          ? `Niño de ${ageYears > 0 ? ageYears + ' año' : child.ageMonths + ' meses'}.`
          : `Niño de ${ageYears} años.`;
      const prompt = `Genera UNA receta de almuerzo para: ${ageContext} Devuelve SOLO JSON: {"recipes":[{"name":"Nombre receta","mealType":"lunch","description":"...","prepTime":10,"cookTime":15,"servings":2,"difficulty":"fácil","ingredients":[{"item":"x","quantity":"1"}],"instructions":["Paso 1"],"nutritionalInfo":{},"tips":[],"allergens":[]}]}`;
      const completion = await openai.chat.completions.create({
        model: process.env.OPENAI_MODEL || 'gpt-3.5-turbo',
        messages: [
          { role: 'system', content: 'Responde solo JSON válido.' },
          { role: 'user', content: prompt }
        ],
        temperature: 0.8,
        max_tokens: 800
      });
      const text = completion.choices[0]?.message?.content;
      if (text) {
        try {
          const data = JSON.parse(text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim());
          const raw = data.recipes?.[0];
          if (raw) {
            recipe = {
              name: raw.name || 'Receta del día',
              mealType: 'lunch',
              description: raw.description || '',
              prepTime: parseInt(raw.prepTime, 10) || 0,
              cookTime: parseInt(raw.cookTime, 10) || 0,
              servings: parseInt(raw.servings, 10) || 2,
              difficulty: raw.difficulty || 'fácil',
              ingredients: Array.isArray(raw.ingredients) ? raw.ingredients : [],
              instructions: Array.isArray(raw.instructions) ? raw.instructions : [],
              nutritionalInfo: raw.nutritionalInfo && typeof raw.nutritionalInfo === 'object' ? raw.nutritionalInfo : {},
              tips: Array.isArray(raw.tips) ? raw.tips : [],
              allergens: Array.isArray(raw.allergens) ? raw.allergens : []
            };
            const recipeRef = await db.collection('recipes').add({
              userId: uid,
              childId: child.id,
              childName,
              mealType,
              ageMonths: child.ageMonths,
              ...recipe,
              source: 'test',
              createdAt: admin.firestore.FieldValue.serverTimestamp()
            });
            recipe.id = recipeRef.id;
            await db.collection('homeRecipeCache').add({
              childId: child.id,
              mealType,
              recipe: { ...recipe, childId: child.id, childName, ageMonths: child.ageMonths, generatedAt: new Date().toISOString() },
              ageMonths: child.ageMonths,
              createdAt: admin.firestore.FieldValue.serverTimestamp()
            });
          }
        } catch (_) {}
      }
    }

    const recipeName = recipe?.name || 'la receta del día';
    const title = `¿Ya le preparaste ${recipeName} a ${childName}?`;
    const body = `Receta del día para ${childName}`;

    let recipeId = recipe?.id || '';
    if (!recipeId && recipe) {
      try {
        const recipeRef = await db.collection('recipes').add({
          userId: uid,
          childId: child.id,
          childName,
          mealType: 'lunch',
          ageMonths: child.ageMonths,
          name: recipe.name,
          description: recipe.description || '',
          prepTime: recipe.prepTime || 0,
          cookTime: recipe.cookTime || 0,
          servings: recipe.servings || 2,
          difficulty: recipe.difficulty || 'fácil',
          ingredients: recipe.ingredients || [],
          instructions: recipe.instructions || [],
          nutritionalInfo: recipe.nutritionalInfo || {},
          tips: recipe.tips || [],
          allergens: recipe.allergens || [],
          source: 'test',
          createdAt: admin.firestore.FieldValue.serverTimestamp()
        });
        recipeId = recipeRef.id;
      } catch (_) {}
    }

    await sendPushNotification(
      userData.fcmTokens,
      { title, body },
      {
        type: 'recipe_daily_reminder',
        recipeId,
        childId: child.id,
        childName,
        recipeName,
        screen: 'RecipeDetail',
        screenParams: recipeId,
        test: true
      }
    );

    await db.collection('notifications').add({
      userId: uid,
      type: 'recipe_daily_reminder',
      title,
      body,
      data: { childId: child.id, childName, recipeName, recipeId },
      read: false,
      createdAt: admin.firestore.FieldValue.serverTimestamp()
    });

    res.json({
      success: true,
      message: 'Push de receta enviado',
      data: { title, body, childName, recipeName, recipeId }
    });
  } catch (error) {
    console.error('❌ [TEST] Error push receta:', error);
    res.status(500).json({
      success: false,
      message: 'Error enviando push de prueba',
      error: error.message
    });
  }
});

// Endpoint para probar push de medicamento (envía ahora)
app.post('/api/notifications/test-medication-reminder', authenticateToken, async (req, res) => {
  try {
    const { uid } = req.user;

    if (!db) {
      return res.status(503).json({ success: false, message: 'Servicio no disponible' });
    }

    const userDoc = await db.collection('users').doc(uid).get();
    if (!userDoc.exists) {
      return res.status(404).json({ success: false, message: 'Usuario no encontrado' });
    }
    const userData = userDoc.data();
    if (!userData.fcmTokens || userData.fcmTokens.length === 0) {
      return res.status(400).json({
        success: false,
        message: 'No tienes tokens FCM. Abre la app para registrar notificaciones.'
      });
    }

    let notif = null;
    try {
      const snapshot = await db.collection('scheduled_med_notifications')
        .where('userId', '==', uid)
        .where('sent', '==', false)
        .limit(5)
        .get();
      if (!snapshot.empty) {
        notif = snapshot.docs[0].data();
        notif.id = snapshot.docs[0].id;
      }
    } catch (qErr) {
      console.warn('[TEST] Error consultando scheduled_med_notifications:', qErr.message);
    }

    if (!notif) {
      const medsSnapshot = await db.collection('medications')
        .where('userId', '==', uid)
        .where('active', '==', true)
        .limit(1)
        .get();
      if (medsSnapshot.empty) {
        return res.status(400).json({
          success: false,
          message: 'No tienes medicamentos activos ni recordatorios pendientes'
        });
      }
      const med = medsSnapshot.docs[0].data();
      const childDoc = await db.collection('children').doc(med.childId).get();
      const childName = childDoc.exists ? (childDoc.data().name || 'tu bebé') : 'tu bebé';
      notif = {
        medicationName: med.name || 'Medicamento',
        dose: med.dose || '',
        doseUnit: med.doseUnit || '',
        childName,
        title: `💊 Momento de ${med.name || 'medicamento'}`,
        body: `Es hora de ${med.name || 'medicamento'}: ${med.dose || ''} ${med.doseUnit || ''} para ${childName}.`
      };
    }

    const title = notif.title || `💊 Momento de ${notif.medicationName}`;
    const body = notif.body || `Es hora de ${notif.medicationName}: ${notif.dose || ''} ${notif.doseUnit || ''} para ${notif.childName}.`;

    await sendPushNotification(
      userData.fcmTokens,
      { title, body },
      {
        type: 'medication_reminder',
        childId: notif.childId || '',
        medicationId: notif.medicationId || '',
        medicationName: notif.medicationName || '',
        screen: 'MedicationScreen',
        test: true
      }
    );

    res.json({
      success: true,
      message: 'Push de medicamento enviado',
      data: { title, body, medicationName: notif.medicationName, childName: notif.childName }
    });
  } catch (error) {
    console.error('❌ [TEST] Error push medicamento:', error);
    res.status(500).json({
      success: false,
      message: 'Error enviando push de medicamento',
      error: error.message
    });
  }
});

