/**
 * Solicitar ser profesional (App)
 * POST /api/profile/request-professional
 */
app.post('/api/profile/request-professional', authenticateToken, async (req, res) => {
  try {
    const userId = req.user.uid;
    const { accountType, personalInfo, professional, documents } = req.body;
    
    // Validaciones
    if (!accountType || !['specialist', 'nutritionist', 'coach', 'psychologist'].includes(accountType)) {
      return res.status(400).json({
        success: false,
        message: 'Tipo de cuenta inválido. Debe ser: specialist, nutritionist, coach o psychologist'
      });
    }
    
    if (!personalInfo?.displayName || !personalInfo?.phone) {
      return res.status(400).json({
        success: false,
        message: 'Nombre y teléfono son requeridos'
      });
    }
    
    if (!professional?.specialties || professional.specialties.length === 0) {
      return res.status(400).json({
        success: false,
        message: 'Debe especificar al menos una especialidad'
      });
    }
    
    if (!documents || documents.length === 0) {
      return res.status(400).json({
        success: false,
        message: 'Debe adjuntar al menos un documento (título, cédula o licencia)'
      });
    }
    
    // Verificar que el usuario existe
    const userDoc = await db.collection('users').doc(userId).get();
    
    if (!userDoc.exists) {
      return res.status(404).json({
        success: false,
        message: 'Usuario no encontrado'
      });
    }
    
    const userData = userDoc.data();
    
    // Verificar que no tenga ya un perfil profesional activo
    if (userData.professionalProfile?.isActive) {
      return res.status(400).json({
        success: false,
        message: 'Ya tienes un perfil profesional activo'
      });
    }
    
    // Verificar que no tenga una solicitud pendiente
    const existingRequestSnapshot = await db.collection('professionalRequests')
      .where('userId', '==', userId)
      .where('status', '==', 'pending')
      .limit(1)
      .get();
    
    if (!existingRequestSnapshot.empty) {
      return res.status(400).json({
        success: false,
        message: 'Ya tienes una solicitud pendiente de aprobación'
      });
    }
    
    // Crear solicitud
    const requestData = {
      userId,
      userEmail: userData.email,
      userName: userData.displayName,
      userPhotoUrl: userData.photoURL || null,
      accountType,
      personalInfo: {
        displayName: personalInfo.displayName.trim(),
        phone: personalInfo.phone.trim(),
        bio: personalInfo.bio?.trim() || null
      },
      professional: {
        specialties: professional.specialties,
        licenseNumber: professional.licenseNumber?.trim() || null,
        university: professional.university?.trim() || null,
        yearsExperience: professional.yearsExperience || 0,
        certifications: professional.certifications || []
      },
      documents, // Array de URLs de documentos subidos
      status: 'pending', // pending, approved, rejected
      createdAt: new Date(),
      updatedAt: new Date()
    };
    
    const requestRef = await db.collection('professionalRequests').add(requestData);
    
    console.log(`✅ [PROFESSIONAL-REQUEST] Solicitud creada: ${requestRef.id} - ${userData.email}`);
    
    // TODO: Enviar notificación a admins
    
    res.json({
      success: true,
      message: 'Solicitud enviada exitosamente. Te notificaremos cuando sea revisada.',
      data: {
        requestId: requestRef.id,
        status: 'pending',
        createdAt: requestData.createdAt
      }
    });
    
  } catch (error) {
    console.error('❌ [PROFESSIONAL-REQUEST] Error creando solicitud:', error);
    res.status(500).json({
      success: false,
      message: 'Error creando solicitud',
      error: error.message
    });
  }
});

/**
 * Subir documento para solicitud profesional (App)
 * POST /api/professionals/requests/upload-document
 */
const uploadDocument = multer({
  storage: multer.memoryStorage(),
  limits: {
    fileSize: 10 * 1024 * 1024 // 10MB máximo para documentos
  },
  fileFilter: function (req, file, cb) {
    // Permitir PDFs, imágenes y documentos
    const allowedTypes = [
      'application/pdf',
      'image/jpeg',
      'image/jpg',
      'image/png',
      'image/heic',
      'image/heif'
    ];
    
    if (allowedTypes.includes(file.mimetype)) {
      cb(null, true);
    } else {
      cb(new Error('Solo se permiten archivos PDF o imágenes'), false);
    }
  }
});

app.post('/api/professionals/requests/upload-document', authenticateToken, uploadDocument.single('document'), async (req, res) => {
  try {
    const userId = req.user.uid;
    const bucket = admin.storage().bucket();
    
    if (!req.file) {
      return res.status(400).json({
        success: false,
        message: 'No se recibió ningún archivo'
      });
    }
    
    const file = req.file;
    const timestamp = Date.now();
    
    // Determinar extensión del archivo
    let extension = 'pdf';
    if (file.mimetype.startsWith('image/')) {
      const mimeExtensions = {
        'image/jpeg': 'jpg',
        'image/jpg': 'jpg',
        'image/png': 'png',
        'image/heic': 'heic',
        'image/heif': 'heif'
      };
      extension = mimeExtensions[file.mimetype] || 'jpg';
    }
    
    // Crear referencia en Storage
    const fileName = `documents/professional-requests/doc-${userId}-${timestamp}.${extension}`;
    const fileRef = bucket.file(fileName);
    
    // Subir archivo
    await fileRef.save(file.buffer, {
      metadata: {
        contentType: file.mimetype,
        metadata: {
          uploadedBy: userId,
          uploadedAt: new Date().toISOString()
        }
      }
    });
    
    // Hacer el archivo público
    await fileRef.makePublic();
    
    // Obtener URL pública
    const publicUrl = `https://storage.googleapis.com/${bucket.name}/${fileName}`;
    
    console.log(`✅ [DOCUMENT] Documento subido: ${fileName}`);
    
    res.json({
      success: true,
      message: 'Documento subido exitosamente',
      data: {
        url: publicUrl,
        storagePath: fileName,
        fileName: file.originalname,
        size: file.size,
        mimeType: file.mimetype
      }
    });
    
  } catch (error) {
    console.error('❌ [DOCUMENT] Error subiendo documento:', error);
    res.status(500).json({
      success: false,
      message: 'Error subiendo documento',
      error: error.message
    });
  }
});

/**
 * Enviar solicitud de servicio profesional (App)
 * POST /api/profile/request-service
 */
app.post('/api/profile/request-service', authenticateToken, async (req, res) => {
  try {
    const userId = req.user.uid;
    const { 
      businessName,
      profileCategoryId,
      cityId,
      countryId,
      address,
      summary,
      extraInfo,
      whatsappLink,
      instagram,
      website,
      logoUrl,
      logoStoragePath,
      latitude,
      longitude
    } = req.body;
    
    // Validaciones
    if (!businessName || !profileCategoryId) {
      return res.status(400).json({
        success: false,
        message: 'Nombre del negocio y categoría son requeridos'
      });
    }
    
    // Verificar que el usuario existe
    const userDoc = await db.collection('users').doc(userId).get();
    
    if (!userDoc.exists) {
      return res.status(404).json({
        success: false,
        message: 'Usuario no encontrado'
      });
    }
    
    const userData = userDoc.data();
    
    // Obtener información de la categoría
    let profileCategory = null;
    if (profileCategoryId) {
      const categoryDoc = await db.collection('professional_profile_categories').doc(profileCategoryId).get();
      if (categoryDoc.exists) {
        const catData = categoryDoc.data();
        profileCategory = {
          id: categoryDoc.id,
          name: catData.name,
          logoUrl: catData.logoUrl
        };
      }
    }
    
    // Obtener información de ubicación
    let cityName = null;
    let countryName = null;
    
    if (countryId) {
      const countryDoc = await db.collection('countries').doc(countryId).get();
      if (countryDoc.exists) {
        countryName = countryDoc.data().name;
      }
    }
    
    if (cityId) {
      const cityDoc = await db.collection('cities').doc(cityId).get();
      if (cityDoc.exists) {
        cityName = cityDoc.data().name;
      }
    }
    
    // Crear solicitud
    const requestData = {
      userId,
      userEmail: userData.email,
      userName: userData.displayName || userData.name,
      userPhotoUrl: userData.photoURL || null,
      businessName: businessName.trim(),
      profileCategoryId,
      profileCategory,
      cityId: cityId || null,
      cityName: cityName || null,
      countryId: countryId || null,
      countryName: countryName || null,
      address: address?.trim() || null,
      summary: summary?.trim() || null,
      extraInfo: extraInfo?.trim() || null,
      whatsappLink: whatsappLink?.trim() || null,
      instagram: instagram?.trim() || null,
      website: website?.trim() || null,
      logoUrl: logoUrl || null,
      logoStoragePath: logoStoragePath || null,
      latitude: latitude || 0,
      longitude: longitude || 0,
      status: 'pending', // pending, approved, rejected
      createdAt: new Date(),
      updatedAt: new Date()
    };
    
    const requestRef = await db.collection('serviceRequests').add(requestData);
    
    console.log(`✅ [SERVICE-REQUEST] Solicitud creada: ${requestRef.id} - ${businessName}`);
    
    res.json({
      success: true,
      message: 'Solicitud enviada exitosamente. Te notificaremos cuando sea revisada.',
      data: {
        id: requestRef.id,
        ...requestData
      }
    });
    
  } catch (error) {
    console.error('❌ [SERVICE-REQUEST] Error creando solicitud:', error);
    res.status(500).json({
      success: false,
      message: 'Error enviando solicitud',
      error: error.message
    });
  }
});

/**
 * Listar solicitudes de perfiles profesionales (Admin)
 * GET /api/admin/professional-requests
 */
app.get('/api/admin/professional-requests', authenticateToken, isAdmin, async (req, res) => {
  try {
    const { status, accountType, page = 1, limit = 20, search } = req.query;
    
    let query = db.collection('professionalRequests');
    
    // Filtros
    if (status) {
      query = query.where('status', '==', status);
    }
    
    if (accountType) {
      query = query.where('accountType', '==', accountType);
    }
    
    query = query.orderBy('createdAt', 'desc');
    
    const snapshot = await query.get();
    
    let requests = [];
    snapshot.forEach(doc => {
      const data = doc.data();
      
      // Filtro de búsqueda
      if (search) {
        const searchLower = search.toLowerCase();
        const matchesName = data.personalInfo?.displayName?.toLowerCase().includes(searchLower);
        const matchesEmail = data.userEmail?.toLowerCase().includes(searchLower);
        if (!matchesName && !matchesEmail) {
          return;
        }
      }
      
      requests.push({
        id: doc.id,
        userId: data.userId,
        userEmail: data.userEmail,
        userName: data.userName,
        userPhotoUrl: data.userPhotoUrl,
        accountType: data.accountType,
        personalInfo: data.personalInfo,
        professional: data.professional,
        documents: data.documents,
        status: data.status,
        createdAt: data.createdAt?.toDate?.() || data.createdAt,
        updatedAt: data.updatedAt?.toDate?.() || data.updatedAt,
        reviewedAt: data.reviewedAt?.toDate?.() || data.reviewedAt,
        reviewedBy: data.reviewedBy || null,
        rejectionReason: data.rejectionReason || null
      });
    });
    
    // Paginación
    const pageNum = parseInt(page);
    const limitNum = parseInt(limit);
    const startIndex = (pageNum - 1) * limitNum;
    const endIndex = startIndex + limitNum;
    const paginatedRequests = requests.slice(startIndex, endIndex);
    
    // Estadísticas
    const stats = {
      pending: requests.filter(r => r.status === 'pending').length,
      approved: requests.filter(r => r.status === 'approved').length,
      rejected: requests.filter(r => r.status === 'rejected').length
    };
    
    console.log(`✅ [ADMIN] Solicitudes profesionales listadas: ${requests.length} total`);
    
    res.json({
      success: true,
      data: paginatedRequests,
      pagination: {
        page: pageNum,
        limit: limitNum,
        total: requests.length,
        totalPages: Math.ceil(requests.length / limitNum)
      },
      stats
    });
    
  } catch (error) {
    console.error('❌ [ADMIN] Error listando solicitudes:', error);
    res.status(500).json({
      success: false,
      message: 'Error listando solicitudes',
      error: error.message
    });
  }
});

/**
 * Aprobar solicitud de perfil profesional (Admin)
 * POST /api/admin/professional-requests/:requestId/approve
 */
app.post('/api/admin/professional-requests/:requestId/approve', authenticateToken, isAdmin, async (req, res) => {
  try {
    const { requestId } = req.params;
    const { pricing } = req.body;
    
    const requestDoc = await db.collection('professionalRequests').doc(requestId).get();
    
    if (!requestDoc.exists) {
      return res.status(404).json({
        success: false,
        message: 'Solicitud no encontrada'
      });
    }
    
    const requestData = requestDoc.data();
    
    if (requestData.status !== 'pending') {
      return res.status(400).json({
        success: false,
        message: `La solicitud ya fue ${requestData.status === 'approved' ? 'aprobada' : 'rechazada'}`
      });
    }
    
    // Crear perfil profesional unificado
    const professionalData = {
      // Estructura compatible con professionals existentes
      name: requestData.personalInfo.displayName,
      headline: `${requestData.professional.specialties[0]} especializado`,
      bio: requestData.personalInfo.bio || '',
      photoUrl: requestData.userPhotoUrl || null,
      contactEmail: requestData.userEmail,
      contactPhone: requestData.personalInfo.phone || '',
      website: '',
      location: '',
      specialties: requestData.professional.specialties || [],
      tags: requestData.professional.specialties || [],
      
      // Campos para consultas médicas
      accountType: requestData.accountType,
      canAcceptConsultations: true,
      
      professionalInfo: {
        licenseNumber: requestData.professional.licenseNumber || null,
        university: requestData.professional.university || null,
        yearsExperience: requestData.professional.yearsExperience || 0,
        certifications: requestData.professional.certifications || []
      },
      
      availability: {
        schedule: {},
        timezone: 'America/Guayaquil',
        maxConsultationsPerDay: 10
      },
      
      consultationPricing: {
        chatConsultation: pricing?.chatConsultation || 25,
        videoConsultation: pricing?.videoConsultation || 40,
        currency: pricing?.currency || 'USD',
        acceptsFreeConsultations: pricing?.acceptsFreeConsultations || false
      },
      
      consultationStats: {
        totalConsultations: 0,
        averageRating: 0,
        responseTime: 0,
        completionRate: 100
      },
      
      linkedUserId: requestData.userId,
      userId: requestData.userId,  // Para compatibilidad
      
      permissions: {
        canAcceptConsultations: true,
        canPrescribe: requestData.accountType === 'specialist',
        canDiagnose: ['specialist', 'psychologist'].includes(requestData.accountType),
        canSellProducts: ['nutritionist', 'coach'].includes(requestData.accountType),
        canCreateMealPlans: requestData.accountType === 'nutritionist',
        canWriteArticles: true
      },
      
      status: 'active',
      createdAt: new Date(),
      updatedAt: new Date()
    };
    
    const professionalRef = await db.collection('professionals').add(professionalData);
    
    // Actualizar usuario con professionalProfile
    await db.collection('users').doc(requestData.userId).update({
      professionalProfile: {
        isActive: true,
        specialistId: professionalRef.id,
        accountType: requestData.accountType,
        verifiedAt: new Date()
      },
      updatedAt: admin.firestore.FieldValue.serverTimestamp()
    });
    
    // Actualizar solicitud
    await db.collection('professionalRequests').doc(requestId).update({
      status: 'approved',
      reviewedAt: new Date(),
      reviewedBy: req.user.email || req.user.uid,
      specialistId: professionalRef.id,
      updatedAt: new Date()
    });
    
    console.log(`✅ [ADMIN] Solicitud aprobada: ${requestId} -> Profesional ${professionalRef.id}`);
    
    // TODO: Enviar email de aprobación al usuario
    // TODO: Enviar notificación push
    
    res.json({
      success: true,
      message: 'Solicitud aprobada exitosamente. El usuario ahora es un profesional verificado.',
      data: {
        requestId,
        specialistId: professionalRef.id,
        userId: requestData.userId,
        userEmail: requestData.userEmail
      }
    });
    
  } catch (error) {
    console.error('❌ [ADMIN] Error aprobando solicitud:', error);
    res.status(500).json({
      success: false,
      message: 'Error aprobando solicitud',
      error: error.message
    });
  }
});

/**
 * Rechazar solicitud de perfil profesional (Admin)
 * POST /api/admin/professional-requests/:requestId/reject
 */
app.post('/api/admin/professional-requests/:requestId/reject', authenticateToken, isAdmin, async (req, res) => {
  try {
    const { requestId } = req.params;
    const { reason } = req.body;
    
    if (!reason || reason.trim().length === 0) {
      return res.status(400).json({
        success: false,
        message: 'Debe proporcionar una razón para el rechazo'
      });
    }
    
    const requestDoc = await db.collection('professionalRequests').doc(requestId).get();
    
    if (!requestDoc.exists) {
      return res.status(404).json({
        success: false,
        message: 'Solicitud no encontrada'
      });
    }
    
    const requestData = requestDoc.data();
    
    if (requestData.status !== 'pending') {
      return res.status(400).json({
        success: false,
        message: `La solicitud ya fue ${requestData.status === 'approved' ? 'aprobada' : 'rechazada'}`
      });
    }
    
    // Actualizar solicitud
    await db.collection('professionalRequests').doc(requestId).update({
      status: 'rejected',
      reviewedAt: new Date(),
      reviewedBy: req.user.email || req.user.uid,
      rejectionReason: reason.trim(),
      updatedAt: new Date()
    });
    
    console.log(`✅ [ADMIN] Solicitud rechazada: ${requestId} - Razón: ${reason}`);
    
    // TODO: Enviar email de rechazo al usuario con la razón
    // TODO: Enviar notificación push
    
    res.json({
      success: true,
      message: 'Solicitud rechazada',
      data: {
        requestId,
        userId: requestData.userId,
        userEmail: requestData.userEmail,
        reason: reason.trim()
      }
    });
    
  } catch (error) {
    console.error('❌ [ADMIN] Error rechazando solicitud:', error);
    res.status(500).json({
      success: false,
      message: 'Error rechazando solicitud',
      error: error.message
    });
  }
});

