// ============================================================================
// SISTEMA DE PERFILES PROFESIONALES - PANEL DEL ESPECIALISTA
// ============================================================================

/**
 * Obtener consultas asignadas al especialista (App - Modo Profesional)
 * GET /api/specialist/consultations
 */
app.get('/api/specialist/consultations', authenticateToken, async (req, res) => {
  try {
    const userId = req.user.uid;
    const { status, page = 1, limit = 20, urgency, type } = req.query;
    
    // Verificar que el usuario tiene perfil profesional
    const userDoc = await db.collection('users').doc(userId).get();
    
    if (!userDoc.exists) {
      return res.status(404).json({
        success: false,
        message: 'Usuario no encontrado'
      });
    }
    
    const userData = userDoc.data();
    
    if (!userData.professionalProfile?.isActive) {
      return res.status(403).json({
        success: false,
        message: 'No tienes un perfil profesional activo'
      });
    }
    
    let specialistId = userData.professionalProfile.specialistId;
    if (!specialistId) {
      const proSnapshot = await db.collection('professionals')
        .where('linkedUserId', '==', userId)
        .limit(1)
        .get();
      if (!proSnapshot.empty) {
        specialistId = proSnapshot.docs[0].id;
        await db.collection('users').doc(userId).update({
          'professionalProfile.specialistId': specialistId,
          updatedAt: new Date()
        });
        console.log(`📌 [SPECIALIST] specialistId asignado desde linkedUserId: ${specialistId}`);
      }
    }
    if (!specialistId) {
      return res.status(400).json({
        success: false,
        message: 'No tienes especialista vinculado. Contacta al administrador.'
      });
    }
    
    const snapshot = await db.collection('consultations')
      .where('specialistId', '==', specialistId)
      .get();
    
    let docs = snapshot.docs;
    if (status) docs = docs.filter(d => d.data().status === status);
    const toMs = (doc) => {
      const c = doc.data()?.createdAt;
      return c?.toMillis?.() ?? c?.toDate?.()?.getTime?.() ?? (c instanceof Date ? c.getTime() : 0);
    };
    docs = docs.sort((a, b) => toMs(b) - toMs(a));
    
    // Filtrar y enriquecer datos
    const consultations = [];
    
    for (const doc of docs) {
      const data = doc.data();
      
      // Filtros adicionales
      if (urgency && data.request?.urgency !== urgency) continue;
      if (type && data.type !== type) continue;
      
      // Obtener info del niño
      let childInfo = null;
      if (data.childId) {
        const childDoc = await db.collection('children').doc(data.childId).get();
        if (childDoc.exists) {
          const childData = childDoc.data();
          const birthDate = parseDateSafe(childData.birthDate);
          const ageMonths = birthDate ? calculateMonthsFromBirthDate(birthDate) : null;
          
          childInfo = {
            name: childData.name,
            age: ageMonths ? `${Math.floor(ageMonths / 12)} años ${ageMonths % 12} meses` : 'N/A',
            photoUrl: childData.photoUrl || null
          };
        }
      }
      
      // Obtener info del padre
      let parentInfo = null;
      if (data.parentId) {
        const parentDoc = await db.collection('users').doc(data.parentId).get();
        if (parentDoc.exists) {
          const parentData = parentDoc.data();
          parentInfo = {
            name: parentData.displayName || 'Usuario',
            photoUrl: parentData.photoURL || null
          };
        }
      }
      
      consultations.push({
        id: doc.id,
        childName: childInfo?.name || 'N/A',
        childAge: childInfo?.age || 'N/A',
        childPhotoUrl: childInfo?.photoUrl,
        parent: parentInfo,
        type: data.type,
        status: data.status,
        request: {
          description: data.request?.description,
          photos: data.request?.photos || [],
          symptomDetails: data.request?.symptomDetails || [],
          urgency: data.request?.urgency
        },
        pricing: {
          finalPrice: data.pricing?.finalPrice || 0,
          isFree: data.pricing?.finalPrice === 0
        },
        createdAt: data.createdAt?.toDate?.() || data.createdAt,
        scheduledFor: data.scheduledFor?.toDate?.() || data.scheduledFor,
        acceptedAt: data.acceptedAt?.toDate?.() || data.acceptedAt
      });
    }
    
    // Paginación
    const pageNum = parseInt(page);
    const limitNum = parseInt(limit);
    const startIndex = (pageNum - 1) * limitNum;
    const endIndex = startIndex + limitNum;
    const paginatedConsultations = consultations.slice(startIndex, endIndex);
    
    // Calcular estadísticas
    const stats = {
      pending: consultations.filter(c => c.status === 'pending').length,
      accepted: consultations.filter(c => c.status === 'accepted').length,
      in_progress: consultations.filter(c => c.status === 'in_progress').length,
      completed: consultations.filter(c => c.status === 'completed').length
    };
    
    console.log(`✅ [SPECIALIST] Consultas listadas: ${consultations.length} para specialistId=${specialistId} (userId=${userId})`);
    
    res.json({
      success: true,
      data: paginatedConsultations,
      pagination: {
        page: pageNum,
        limit: limitNum,
        total: consultations.length,
        totalPages: Math.ceil(consultations.length / limitNum)
      },
      stats
    });
    
  } catch (error) {
    console.error('❌ [SPECIALIST] Error listando consultas:', error);
    res.status(500).json({
      success: false,
      message: 'Error listando consultas',
      error: error.message
    });
  }
});

/**
 * Historial de consultas completadas (Especialista médico)
 * GET /api/specialist/consultations/history?page=1&limit=20
 */
app.get('/api/specialist/consultations/history', authenticateToken, async (req, res) => {
  try {
    const userId = req.user.uid;
    const { page = 1, limit = 20 } = req.query;
    
    const userDoc = await db.collection('users').doc(userId).get();
    if (!userDoc.exists || !userDoc.data().professionalProfile?.isActive) {
      return res.status(403).json({
        success: false,
        message: 'No tienes un perfil médico activo'
      });
    }
    
    const specialistId = userDoc.data().professionalProfile.specialistId;
    
    const snapshot = await db.collection('consultations')
      .where('specialistId', '==', specialistId)
      .where('status', '==', 'completed')
      .orderBy('createdAt', 'desc')
      .get();
    
    const consultations = [];
    for (const doc of snapshot.docs) {
      const data = doc.data();
      let childInfo = null;
      if (data.childId) {
        const childDoc = await db.collection('children').doc(data.childId).get();
        if (childDoc.exists) {
          const c = childDoc.data();
          const birthDate = parseDateSafe(c.birthDate);
          const ageMonths = birthDate ? calculateMonthsFromBirthDate(birthDate) : null;
          childInfo = { name: c.name, age: ageMonths ? `${Math.floor(ageMonths / 12)} años ${ageMonths % 12} meses` : 'N/A' };
        }
      }
      let parentInfo = null;
      if (data.parentId) {
        const parentDoc = await db.collection('users').doc(data.parentId).get();
        if (parentDoc.exists) {
          const p = parentDoc.data();
          parentInfo = { name: p.displayName || 'Usuario' };
        }
      }
      consultations.push({
        id: doc.id,
        childName: childInfo?.name || 'N/A',
        childAge: childInfo?.age || 'N/A',
        parent: parentInfo,
        type: data.type,
        status: data.status,
        result: data.result,
        pricing: { finalPrice: data.pricing?.finalPrice || 0 },
        createdAt: data.createdAt?.toDate?.() || data.createdAt,
        completedAt: data.completedAt?.toDate?.() || data.completedAt,
        rating: data.rating
      });
    }
    
    const pageNum = Math.max(1, parseInt(page));
    const limitNum = Math.min(50, Math.max(1, parseInt(limit)));
    const start = (pageNum - 1) * limitNum;
    const paginated = consultations.slice(start, start + limitNum);
    
    res.json({
      success: true,
      data: paginated,
      pagination: {
        page: pageNum,
        limit: limitNum,
        total: consultations.length,
        hasMore: start + limitNum < consultations.length
      }
    });
  } catch (error) {
    console.error('❌ [SPECIALIST] Error obteniendo historial:', error);
    res.status(500).json({
      success: false,
      message: 'Error obteniendo historial de consultas',
      error: error.message
    });
  }
});

/**
 * Obtener detalles de consulta (Especialista)
 * GET /api/specialist/consultations/:consultationId
 */
app.get('/api/specialist/consultations/:consultationId', authenticateToken, async (req, res) => {
  try {
    const userId = req.user.uid;
    const { consultationId } = req.params;
    
    // Verificar perfil profesional
    const userDoc = await db.collection('users').doc(userId).get();
    
    if (!userDoc.exists || !userDoc.data().professionalProfile?.isActive) {
      return res.status(403).json({
        success: false,
        message: 'No tienes un perfil profesional activo'
      });
    }
    
    const specialistId = userDoc.data().professionalProfile.specialistId;
    
    const consultationDoc = await db.collection('consultations').doc(consultationId).get();
    
    if (!consultationDoc.exists) {
      return res.status(404).json({
        success: false,
        message: 'Consulta no encontrada'
      });
    }
    
    const data = consultationDoc.data();
    
    // Verificar que la consulta pertenece a este especialista
    if (data.specialistId !== specialistId) {
      return res.status(403).json({
        success: false,
        message: 'No tienes acceso a esta consulta'
      });
    }
    
    // Obtener info completa del niño
    let childInfo = null;
    if (data.childId) {
      const childDoc = await db.collection('children').doc(data.childId).get();
      if (childDoc.exists) {
        childInfo = {
          id: childDoc.id,
          ...childDoc.data(),
          birthDate: childDoc.data().birthDate?.toDate?.() || childDoc.data().birthDate
        };
      }
    }
    
    // Obtener info del padre
    let parentInfo = null;
    if (data.parentId) {
      const parentDoc = await db.collection('users').doc(data.parentId).get();
      if (parentDoc.exists) {
        const parentData = parentDoc.data();
        parentInfo = {
          id: parentDoc.id,
          name: parentData.displayName,
          email: parentData.email,
          photoUrl: parentData.photoURL,
          phone: parentData.phone
        };
      }
    }
    
    let messages = [];
    try {
      const messagesSnapshot = await db.collection('consultations')
        .doc(consultationId)
        .collection('messages')
        .orderBy('createdAt', 'asc')
        .get();
      messagesSnapshot.forEach(msgDoc => {
        const msgData = msgDoc.data();
        messages.push({
          id: msgDoc.id,
          ...msgData,
          createdAt: msgData.createdAt?.toDate?.() || msgData.createdAt
        });
      });
    } catch (e) {
      const altSnap = await db.collection('consultations').doc(consultationId).collection('messages').get();
      messages = altSnap.docs.map(d => ({ id: d.id, ...d.data(), createdAt: d.data().createdAt?.toDate?.() || d.data().createdAt })).sort((a, b) => (a.createdAt || 0) - (b.createdAt || 0));
    }

    const specialistProDoc = await db.collection('professionals').doc(specialistId).get();
    const canPrescribe = specialistProDoc.exists ? (specialistProDoc.data().permissions?.canPrescribe ?? specialistProDoc.data().canPrescribe ?? false) : false;

    res.json({
      success: true,
      data: {
        id: consultationDoc.id,
        ...data,
        child: childInfo,
        parent: parentInfo,
        messages,
        result: data.result || data.outcome,
        canPrescribe,
        createdAt: data.createdAt?.toDate?.() || data.createdAt,
        acceptedAt: data.acceptedAt?.toDate?.() || data.acceptedAt,
        startedAt: data.startedAt?.toDate?.() || data.startedAt,
        completedAt: data.completedAt?.toDate?.() || data.completedAt,
        scheduledFor: data.scheduledFor?.toDate?.() || data.scheduledFor
      }
    });
    
  } catch (error) {
    console.error('❌ [SPECIALIST] Error obteniendo consulta:', error);
    res.status(500).json({
      success: false,
      message: 'Error obteniendo consulta',
      error: error.message
    });
  }
});

/**
 * Aceptar consulta (Especialista)
 * POST /api/specialist/consultations/:consultationId/accept
 */
app.post('/api/specialist/consultations/:consultationId/accept', authenticateToken, async (req, res) => {
  try {
    const userId = req.user.uid;
    const { consultationId } = req.params;
    const { scheduledFor, estimatedResponseTime } = req.body;
    
    // Verificar perfil profesional
    const userDoc = await db.collection('users').doc(userId).get();
    
    if (!userDoc.exists || !userDoc.data().professionalProfile?.isActive) {
      return res.status(403).json({
        success: false,
        message: 'No tienes un perfil profesional activo'
      });
    }
    
    const specialistId = userDoc.data().professionalProfile.specialistId;
    
    const consultationDoc = await db.collection('consultations').doc(consultationId).get();
    
    if (!consultationDoc.exists) {
      return res.status(404).json({
        success: false,
        message: 'Consulta no encontrada'
      });
    }
    
    const data = consultationDoc.data();
    
    if (data.specialistId !== specialistId) {
      return res.status(403).json({
        success: false,
        message: 'No tienes acceso a esta consulta'
      });
    }
    
    if (data.status !== 'pending') {
      return res.status(400).json({
        success: false,
        message: `La consulta ya está en estado: ${data.status}`
      });
    }
    
    // Actualizar consulta
    const updateData = {
      status: 'accepted',
      acceptedAt: new Date(),
      updatedAt: new Date()
    };
    
    if (scheduledFor) {
      updateData.scheduledFor = new Date(scheduledFor);
    }
    
    if (estimatedResponseTime) {
      updateData.estimatedResponseTime = parseInt(estimatedResponseTime);
    }
    
    await db.collection('consultations').doc(consultationId).update(updateData);
    
    console.log(`✅ [SPECIALIST] Consulta aceptada: ${consultationId} por ${specialistId}`);
    
    // TODO: Enviar notificación push al padre
    
    res.json({
      success: true,
      message: 'Consulta aceptada exitosamente',
      data: {
        status: 'accepted',
        acceptedAt: updateData.acceptedAt,
        scheduledFor: updateData.scheduledFor,
        estimatedResponseTime: updateData.estimatedResponseTime
      }
    });
    
  } catch (error) {
    console.error('❌ [SPECIALIST] Error aceptando consulta:', error);
    res.status(500).json({
      success: false,
      message: 'Error aceptando consulta',
      error: error.message
    });
  }
});

