/**
 * Crear consulta médica (App)
 * POST /api/children/:childId/consultations
 */
app.post('/api/children/:childId/consultations', authenticateToken, async (req, res) => {
  try {
    const { childId } = req.params;
    const userId = req.user.uid;
    const { 
      description, 
      photos = [], 
      symptoms = [], 
      type, 
      urgency = 'normal',
      preferredSpecialistId,
      couponCode 
    } = req.body;
    
    if (!description || !type) {
      return res.status(400).json({
        success: false,
        message: 'Descripción y tipo de consulta son requeridos'
      });
    }
    
    if (!['chat', 'video'].includes(type)) {
      return res.status(400).json({
        success: false,
        message: 'Tipo de consulta inválido. Debe ser "chat" o "video"'
      });
    }
    
    // Verificar que el hijo pertenece al usuario
    const childDoc = await db.collection('children').doc(childId).get();
    
    if (!childDoc.exists) {
      return res.status(404).json({
        success: false,
        message: 'Hijo no encontrado'
      });
    }
    
    const childData = childDoc.data();
    
    // Verificar que el usuario es el padre o tiene acceso compartido
    const hasAccess = childData.parentId === userId || 
                      (childData.sharedWith && childData.sharedWith.includes(userId));
    
    if (!hasAccess) {
      return res.status(403).json({
        success: false,
        message: 'No tienes permiso para crear consultas para este hijo'
      });
    }
    
    // Buscar especialista disponible
    let specialistId = preferredSpecialistId;
    
    if (!specialistId) {
      // Buscar especialista activo con mejor rating
      const specialistsSnapshot = await db.collection('professionals')
        .where('status', '==', 'active')
        .orderBy('stats.averageRating', 'desc')
        .limit(1)
        .get();
      
      if (specialistsSnapshot.empty) {
        return res.status(503).json({
          success: false,
          message: 'No hay especialistas disponibles en este momento'
        });
      }
      
      specialistId = specialistsSnapshot.docs[0].id;
    }
    
    const specialistDoc = await db.collection('professionals').doc(specialistId).get();
    
    if (!specialistDoc.exists || specialistDoc.data().status !== 'active') {
      return res.status(404).json({
        success: false,
        message: 'Especialista no disponible'
      });
    }
    
    const specialist = specialistDoc.data();
    
    // Obtener pricing (compatible con ambas estructuras)
    const pricing = specialist.consultationPricing || specialist.pricing || {};
    
    // Calcular precio
    const basePrice = type === 'chat' 
      ? pricing.chatConsultation 
      : pricing.videoConsultation;
    
    if (!basePrice) {
      return res.status(400).json({
        success: false,
        message: 'El especialista no tiene precios configurados para este tipo de consulta'
      });
    }
    
    let discount = 0;
    let finalCouponCode = null;
    let finalCouponId = null;
    let isFree = false;
    let autoApplied = false;
    
    // 1. Primero intentar con el cupón ingresado manualmente (si existe)
    let appliedCoupon = null;
    let appliedCouponDocId = null;
    
    if (couponCode) {
      const couponSnapshot = await db.collection('discountCoupons')
        .where('code', '==', couponCode.toUpperCase())
        .where('isActive', '==', true)
        .limit(1)
        .get();
      
      if (!couponSnapshot.empty) {
        const couponDoc = couponSnapshot.docs[0];
        const coupon = couponDoc.data();
        
        // Validar cupón
        const now = new Date();
        const isValid = 
          (!coupon.validFrom || coupon.validFrom.toDate() <= now) &&
          (!coupon.validUntil || coupon.validUntil.toDate() >= now) &&
          (!coupon.maxUses || coupon.usedCount < coupon.maxUses) &&
          (coupon.applicableTo === 'all' || coupon.applicableTo === type) &&
          (!coupon.specialistId || coupon.specialistId === specialistId);
        
        if (isValid) {
          appliedCoupon = coupon;
          appliedCouponDocId = couponDoc.id;
        }
      }
    }
    
    // 2. Si no hay cupón manual, buscar cupones auto-aplicables
    if (!appliedCoupon) {
      const autoCoupon = await findBestAutoApplyCoupon(userId, type, specialistId);
      if (autoCoupon) {
        appliedCoupon = autoCoupon;
        appliedCouponDocId = autoCoupon.id;
        autoApplied = true;
      }
    }
    
    // Calcular descuento y actualizar contador si hay cupón aplicable
    if (appliedCoupon) {
      if (appliedCoupon.type === 'percentage') {
        discount = basePrice * (appliedCoupon.value / 100);
      } else if (appliedCoupon.type === 'fixed') {
        discount = appliedCoupon.value;
      } else if (appliedCoupon.type === 'free') {
        discount = basePrice;
        isFree = true;
      }
      
      finalCouponCode = appliedCoupon.code;
      
      // Incrementar contador de usos
      await db.collection('discountCoupons').doc(appliedCouponDocId).update({
        usedCount: admin.firestore.FieldValue.increment(1)
      });
      
      console.log(`✅ Cupón aplicado: ${finalCouponCode} ${autoApplied ? '(automático)' : '(manual)'}`);
    }
    
    const finalPrice = Math.max(0, basePrice - discount);
    
    // Crear consulta
    const consultationData = {
      parentId: userId,
      childId,
      childName: childData.name,
      childAge: childData.age || null,
      specialistId,
      specialistName: specialist.name,
      type,
      status: isFree ? 'pending' : 'awaiting_payment',
      request: {
        description: description.trim(),
        photos: photos || [],
        symptoms: symptoms || [],
        urgency: urgency || 'normal'
      },
      pricing: {
        basePrice,
        discount: Math.round(discount * 100) / 100,
        finalPrice: Math.round(finalPrice * 100) / 100,
        couponCode: finalCouponCode,
        isFree
      },
      payment: {
        method: null,
        transactionId: null,
        status: isFree ? 'free' : 'pending',
        paidAt: isFree ? new Date() : null
      },
      schedule: {
        requestedAt: new Date(),
        acceptedAt: null,
        scheduledFor: null,
        startedAt: null,
        completedAt: null
      },
      chat: {
        channelId: null,
        messageCount: 0
      },
      video: {
        roomId: null,
        duration: 0,
        recording: null
      },
      outcome: {
        diagnosis: null,
        treatment: null,
        prescriptions: [],
        notes: null,
        followUpRequired: false
      },
      rating: {
        score: null,
        comment: null,
        ratedAt: null
      },
      createdAt: new Date(),
      updatedAt: new Date()
    };
    
    const consultationRef = await db.collection('consultations').add(consultationData);
    
    console.log(`✅ [CONSULTATION] Nueva consulta creada: ${consultationRef.id} - ${type} - $${finalPrice}`);
    
    // Obtener detalles de los síntomas para el response
    const symptomDetails = [];
    if (symptoms && symptoms.length > 0) {
      for (const symptomId of symptoms) {
        try {
          const symptomDoc = await db.collection('symptoms').doc(symptomId).get();
          if (symptomDoc.exists) {
            const symptomData = symptomDoc.data();
            symptomDetails.push({
              id: symptomDoc.id,
              name: symptomData.name,
              description: symptomData.description,
              category: symptomData.category,
              severity: symptomData.severity
            });
          }
        } catch (err) {
          console.warn(`⚠️ Error obteniendo síntoma ${symptomId}:`, err.message);
        }
      }
    }
    
    if (consultationData.status === 'pending') {
      notifySpecialistNewConsultation(specialistId, consultationRef.id, childData.name).catch(() => {});
    }
    
    res.json({
      success: true,
      message: 'Consulta creada exitosamente',
      data: {
        consultationId: consultationRef.id,
        ...consultationData,
        request: {
          ...consultationData.request,
          symptomDetails  // Agregar detalles de los síntomas
        },
        paymentRequired: !isFree
      }
    });
    
  } catch (error) {
    console.error('❌ [CONSULTATION] Error creando consulta:', error);
    res.status(500).json({
      success: false,
      message: 'Error creando consulta',
      error: error.message
    });
  }
});

/**
 * Listar consultas del usuario como consumidor/padre (App - perfil normal)
 * GET /api/consultations
 * - Consultas donde el usuario es el padre (parentId == userId)
 * - Para consultas como especialista: usar GET /api/specialist/consultations
 */
app.get('/api/consultations', authenticateToken, async (req, res) => {
  try {
    const userId = req.user.uid;
    const { status, childId, page = 1, limit = 20 } = req.query;
    
    let query = db.collection('consultations').where('parentId', '==', userId);
    
    if (status) {
      query = query.where('status', '==', status);
    }
    
    if (childId) {
      query = query.where('childId', '==', childId);
    }
    
    query = query.orderBy('createdAt', 'desc');
    
    const snapshot = await query.get();
    
    const consultations = [];
    snapshot.forEach(doc => {
      const data = doc.data();
      consultations.push({
        id: doc.id,
        ...data,
        createdAt: data.createdAt?.toDate?.() || data.createdAt,
        updatedAt: data.updatedAt?.toDate?.() || data.updatedAt
      });
    });
    
    // Paginación
    const pageNum = parseInt(page);
    const limitNum = parseInt(limit);
    const startIndex = (pageNum - 1) * limitNum;
    const endIndex = startIndex + limitNum;
    const paginatedConsultations = consultations.slice(startIndex, endIndex);
    
    console.log(`✅ [CONSULTATIONS] Consultas listadas: ${consultations.length} (padre) para usuario ${userId}`);
    
    res.json({
      success: true,
      data: paginatedConsultations,
      pagination: {
        page: pageNum,
        limit: limitNum,
        total: consultations.length,
        totalPages: Math.ceil(consultations.length / limitNum)
      }
    });
    
  } catch (error) {
    console.error('❌ [CONSULTATIONS] Error listando consultas:', error);
    res.status(500).json({
      success: false,
      message: 'Error listando consultas',
      error: error.message
    });
  }
});

/**
 * Obtener detalles de consulta (App)
 * GET /api/consultations/:consultationId
 */
app.get('/api/consultations/:consultationId', authenticateToken, async (req, res) => {
  try {
    const { consultationId } = req.params;
    const userId = req.user.uid;
    
    const consultationDoc = await db.collection('consultations').doc(consultationId).get();
    
    if (!consultationDoc.exists) {
      return res.status(404).json({
        success: false,
        message: 'Consulta no encontrada'
      });
    }
    
    const consultation = consultationDoc.data();

    const isParent = consultation.parentId === userId;
    let specialistDoc = null;
    let isSpecialist = false;
    if (consultation.specialistId) {
      specialistDoc = await db.collection('professionals').doc(consultation.specialistId).get();
      if (specialistDoc.exists) {
        const sp = specialistDoc.data();
        isSpecialist = (sp.linkedUserId === userId || sp.userId === userId);
      }
    }
    if (!isParent && !isSpecialist) {
      return res.status(403).json({
        success: false,
        message: 'No tienes permiso para ver esta consulta'
      });
    }

    const specialist = specialistDoc && specialistDoc.exists ? specialistDoc.data() : null;
    
    // Obtener detalles de los síntomas
    const symptomDetails = [];
    if (consultation.request?.symptoms && consultation.request.symptoms.length > 0) {
      for (const symptomId of consultation.request.symptoms) {
        try {
          const symptomDoc = await db.collection('symptoms').doc(symptomId).get();
          if (symptomDoc.exists) {
            const symptomData = symptomDoc.data();
            symptomDetails.push({
              id: symptomDoc.id,
              name: symptomData.name,
              description: symptomData.description,
              category: symptomData.category,
              severity: symptomData.severity
            });
          }
        } catch (err) {
          console.warn(`⚠️ Error obteniendo síntoma ${symptomId}:`, err.message);
        }
      }
    }
    
    const result = consultation.result || consultation.outcome;
    res.json({
      success: true,
      data: {
        id: consultationDoc.id,
        ...consultation,
        request: {
          ...consultation.request,
          symptomDetails
        },
        result: result ? {
          diagnosis: result.diagnosis,
          treatment: result.treatment,
          prescriptions: result.prescriptions || [],
          notes: result.notes,
          followUpRequired: result.followUpRequired,
          followUpDate: result.followUpDate?.toDate?.() || result.followUpDate,
          completedAt: result.completedAt?.toDate?.() || result.completedAt
        } : null,
        specialist: specialist ? {
          id: consultation.specialistId,
          displayName: specialist.name,
          photoUrl: specialist.photoUrl,
          specialties: specialist.specialties
        } : null,
        createdAt: consultation.createdAt?.toDate?.() || consultation.createdAt,
        updatedAt: consultation.updatedAt?.toDate?.() || consultation.updatedAt
      }
    });
    
  } catch (error) {
    console.error('❌ [CONSULTATIONS] Error obteniendo consulta:', error);
    res.status(500).json({
      success: false,
      message: 'Error obteniendo consulta',
      error: error.message
    });
  }
});

/**
 * Cancelar consulta (App)
 * DELETE /api/consultations/:consultationId
 */
app.delete('/api/consultations/:consultationId', authenticateToken, async (req, res) => {
  try {
    const { consultationId } = req.params;
    const userId = req.user.uid;
    
    const consultationDoc = await db.collection('consultations').doc(consultationId).get();
    
    if (!consultationDoc.exists) {
      return res.status(404).json({
        success: false,
        message: 'Consulta no encontrada'
      });
    }
    
    const consultation = consultationDoc.data();
    
    // Verificar que el usuario es el dueño
    if (consultation.parentId !== userId) {
      return res.status(403).json({
        success: false,
        message: 'No tienes permiso para cancelar esta consulta'
      });
    }
    
    // No se puede cancelar si ya está completada
    if (consultation.status === 'completed') {
      return res.status(400).json({
        success: false,
        message: 'No se puede cancelar una consulta completada'
      });
    }
    
    // No se puede cancelar si ya está en progreso
    if (consultation.status === 'in_progress') {
      return res.status(400).json({
        success: false,
        message: 'No se puede cancelar una consulta en progreso'
      });
    }
    
    await db.collection('consultations').doc(consultationId).update({
      status: 'cancelled',
      updatedAt: new Date()
    });
    
    console.log(`✅ [CONSULTATION] Consulta cancelada: ${consultationId}`);
    
    // TODO: Notificar al especialista
    // TODO: Procesar reembolso si aplica
    
    res.json({
      success: true,
      message: 'Consulta cancelada exitosamente'
    });
    
  } catch (error) {
    console.error('❌ [CONSULTATIONS] Error cancelando consulta:', error);
    res.status(500).json({
      success: false,
      message: 'Error cancelando consulta',
      error: error.message
    });
  }
});

/**
 * Crear PaymentIntent para consulta (Stripe)
 * POST /api/consultations/:consultationId/payment/create-intent
 * Retorna clientSecret para confirmar en el frontend con Stripe SDK
 */
app.post('/api/consultations/:consultationId/payment/create-intent', authenticateToken, async (req, res) => {
  try {
    const { consultationId } = req.params;
    const userId = req.user.uid;
    const consultationDoc = await db.collection('consultations').doc(consultationId).get();
    if (!consultationDoc.exists) return res.status(404).json({ success: false, message: 'Consulta no encontrada' });
    const consultation = consultationDoc.data();
    if (consultation.parentId !== userId) return res.status(403).json({ success: false, message: 'Sin permiso' });
    if (consultation.payment?.status === 'completed') return res.status(400).json({ success: false, message: 'Ya pagada' });
    const amount = Math.round((consultation.pricing?.finalPrice || 0) * 100);
    if (amount < 50) return res.status(400).json({ success: false, message: 'Monto mínimo $0.50' });

    const stripeSecret = process.env.STRIPE_SECRET_KEY;
    if (!stripeSecret) return res.status(503).json({ success: false, message: 'Stripe no configurado' });

    const stripe = require('stripe')(stripeSecret);
    const paymentIntent = await stripe.paymentIntents.create({
      amount,
      currency: 'usd',
      metadata: { consultationId, userId },
      payment_method_types: ['card']
    });

    res.json({
      success: true,
      data: {
        clientSecret: paymentIntent.client_secret,
        paymentIntentId: paymentIntent.id
      }
    });
  } catch (err) {
    console.error('❌ [STRIPE] create-intent:', err.message);
    res.status(500).json({ success: false, message: err.message });
  }
});

/**
 * Procesar pago de consulta (App)
 * POST /api/consultations/:consultationId/payment
 * Body (Stripe): { paymentMethodId } - confirma PaymentIntent con método de pago
 * Body (legacy): { paymentMethod, paymentToken } - simula pago (sin Stripe)
 */
app.post('/api/consultations/:consultationId/payment', authenticateToken, async (req, res) => {
  try {
    const { consultationId } = req.params;
    const userId = req.user.uid;
    const { paymentMethodId, paymentIntentId } = req.body;

    const consultationDoc = await db.collection('consultations').doc(consultationId).get();
    if (!consultationDoc.exists) return res.status(404).json({ success: false, message: 'Consulta no encontrada' });
    const consultation = consultationDoc.data();
    if (consultation.parentId !== userId) return res.status(403).json({ success: false, message: 'Sin permiso' });
    if (consultation.payment?.status === 'completed') return res.status(400).json({ success: false, message: 'Ya pagada' });

    const stripeSecret = process.env.STRIPE_SECRET_KEY;
    if (stripeSecret && paymentMethodId && paymentIntentId) {
      const stripe = require('stripe')(stripeSecret);
      const confirmed = await stripe.paymentIntents.confirm(paymentIntentId, { payment_method: paymentMethodId });
      if (confirmed.status !== 'succeeded' && confirmed.status !== 'requires_capture') {
        return res.status(400).json({ success: false, message: 'Pago no completado', status: confirmed.status });
      }
    } else if (!stripeSecret) {
      const transactionId = `txn_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
      await db.collection('consultations').doc(consultationId).update({
        'payment.method': 'simulated',
        'payment.transactionId': transactionId,
        'payment.status': 'completed',
        'payment.paidAt': new Date(),
        status: 'pending',
        updatedAt: new Date()
      });
      notifySpecialistNewConsultation(consultation.specialistId, consultationId, consultation.childName).catch(() => {});
      return res.json({ success: true, message: 'Pago procesado', data: { transactionId, amount: consultation.pricing?.finalPrice, currency: 'USD' } });
    } else {
      return res.status(400).json({ success: false, message: 'paymentMethodId y paymentIntentId requeridos para Stripe' });
    }

    await db.collection('consultations').doc(consultationId).update({
      'payment.method': 'stripe',
      'payment.transactionId': paymentIntentId,
      'payment.status': 'completed',
      'payment.paidAt': new Date(),
      status: 'pending',
      updatedAt: new Date()
    });
    notifySpecialistNewConsultation(consultation.specialistId, consultationId, consultation.childName).catch(() => {});

    res.json({
      success: true,
      message: 'Pago procesado exitosamente',
      data: { transactionId: paymentIntentId, amount: consultation.pricing?.finalPrice, currency: 'USD' }
    });
  } catch (err) {
    console.error('❌ [PAYMENT] Error:', err);
    res.status(500).json({ success: false, message: err.message });
  }
});

