/**
 * TEMPORAL: Verificar solicitudes de servicio sin autenticación
 * GET /api/temp/list-service-requests
 */
app.get('/api/temp/list-service-requests', async (req, res) => {
  try {
    const snapshot = await db.collection('serviceRequests')
      .orderBy('createdAt', 'desc')
      .get();
    
    const requests = [];
    snapshot.forEach(doc => {
      const data = doc.data();
      requests.push({
        id: doc.id,
        businessName: data.businessName,
        userEmail: data.userEmail,
        status: data.status,
        createdAt: data.createdAt,
        profileCategory: data.profileCategory
      });
    });
    
    res.json({
      success: true,
      count: requests.length,
      data: requests
    });
  } catch (error) {
    res.status(500).json({ success: false, error: error.message });
  }
});

/**
 * TEMPORAL: Buscar documento por ID en múltiples colecciones
 * GET /api/temp/find-document/:id
 */
app.get('/api/temp/find-document/:id', async (req, res) => {
  try {
    const { id } = req.params;
    const collections = [
      'professionals',
      'serviceRequests', 
      'professionalRequests',
      'service_requests',
      'marketplaceRequests',
      'marketplace_services',
      'services',
      'business_requests'
    ];
    
    const results = {};
    
    for (const collectionName of collections) {
      try {
        const doc = await db.collection(collectionName).doc(id).get();
        
        if (doc.exists) {
          results[collectionName] = {
            found: true,
            data: {
              id: doc.id,
              ...doc.data()
            }
          };
        } else {
          results[collectionName] = { found: false };
        }
      } catch (error) {
        results[collectionName] = {
          found: false,
          error: error.message
        };
      }
    }
    
    res.json({
      success: true,
      searchId: id,
      results
    });
    
  } catch (error) {
    res.status(500).json({ success: false, error: error.message });
  }
});

/**
 * TEMPORAL: Verificar solicitudes de servicio
 * GET /api/temp/check-service-requests
 */
app.get('/api/temp/check-service-requests', async (req, res) => {
  try {
    // Intentar varias colecciones posibles
    const collections = ['serviceRequests', 'professionalRequests', 'service_requests', 'marketplaceRequests'];
    const results = {};
    
    for (const collectionName of collections) {
      try {
        const snapshot = await db.collection(collectionName)
          .orderBy('createdAt', 'desc')
          .limit(5)
          .get();
        
        results[collectionName] = {
          exists: true,
          count: snapshot.size,
          samples: snapshot.docs.map(doc => ({
            id: doc.id,
            ...doc.data()
          }))
        };
      } catch (error) {
        results[collectionName] = {
          exists: false,
          error: error.message
        };
      }
    }
    
    res.json({
      success: true,
      collections: results
    });
    
  } catch (error) {
    res.status(500).json({ success: false, error: error.message });
  }
});

/**
 * TEMPORAL: Verificar estado de un profesional
 * GET /api/temp/check-professional/:id
 */
app.get('/api/temp/check-professional/:id', async (req, res) => {
  try {
    const { id } = req.params;
    const doc = await db.collection('professionals').doc(id).get();
    
    if (!doc.exists) {
      return res.status(404).json({ success: false, message: 'No encontrado' });
    }
    
    const data = doc.data();
    
    res.json({
      success: true,
      data: {
        id: doc.id,
        name: data.name,
        linkedUserId: data.linkedUserId || null,
        userId: data.userId || null,
        accountType: data.accountType || null,
        canAcceptConsultations: data.canAcceptConsultations || false,
        consultationPricing: data.consultationPricing || null,
        hasOldPersonalInfo: !!data.personalInfo,
        hasOldProfessional: !!data.professional
      }
    });
  } catch (error) {
    res.status(500).json({ success: false, error: error.message });
  }
});

/**
 * TEMPORAL: Agregar linkedUserId a un profesional
 * POST /api/temp/add-linked-user/:id
 */
app.post('/api/temp/add-linked-user/:id', async (req, res) => {
  try {
    const { id } = req.params;
    const { userId } = req.body;
    
    if (!userId) {
      return res.status(400).json({ success: false, message: 'userId requerido' });
    }
    
    // Verificar que el profesional existe
    const profDoc = await db.collection('professionals').doc(id).get();
    if (!profDoc.exists) {
      return res.status(404).json({ success: false, message: 'Profesional no encontrado' });
    }
    
    // Verificar que el usuario existe
    const userDoc = await db.collection('users').doc(userId).get();
    if (!userDoc.exists) {
      return res.status(404).json({ success: false, message: 'Usuario no encontrado' });
    }
    
    const profData = profDoc.data();
    
    // Actualizar profesional
    await db.collection('professionals').doc(id).update({
      linkedUserId: userId,
      accountType: 'medical',
      canAcceptConsultations: true,
      updatedAt: new Date()
    });
    
    // Actualizar usuario
    await db.collection('users').doc(userId).update({
      professionalProfile: {
        isActive: true,
        specialistId: id,
        specialistName: profData.name,
        accountType: 'medical'
      },
      updatedAt: admin.firestore.FieldValue.serverTimestamp()
    });
    
    console.log(`✅ [TEMP] Usuario vinculado: ${userId} -> Profesional ${id}`);
    
    res.json({
      success: true,
      message: 'Usuario vinculado exitosamente',
      data: {
        professionalId: id,
        userId: userId
      }
    });
    
  } catch (error) {
    res.status(500).json({ success: false, error: error.message });
  }
});

// Middleware para rutas no encontradas (DEBE estar después de todas las rutas)
app.use('*', (req, res) => {
  console.log('⚠️ [404] Ruta no encontrada:', req.method, req.originalUrl);
  res.status(404).json({
    success: false,
    message: 'Ruta no encontrada',
    path: req.originalUrl,
    method: req.method
  });
});

